  bool get _telegramAdminControlEnabled {
    if (!_telegramAdminControlEnabledEnv) {
      return false;
    }
    if (!_telegramBridge.isConfigured) {
      return false;
    }
    return _resolvedTelegramAdminChatId().isNotEmpty;
  }

  bool get _telegramAdminCriticalPushEnabled {
    if (!_telegramAdminCriticalPushEnabledEnv) {
      return false;
    }
    return _telegramAdminControlEnabled;
  }

  bool get _telegramAdminExecutionEnabled {
    return _telegramAdminExecutionEnabledOverride ??
        _telegramAdminExecutionEnabledEnv;
  }

  bool get _telegramAiAssistantEnabled {
    final enabled =
        widget.telegramAiAssistantEnabledOverride ??
        _telegramAiAssistantEnabledOverride ??
        _telegramAiAssistantEnabledEnv;
    if (!enabled) {
      return false;
    }
    return _telegramBridge.isConfigured;
  }

  bool get _telegramAiApprovalRequired {
    return widget.telegramAiApprovalRequiredOverride ??
        _telegramAiApprovalRequiredOverride ??
        _telegramAiApprovalRequiredEnv;
  }

  List<String> get _telegramAiConfiguredProviderLabels {
    final labels = <String>[];
    if (_buildOnyxAgentCloudBoostService().isConfigured) {
      labels.add('onyx-cloud');
    }
    final directConfig = OpenAiRuntimeConfig.resolve(
      primaryApiKey: _telegramAiOpenAiApiKeyEnv,
      primaryModel: _telegramAiModelEnv,
      primaryEndpoint: _telegramAiEndpointEnv,
      genericApiKey: _genericOpenAiApiKeyEnv,
      genericModel: _genericOpenAiModelEnv,
      genericBaseUrl: _genericOpenAiBaseUrlEnv,
    );
    if (directConfig.isConfigured) {
      labels.add('openai-direct');
    }
    if (_buildOnyxAgentLocalBrainService().isConfigured) {
      labels.add('onyx-local');
    }
    return labels;
  }

  bool get _telegramAiFallbackOnly =>
      _telegramAiConfiguredProviderLabels.isEmpty;

  String get _telegramAiProviderChainLabel {
    final labels = _telegramAiConfiguredProviderLabels;
    if (labels.isEmpty) {
      return 'fallback-only';
    }
    return '${labels.join(' -> ')} -> fallback';
  }

  bool get _telegramInboundRouterEnabled {
    if (!_telegramBridge.isConfigured) {
      return false;
    }
    return _telegramAdminControlEnabled ||
        _telegramAiAssistantEnabled ||
        _resolvedTelegramClientChatId().isNotEmpty ||
        _resolvedTelegramPartnerChatId().isNotEmpty ||
        _resolvedTelegramAdminChatId().isNotEmpty;
  }

  bool get _keepTelegramPollingWhenBackgrounded {
    return kIsWeb || _appMode == OnyxAppMode.controller;
  }

  String get _telegramAdminTargetClientId {
    final override = (_telegramAdminTargetClientIdOverride ?? '').trim();
    if (override.isNotEmpty) {
      return override;
    }
    return _selectedClient;
  }

  String get _telegramAdminTargetSiteId {
    final override = (_telegramAdminTargetSiteIdOverride ?? '').trim();
    if (override.isNotEmpty) {
      return override;
    }
    return _selectedSite;
  }

  Set<int> get _telegramAdminAllowedUserIdsFromEnv {
    final raw = _telegramAdminAllowedUserIdsEnv.trim();
    if (raw.isEmpty) {
      return const <int>{};
    }
    return raw
        .split(',')
        .map((value) => int.tryParse(value.trim()))
        .whereType<int>()
        .where((value) => value > 0)
        .toSet();
  }

  Set<int> get _telegramAdminAllowedUserIds {
    final override = _telegramAdminAllowedUserIdsOverride;
    if (override == null) {
      return _telegramAdminAllowedUserIdsFromEnv;
    }
    return override.where((value) => value > 0).toSet();
  }

  SmsDeliveryService _buildSmsDeliveryService() {
    final provider = _smsFallbackProviderEnv.trim();
    if (provider.isEmpty) {
      return const UnconfiguredSmsDeliveryService();
    }
    if (provider.toLowerCase() == 'bulksms') {
      final tokenPair = _smsFallbackApiTokenEnv.trim();
      final separatorIndex = tokenPair.indexOf(':');
      final tokenIdentity = separatorIndex > 0
          ? tokenPair.substring(0, separatorIndex).trim()
          : '';
      final tokenSecret = separatorIndex > 0
          ? tokenPair.substring(separatorIndex + 1).trim()
          : '';
      final identity = tokenIdentity.isNotEmpty
          ? tokenIdentity
          : _smsFallbackUsernameEnv.trim();
      final secret = tokenSecret.isNotEmpty
          ? tokenSecret
          : _smsFallbackPasswordEnv.trim();
      final endpoint =
          Uri.tryParse(_smsFallbackApiUrlEnv.trim()) ??
          Uri.parse('https://api.bulksms.com/v1/messages?auto-unicode=true');
      if (identity.isEmpty || secret.isEmpty) {
        return const UnconfiguredSmsDeliveryService();
      }
      return BulkSmsDeliveryService(
        client: _smsBridgeHttpClient,
        credentialIdentity: identity,
        credentialSecret: secret,
        endpoint: endpoint,
      );
    }
    final endpoint = Uri.tryParse(_smsFallbackApiUrlEnv.trim());
    if (endpoint == null) {
      return const UnconfiguredSmsDeliveryService();
    }
    return HttpSmsDeliveryService(
      client: _smsBridgeHttpClient,
      provider: provider,
      endpoint: endpoint,
      bearerToken: _smsFallbackApiTokenEnv.trim().isEmpty
          ? null
          : _smsFallbackApiTokenEnv.trim(),
    );
  }

  VoipCallService _buildVoipCallService() {
    final provider = _voipProviderEnv.trim();
    if (provider.isEmpty) {
      return const UnconfiguredVoipCallService();
    }
    if (provider.toLowerCase() == 'asterisk') {
      final tokenPair = _voipApiTokenEnv.trim();
      final separatorIndex = tokenPair.indexOf(':');
      final tokenIdentity = separatorIndex > 0
          ? tokenPair.substring(0, separatorIndex).trim()
          : '';
      final tokenSecret = separatorIndex > 0
          ? tokenPair.substring(separatorIndex + 1).trim()
          : '';
      final username = tokenIdentity.isNotEmpty
          ? tokenIdentity
          : _voipUsernameEnv.trim();
      final password = tokenSecret.isNotEmpty
          ? tokenSecret
          : _voipPasswordEnv.trim();
      final endpoint = Uri.tryParse(_voipApiUrlEnv.trim());
      if (endpoint == null ||
          username.isEmpty ||
          password.isEmpty ||
          _voipDialplanContextEnv.trim().isEmpty) {
        return const UnconfiguredVoipCallService();
      }
      return AsteriskAriVoipCallService(
        client: _voipBridgeHttpClient,
        baseUri: endpoint,
        username: username,
        password: password,
        endpointTechnology: _voipEndpointTechnologyEnv.trim(),
        sipHost: _voipSipHostEnv.trim().isEmpty ? null : _voipSipHostEnv.trim(),
        dialplanContext: _voipDialplanContextEnv.trim(),
        dialplanExtension: _voipDialplanExtensionEnv.trim(),
        dialplanPriority: _voipDialplanPriorityEnv,
        callerId: _voipCallerIdEnv.trim().isEmpty
            ? null
            : _voipCallerIdEnv.trim(),
      );
    }
    final endpoint = Uri.tryParse(_voipApiUrlEnv.trim());
    if (endpoint == null) {
      return const UnconfiguredVoipCallService();
    }
    return HttpVoipCallService(
      client: _voipBridgeHttpClient,
      provider: provider,
      endpoint: endpoint,
      bearerToken: _voipApiTokenEnv.trim().isEmpty
          ? null
          : _voipApiTokenEnv.trim(),
    );
  }

  TelegramBridgeService _buildTelegramBridge() {
    if (!_telegramBridgeEnabledEnv) {
      return const UnconfiguredTelegramBridgeService();
    }
    final botToken = _telegramBotTokenEnv.trim();
    if (botToken.isEmpty) {
      return const UnconfiguredTelegramBridgeService();
