  bool get _olarmConfigured {
    return _olarmApiKeyEnv.trim().isNotEmpty &&
        _olarmDeviceIdEnv.trim().isNotEmpty;
  }

  void _startOlarmBridgeIfConfigured() {
    if (!_olarmConfigured) {
      return;
    }
    final service =
        _olarmService ??
        OnyxOlarmBridgeService(
          apiKey: _olarmApiKeyEnv.trim(),
          siteId: _selectedSite.trim(),
          deviceId: _olarmDeviceIdEnv.trim(),
          client: _olarmHttpClient,
        );
    _olarmService = service;
    unawaited(_olarmEventSubscription?.cancel());
    _olarmEventSubscription = service.events.listen((event) {
      unawaited(_handleOlarmEvent(event));
    });
    unawaited(
      service.connect().catchError((Object error, StackTrace stackTrace) {
        developer.log(
          'Failed to start Olarm bridge.',
          name: 'OnyxOlarmBridge',
          error: error,
          stackTrace: stackTrace,
          level: 1000,
        );
      }),
    );
  }

  Future<void> _handleOlarmEvent(OnyxOlarmEvent event) async {
    await _recordOlarmEventToSupabase(event);
    await _pushOlarmAlarmEventToTelegram(event);
  }

  Future<void> _recordOlarmEventToSupabase(OnyxOlarmEvent event) async {
    if (!widget.supabaseReady) {
      return;
    }
    final normalized = _olarmNormalizedPayload(event.rawPayload);
    try {
      await Supabase.instance.client
          .from('site_alarm_events')
          .insert(<String, Object?>{
            'site_id': _selectedSite,
            'device_id': event.deviceId.trim(),
            'event_type': event.eventType.name,
            'zone_id': event.zoneId?.trim().isEmpty == true
                ? null
                : event.zoneId?.trim(),
            'area_id': event.areaId?.trim().isEmpty == true
                ? null
                : event.areaId?.trim(),
            'zone_name': normalized['zone_name'],
            'area_name': normalized['area_name'],
            'armed_state': normalized['armed_state'],
            'occurred_at': event.occurredAt.toUtc().toIso8601String(),
            'raw_payload': event.rawPayload,
          });
    } catch (error, stackTrace) {
      developer.log(
        'Failed to persist Olarm alarm event for ${event.deviceId}.',
        name: 'OnyxOlarmBridge',
        error: error,
        stackTrace: stackTrace,
        level: 1000,
      );
    }
  }

  Future<void> _pushOlarmAlarmEventToTelegram(OnyxOlarmEvent event) async {
    final text = _olarmTelegramAlertText(event);
    if (text == null || text.trim().isEmpty) {
      return;
    }
    final dispatch = await _telegramPushCoordinator.sendScopedAlert(
      clientId: _selectedClient,
      siteId: _selectedSite,
      messageKeyPrefix:
          'tg-olarm-${event.eventType.name}-${event.deviceId.trim().isEmpty ? 'device' : event.deviceId.trim()}-${event.occurredAt.microsecondsSinceEpoch}',
      text: text,
    );
    if (!mounted) {
      return;
    }
    setState(() {
      _telegramBridgeHealthLabel = dispatch.healthLabel;
      _telegramBridgeHealthDetail = dispatch.healthDetail;
      _telegramBridgeHealthUpdatedAtUtc = _telegramFlowNowUtc();
    });
    if (dispatch.attemptStatus != 'telegram-ok') {
      return;
    }
    await _appendTelegramConversationMessage(
      clientId: _selectedClient,
      siteId: _selectedSite,
      author: 'ONYX Alarm',
      body: text,
      occurredAtUtc: event.occurredAt.toUtc(),
      roomKey: 'Residents',
      viewerRole: ClientAppViewerRole.client.name,
      incidentStatusLabel: 'Alarm Event',
      messageSource: 'telegram',
      messageProvider: 'olarm_alarm',
    );
  }

  Map<String, dynamic> _olarmNormalizedPayload(Map<String, dynamic> payload) {
    final raw = payload['onyx_normalized'];
    if (raw is Map) {
      return Map<String, dynamic>.from(raw);
    }
    return const <String, dynamic>{};
  }

  String? _olarmTelegramAlertText(OnyxOlarmEvent event) {
    final siteLabel = _deliverySiteLabelFor(
      clientId: _selectedClient,
      siteId: _selectedSite,
    );
    final normalized = _olarmNormalizedPayload(event.rawPayload);
    final zoneName =
        (normalized['zone_name'] ?? '').toString().trim().isNotEmpty
        ? normalized['zone_name'].toString().trim()
        : (event.zoneId?.trim().isNotEmpty == true
              ? 'Zone ${event.zoneId!.trim()}'
              : 'Alarm zone');
    final areaName =
        (normalized['area_name'] ?? '').toString().trim().isNotEmpty
        ? normalized['area_name'].toString().trim()
        : (event.areaId?.trim().isNotEmpty == true
              ? 'Area ${event.areaId!.trim()}'
              : 'Alarm area');
    final isPerimeter = normalized['is_perimeter'] == true;
    return switch (event.eventType) {
      OnyxOlarmEventType.zoneOpen when isPerimeter =>
        '⚠️ Alarm zone open: $zoneName at $siteLabel',
      OnyxOlarmEventType.areaTriggered =>
        '🚨 ALARM TRIGGERED: $areaName at $siteLabel',
      OnyxOlarmEventType.areaArmed => '🔒 Site armed: $siteLabel',
      OnyxOlarmEventType.areaDisarmed => '🔓 Site disarmed: $siteLabel',
      _ => null,
    };
  }

  @override
  void dispose() {
    _guardCheckpointScanChannel.setMethodCallHandler(null);
    WidgetsBinding.instance.removeObserver(this);
    _router.routerDelegate.removeListener(_syncRouteFromRouter);
    _router.dispose();
    _routerRefreshNotifier.dispose();
    _livePollTimer?.cancel();
    _opsIntegrationPollTimer?.cancel();
    _guardOpsSyncTimer?.cancel();
    _tacticalGuardPositionsRefreshTimer?.cancel();
    _tacticalGuardPositionsDebounceTimer?.cancel();
    _offlineIncidentSpoolSyncTimer?.cancel();
    _telegramAdminPollTimer?.cancel();
    _siteAwarenessAlertPollTimer?.cancel();
    _patrolMonitorTimer?.cancel();
    _behaviourMonitorTimer?.cancel();
    _operatorDisciplineTimer?.cancel();
    _clientTrustSnapshotTimer?.cancel();
    unawaited(_eventStoreSubscription?.cancel() ?? Future<void>.value());
    _telegramPollingTabLock.dispose();
    _monitoringWatchScheduleTimer?.cancel();
    _monitoringContinuousVisualWatchTimer?.cancel();
    _telegramDemoScriptTimer?.cancel();
    _cancelDemoAutopilot();
    for (final bridge in _dvrVideoBridgeByScope.values) {
      bridge.delegate.dispose();
    }
    _dvrVideoBridgeByScope.clear();
    if (_videoBridgeService case DvrBackedVideoBridgeService(:final delegate)) {
      delegate.dispose();
    }
    unawaited(_stopOnyxAgentCameraBridgeServer());
    unawaited(_stopLocalHikvisionDvrProxy());
    _radioBridgeHttpClient.close();
    _cctvBridgeHttpClient.close();
    _wearableBridgeHttpClient.close();
    _listenerAlarmFeedHttpClient.close();
    _listenerAlarmLegacyFeedHttpClient.close();
    _smsBridgeHttpClient.close();
    _telegramBridgeHttpClient.close();
    _telegramAiHttpClient.close();
    _elevenLabsHttpClient.close();
    _olarmHttpClient.close();
    _onyxAgentLocalHttpClient.close();
    _onyxAgentToolHttpClient.close();
    _voipBridgeHttpClient.close();
    _monitoringVisionHttpClient.close();
    _monitoringYoloHttpClient.close();
    unawaited(_olarmEventSubscription?.cancel() ?? Future<void>.value());
    unawaited(_olarmService?.disconnect() ?? Future<void>.value());
    _guardTelemetryAdapter.dispose();
    _newsIntel.dispose();
    final tacticalChannel = _tacticalGuardPositionsChannel;
    if (tacticalChannel != null && widget.supabaseReady) {
      unawaited(Supabase.instance.client.removeChannel(tacticalChannel));
    }
    super.dispose();
  }

  @override
  void didChangeAppLifecycleState(AppLifecycleState state) {
    if (state != AppLifecycleState.resumed) {
      if (state == AppLifecycleState.inactive ||
          state == AppLifecycleState.paused ||
          state == AppLifecycleState.detached) {
        _opsIntegrationPollTimer?.cancel();
        _opsIntegrationPollTimer = null;
        _monitoringWatchScheduleTimer?.cancel();
        _monitoringWatchScheduleTimer = null;
        if (!_keepTelegramPollingWhenBackgrounded) {
          _telegramAdminPollTimer?.cancel();
          _telegramAdminPollTimer = null;
          _siteAwarenessAlertPollTimer?.cancel();
          _siteAwarenessAlertPollTimer = null;
          _patrolMonitorTimer?.cancel();
          _patrolMonitorTimer = null;
          _behaviourMonitorTimer?.cancel();
          _behaviourMonitorTimer = null;
          _operatorDisciplineTimer?.cancel();
          _operatorDisciplineTimer = null;
          _telegramPollingTabLock.release();
          _telegramPollingPrimaryTab = false;
        }
      }
      return;
    }
    _startOpsIntegrationPollingLoop();
    _startTelegramAdminControlLoop();
    _startSiteAwarenessAlertLoop();
    _startPatrolMonitorLoop();
    _startBehaviourMonitorLoop();
    _startMonitoringWatchScheduleLoop();
    unawaited(_maybeAutoGenerateMorningSovereignReport());
    if (!widget.supabaseReady || _guardOpsSyncInFlight) return;
    if (mounted) {
      setState(() {
        _guardOpsLastSyncLabel =
            'Guard sync queued after app resume (connectivity recheck).';
      });
    }
    unawaited(_queueGuardResumeSync());
  }

  Future<void> _queueGuardResumeSync() async {
    try {
      final nowUtc = DateTime.now().toUtc();
      final lastQueuedAt = _lastGuardResumeSyncEventQueuedAtUtc;
      final shouldEnqueue =
          lastQueuedAt == null ||
          nowUtc.difference(lastQueuedAt).inSeconds >=
              _guardResumeSyncEventThrottleSeconds;
      if (shouldEnqueue) {
        _lastGuardResumeSyncEventQueuedAtUtc = nowUtc;
        await _enqueueGuardOpsEvent(
          type: GuardOpsEventType.syncStatus,
          payload: {
            'sync_reason': 'app_resumed',
            'source': 'app_lifecycle',
            'connectivity_recheck': true,
            'event_throttle_seconds': _guardResumeSyncEventThrottleSeconds,
          },
        );
      }
      await _syncGuardOpsNow(background: true);
    } catch (error) {
      if (!mounted) return;
      setState(() {
        _guardOpsLastSyncLabel = 'Resume sync failed: $error';
        _guardOpsLastFailureReason = error.toString();
      });
    }
  }

  Future<void> _hydrateTelemetry() async {
    final persistence = await _persistenceServiceFuture;
    final telemetry = await persistence.readTelemetry();
    if (telemetry == null || !mounted) return;
    setState(() {
      _intakeTelemetry = telemetry;
      _lastIntakeStatus =
          'Telemetry restored from local cache (${telemetry.runs} runs).';
    });
  }

  Future<void> _persistTelemetry() async {
    final persistence = await _persistenceServiceFuture;
    await persistence.saveTelemetry(_intakeTelemetry);
  }

  Future<void> _hydrateOperatorIdentity() async {
    final persistence = await _persistenceServiceFuture;
    final persisted = (await persistence.readOperatorId() ?? '').trim();
    if (persisted.isEmpty || persisted == _operatorId) {
      return;
    }
    if (mounted) {
      setState(() {
        _operatorId = persisted;
        _rebuildDispatchServices();
      });
    } else {
      _operatorId = persisted;
      _rebuildDispatchServices();
    }
  }

  Future<void> _persistOperatorIdentity() async {
    final persistence = await _persistenceServiceFuture;
    final normalized = _operatorId.trim();
    if (normalized.isEmpty || normalized == _defaultOperatorId) {
      await persistence.clearOperatorId();
    } else {
      await persistence.saveOperatorId(normalized);
    }
  }

  Future<void> _setOperatorIdentity(String operatorId) async {
    final normalized = operatorId.trim().isEmpty
        ? _defaultOperatorId
        : operatorId.trim();
    if (normalized == _operatorId) {
      return;
    }
    if (mounted) {
      setState(() {
        _operatorId = normalized;
        _rebuildDispatchServices();
      });
    } else {
      _operatorId = normalized;
      _rebuildDispatchServices();
    }
    await _persistOperatorIdentity();
  }

