  Future<void> _hydrateClientAppDraft() async {
    final persistence = await _persistenceServiceFuture;
    final draft = await persistence.readClientAppDraft();
    final conversation = await _conversationRepositoryForScope(
      clientId: _selectedClient,
      siteId: _selectedSite,
    );
    if (conversation == null) {
      return;
    }
    final storedMessages = await conversation.readMessages();
    final storedAcknowledgements = await conversation.readAcknowledgements();
    final storedPushQueue = await conversation.readPushQueue();
    final storedPushSyncState = await conversation.readPushSyncState();
    final scopedConversationScopeKeys = await persistence
        .readClientConversationScopeKeys();
    final hasScopedConversationScopes = scopedConversationScopeKeys.isNotEmpty;
    final scopedConversationMessagesByScope =
        <String, List<ClientAppMessage>>{};
    final scopedAcknowledgementsByScope =
        <String, List<ClientAppAcknowledgement>>{};
    final scopedPushQueueByScope = <String, List<ClientAppPushDeliveryItem>>{};
    final scopedPushSyncStateByScope = <String, ClientPushSyncState>{};
    for (final scopeKey in scopedConversationScopeKeys) {
      final normalizedScopeKey = scopeKey.trim();
      final parts = normalizedScopeKey.split('|');
      if (normalizedScopeKey.isEmpty || parts.length != 2) {
        continue;
      }
      final clientId = parts.first.trim();
      final siteId = parts.last.trim();
      if (clientId.isEmpty ||
          siteId.isEmpty ||
          (clientId == _selectedClient.trim() &&
              siteId == _selectedSite.trim())) {
        continue;
      }
      final repository = await _conversationRepositoryForScope(
        clientId: clientId,
        siteId: siteId,
      );
      if (repository == null) {
        continue;
      }
      final scopedMessages = await repository.readMessages();
      if (scopedMessages.isEmpty) {
        final scopedAcknowledgements = await repository.readAcknowledgements();
        final scopedPushQueue = await repository.readPushQueue();
        final scopedPushSyncState = await repository.readPushSyncState();
        if (scopedAcknowledgements.isNotEmpty) {
          scopedAcknowledgementsByScope[normalizedScopeKey] =
              List<ClientAppAcknowledgement>.from(scopedAcknowledgements)
                ..sort((a, b) => b.acknowledgedAt.compareTo(a.acknowledgedAt));
        }
        if (scopedPushQueue.isNotEmpty) {
          scopedPushQueueByScope[normalizedScopeKey] =
              List<ClientAppPushDeliveryItem>.from(scopedPushQueue)
                ..sort((a, b) => b.occurredAt.compareTo(a.occurredAt));
        }
        if (scopedPushSyncState.statusLabel != 'idle' ||
            scopedPushSyncState.lastSyncedAtUtc != null ||
            (scopedPushSyncState.failureReason ?? '').trim().isNotEmpty ||
            scopedPushSyncState.retryCount > 0 ||
            scopedPushSyncState.history.isNotEmpty ||
            scopedPushSyncState.backendProbeStatusLabel != 'idle' ||
            scopedPushSyncState.backendProbeLastRunAtUtc != null ||
            (scopedPushSyncState.backendProbeFailureReason ?? '')
                .trim()
                .isNotEmpty ||
            scopedPushSyncState.backendProbeHistory.isNotEmpty) {
          scopedPushSyncStateByScope[normalizedScopeKey] = scopedPushSyncState;
        }
        continue;
      }
      final nextMessages = List<ClientAppMessage>.from(scopedMessages)
        ..sort((a, b) => b.occurredAt.compareTo(a.occurredAt));
      scopedConversationMessagesByScope[normalizedScopeKey] = nextMessages;
      final scopedAcknowledgements = await repository.readAcknowledgements();
      if (scopedAcknowledgements.isNotEmpty) {
        scopedAcknowledgementsByScope[normalizedScopeKey] =
            List<ClientAppAcknowledgement>.from(scopedAcknowledgements)
              ..sort((a, b) => b.acknowledgedAt.compareTo(a.acknowledgedAt));
      }
      final scopedPushQueue = await repository.readPushQueue();
      if (scopedPushQueue.isNotEmpty) {
        scopedPushQueueByScope[normalizedScopeKey] =
            List<ClientAppPushDeliveryItem>.from(scopedPushQueue)
              ..sort((a, b) => b.occurredAt.compareTo(a.occurredAt));
      }
      final scopedPushSyncState = await repository.readPushSyncState();
      if (scopedPushSyncState.statusLabel != 'idle' ||
          scopedPushSyncState.lastSyncedAtUtc != null ||
          (scopedPushSyncState.failureReason ?? '').trim().isNotEmpty ||
          scopedPushSyncState.retryCount > 0 ||
          scopedPushSyncState.history.isNotEmpty ||
          scopedPushSyncState.backendProbeStatusLabel != 'idle' ||
          scopedPushSyncState.backendProbeLastRunAtUtc != null ||
          (scopedPushSyncState.backendProbeFailureReason ?? '')
              .trim()
              .isNotEmpty ||
          scopedPushSyncState.backendProbeHistory.isNotEmpty) {
        scopedPushSyncStateByScope[normalizedScopeKey] = scopedPushSyncState;
      }
    }
    if (draft == null &&
        storedMessages.isEmpty &&
        storedAcknowledgements.isEmpty &&
        storedPushQueue.isEmpty &&
        storedPushSyncState.statusLabel == 'idle' &&
        storedPushSyncState.lastSyncedAtUtc == null &&
        (storedPushSyncState.failureReason == null ||
            storedPushSyncState.failureReason!.trim().isEmpty) &&
        storedPushSyncState.retryCount <= 0 &&
        storedPushSyncState.history.isEmpty &&
        storedPushSyncState.backendProbeStatusLabel == 'idle' &&
        storedPushSyncState.backendProbeLastRunAtUtc == null &&
        (storedPushSyncState.backendProbeFailureReason == null ||
            storedPushSyncState.backendProbeFailureReason!.trim().isEmpty) &&
        storedPushSyncState.backendProbeHistory.isEmpty &&
        !hasScopedConversationScopes) {
      return;
    }
    if (!mounted) return;
    final restoredMessages = storedMessages.isNotEmpty
        ? storedMessages
        : draft?.legacyManualMessages ?? const <ClientAppMessage>[];
    final restoredAcknowledgements = storedAcknowledgements.isNotEmpty
        ? storedAcknowledgements
        : draft?.legacyAcknowledgements ?? const <ClientAppAcknowledgement>[];
    if (storedMessages.isEmpty && restoredMessages.isNotEmpty) {
      unawaited(conversation.saveMessages(restoredMessages));
    }
    if (storedAcknowledgements.isEmpty && restoredAcknowledgements.isNotEmpty) {
      unawaited(conversation.saveAcknowledgements(restoredAcknowledgements));
    }
    ClientPushSyncAttempt? latestTelegramAttempt;
    ClientPushSyncAttempt? latestSmsFallbackAttempt;
    ClientPushSyncAttempt? latestVoipAttempt;
    for (final attempt in storedPushSyncState.history) {
      if (attempt.status.startsWith('telegram-') &&
          latestTelegramAttempt == null) {
        latestTelegramAttempt = attempt;
      } else if (attempt.status.startsWith('sms-fallback') &&
          latestSmsFallbackAttempt == null) {
        latestSmsFallbackAttempt = attempt;
      } else if (attempt.status.startsWith('voip-') &&
          latestVoipAttempt == null) {
        latestVoipAttempt = attempt;
      }
      if (latestTelegramAttempt != null &&
          latestSmsFallbackAttempt != null &&
          latestVoipAttempt != null) {
        break;
      }
    }
    var restoredBridgeLabel = _telegramBridge.isConfigured
        ? 'configured'
        : 'disabled';
    String? restoredBridgeDetail = _telegramBridge.isConfigured
        ? 'Bridge token configured. Awaiting delivery attempts.'
        : 'Telegram bridge disabled or missing bot token.';
    var restoredFallbackActive = false;
    DateTime? restoredBridgeUpdatedAtUtc;
    if (latestTelegramAttempt != null) {
      restoredBridgeUpdatedAtUtc = latestTelegramAttempt.occurredAt.toUtc();
      switch (latestTelegramAttempt.status) {
        case 'telegram-ok':
          restoredBridgeLabel = 'ok';
          restoredBridgeDetail = 'Last Telegram delivery succeeded.';
          restoredFallbackActive = false;
          break;
        case 'telegram-blocked':
          restoredBridgeLabel = 'blocked';
          restoredBridgeDetail = latestTelegramAttempt.failureReason;
          restoredFallbackActive = true;
          break;
        case 'telegram-skipped':
          restoredBridgeLabel = 'no-target';
          restoredBridgeDetail = latestTelegramAttempt.failureReason;
          restoredFallbackActive = true;
          break;
        case 'telegram-failed':
          restoredBridgeLabel = 'degraded';
          restoredBridgeDetail = latestTelegramAttempt.failureReason;
          restoredFallbackActive = false;
          break;
        default:
          break;
      }
    }
    final scopedCommsAuditRestore =
        await _restoreScopedCommsExecutionUpdatesFromLocalCache(
          persistence: persistence,
          excludeScopeKeys: <String>{
            _clientCommsScopeKey(_selectedClient, _selectedSite),
          },
        );
    setState(() {
      if (draft != null) {
        _clientAppViewerRole = draft.viewerRole;
        _clientAppSelectedRoomByRole = Map<String, String>.from(
          draft.selectedRoomByRole,
        );
        _clientAppShowAllRoomItemsByRole = Map<String, bool>.from(
          draft.showAllRoomItemsByRole,
        );
        _clientAppSelectedRoom = draft.selectedRoomFor(
          ClientAppViewerRole.client,
        );
        _clientAppShowAllRoomItems = draft.showAllRoomItemsFor(
          ClientAppViewerRole.client,
        );
        _clientAppSelectedIncidentReferenceByRole = Map<String, String>.from(
          draft.selectedIncidentReferenceByRole,
        );
        _clientAppExpandedIncidentReferenceByRole = Map<String, String>.from(
          draft.expandedIncidentReferenceByRole,
        );
        _clientAppHasTouchedIncidentExpansionByRole = Map<String, bool>.from(
          draft.hasTouchedIncidentExpansionByRole,
        );
        _clientAppFocusedIncidentReferenceByRole = Map<String, String>.from(
          draft.focusedIncidentReferenceByRole,
        );
      }
      _clientAppMessages = restoredMessages;
      _clientConversationMessagesByScope = scopedConversationMessagesByScope;
      _clientAppAcknowledgements = restoredAcknowledgements;
      _clientAcknowledgementsByScope = scopedAcknowledgementsByScope;
      _clientAppPushQueue = List<ClientAppPushDeliveryItem>.from(
        storedPushQueue,
      );
      _clientPushQueueByScope = scopedPushQueueByScope;
      _clientAppPushSyncStatusLabel = storedPushSyncState.statusLabel;
      _clientAppPushLastSyncedAtUtc = storedPushSyncState.lastSyncedAtUtc;
      _clientAppPushSyncFailureReason = storedPushSyncState.failureReason;
      _clientAppPushSyncRetryCount = storedPushSyncState.retryCount;
      _clientAppPushSyncHistory = storedPushSyncState.history;
      _clientAppTelegramDeliveredMessageKeys =
          storedPushSyncState.telegramDeliveredMessageKeys;
      _telegramBridgeFallbackToInApp = restoredFallbackActive;
      _telegramBridgeHealthLabel = restoredBridgeLabel;
      _telegramBridgeHealthDetail = restoredBridgeDetail;
      _telegramBridgeHealthUpdatedAtUtc = restoredBridgeUpdatedAtUtc;
      _latestSmsFallbackUpdateByScope = <String, _ScopedCommsExecutionUpdate>{
        ...scopedCommsAuditRestore.smsFallbackUpdatesByScope,
        if (latestSmsFallbackAttempt != null)
          _clientCommsScopeKey(
            _selectedClient,
            _selectedSite,
          ): _ScopedCommsExecutionUpdate(
            clientId: _selectedClient,
            siteId: _selectedSite,
            status:
                (latestSmsFallbackAttempt.failureReason ?? '').trim().isEmpty
                ? latestSmsFallbackAttempt.status
                : latestSmsFallbackAttempt.failureReason!.trim(),
            occurredAtUtc: latestSmsFallbackAttempt.occurredAt.toUtc(),
          ),
      };
      _latestVoipStageUpdateByScope = <String, _ScopedCommsExecutionUpdate>{
        ...scopedCommsAuditRestore.voipStageUpdatesByScope,
        if (latestVoipAttempt != null)
          _clientCommsScopeKey(
            _selectedClient,
            _selectedSite,
          ): _ScopedCommsExecutionUpdate(
            clientId: _selectedClient,
            siteId: _selectedSite,
            status: (latestVoipAttempt.failureReason ?? '').trim().isEmpty
                ? latestVoipAttempt.status
                : latestVoipAttempt.failureReason!.trim(),
            occurredAtUtc: latestVoipAttempt.occurredAt.toUtc(),
          ),
      };
      _clientAppBackendProbeStatusLabel =
          storedPushSyncState.backendProbeStatusLabel;
      _clientAppBackendProbeLastRunAtUtc =
          storedPushSyncState.backendProbeLastRunAtUtc;
      _clientAppBackendProbeFailureReason =
          storedPushSyncState.backendProbeFailureReason;
      _clientAppBackendProbeHistory = storedPushSyncState.backendProbeHistory;
      _clientPushSyncStateByScope = scopedPushSyncStateByScope;
    });
  }

  Future<
    ({
      Map<String, _ScopedCommsExecutionUpdate> smsFallbackUpdatesByScope,
      Map<String, _ScopedCommsExecutionUpdate> voipStageUpdatesByScope,
    })
  >
  _restoreScopedCommsExecutionUpdatesFromLocalCache({
    required DispatchPersistenceService persistence,
    Set<String> excludeScopeKeys = const <String>{},
  }) async {
    final scopeKeys = await persistence.readClientConversationScopeKeys();
    if (scopeKeys.isEmpty) {
      return (
        smsFallbackUpdatesByScope:
            const <String, _ScopedCommsExecutionUpdate>{},
        voipStageUpdatesByScope: const <String, _ScopedCommsExecutionUpdate>{},
      );
    }
    final smsFallbackUpdatesByScope = <String, _ScopedCommsExecutionUpdate>{};
    final voipStageUpdatesByScope = <String, _ScopedCommsExecutionUpdate>{};
    for (final scopeKey in scopeKeys) {
      final normalizedScopeKey = scopeKey.trim();
      if (normalizedScopeKey.isEmpty ||
          excludeScopeKeys.contains(normalizedScopeKey)) {
        continue;
      }
      final parts = normalizedScopeKey.split('|');
      if (parts.length != 2) {
        continue;
      }
      final clientId = parts.first.trim();
      final siteId = parts.last.trim();
      if (clientId.isEmpty || siteId.isEmpty) {
        continue;
      }
      final repository = ScopedSharedPrefsClientConversationRepository(
        persistence: persistence,
        clientId: clientId,
        siteId: siteId,
      );
      final pushSyncState = await repository.readPushSyncState();
      ClientPushSyncAttempt? latestSmsFallbackAttempt;
      ClientPushSyncAttempt? latestVoipAttempt;
      for (final attempt in pushSyncState.history) {
        if (attempt.status.startsWith('sms-fallback') &&
            latestSmsFallbackAttempt == null) {
          latestSmsFallbackAttempt = attempt;
        } else if (attempt.status.startsWith('voip-') &&
            latestVoipAttempt == null) {
          latestVoipAttempt = attempt;
        }
        if (latestSmsFallbackAttempt != null && latestVoipAttempt != null) {
          break;
        }
      }
      if (latestSmsFallbackAttempt != null) {
        smsFallbackUpdatesByScope[normalizedScopeKey] =
            _ScopedCommsExecutionUpdate(
              clientId: clientId,
              siteId: siteId,
              status:
                  (latestSmsFallbackAttempt.failureReason ?? '').trim().isEmpty
                  ? latestSmsFallbackAttempt.status
                  : latestSmsFallbackAttempt.failureReason!.trim(),
              occurredAtUtc: latestSmsFallbackAttempt.occurredAt.toUtc(),
            );
      }
      if (latestVoipAttempt != null) {
        voipStageUpdatesByScope[normalizedScopeKey] =
            _ScopedCommsExecutionUpdate(
              clientId: clientId,
              siteId: siteId,
              status: (latestVoipAttempt.failureReason ?? '').trim().isEmpty
                  ? latestVoipAttempt.status
                  : latestVoipAttempt.failureReason!.trim(),
              occurredAtUtc: latestVoipAttempt.occurredAt.toUtc(),
            );
      }
    }
    return (
      smsFallbackUpdatesByScope: smsFallbackUpdatesByScope,
      voipStageUpdatesByScope: voipStageUpdatesByScope,
    );
  }

  Future<void> _hydrateTelegramAdminRuntimeState() async {
    final persistence = await _persistenceServiceFuture;
    final state = await persistence.readTelegramAdminRuntimeState();
    if (state.isEmpty) {
      return;
    }
    final pollOverride = _summaryInt(state['poll_interval_override_seconds']);
    final reminderOverride = _summaryInt(
      state['critical_reminder_override_seconds'],
    );
    final executionEnabledOverride = _summaryBool(
      state['execution_enabled_override'],
    );
    final allowedUserIdsOverrideRaw = state['allowed_user_ids_override'];
    final allowedUserIdsOverride = allowedUserIdsOverrideRaw is List
        ? allowedUserIdsOverrideRaw
              .map((entry) => int.tryParse((entry ?? '').toString().trim()))
              .whereType<int>()
              .where((value) => value > 0)
              .toSet()
              .toList(growable: false)
        : null;
    final targetClientOverride = _summaryString(
      state['target_client_override'],
    );
    final targetSiteOverride = _summaryString(state['target_site_override']);
    final criticalSnoozedUntil = _summaryDate(
      state['critical_snoozed_until_utc'],
    );
    final criticalAckFingerprint =
        _summaryString(state['critical_ack_fingerprint']) ?? '';
    final criticalAckAt = _summaryDate(state['critical_ack_at_utc']);
    final criticalAlertFingerprint =
        _summaryString(state['critical_alert_fingerprint']) ?? '';
    final lastCriticalAlertAt = _summaryDate(
      state['last_critical_alert_at_utc'],
    );
    final lastCriticalAlertSummary = _summaryString(
      state['last_critical_alert_summary'],
    );
    final lastCommandAt = _summaryDate(state['last_command_at_utc']);
    final lastCommandSummary = _summaryString(state['last_command_summary']);
    final lastUpdateId = _summaryInt(state['last_update_id']);
    final handledOutOfOrderRaw = state['handled_out_of_order_update_ids'];
    final handledOutOfOrderUpdateIds = handledOutOfOrderRaw is List
        ? handledOutOfOrderRaw
              .map((entry) => _summaryInt(entry))
              .whereType<int>()
              .where((value) => value > 0)
              .toSet()
        : const <int>{};
    final pendingOnboardingRaw = state['pending_onboarding_intake'];
    final pendingOnboarding = pendingOnboardingRaw is Map
        ? _TelegramAdminOnboardingIntake.fromJson(
            pendingOnboardingRaw.cast<Object?, Object?>().map(
              (key, value) => MapEntry(key.toString(), value),
            ),
          )
        : null;
    final approvedOnboardingPrefillRaw = state['approved_onboarding_prefill'];
    final approvedInviteLinksRaw = approvedOnboardingPrefillRaw is Map
        ? approvedOnboardingPrefillRaw['invite_links']
        : null;
    final approvedOnboardingPrefill = approvedOnboardingPrefillRaw is Map
        ? AdminApprovedTelegramOnboardingPrefill(
            clientId: (approvedOnboardingPrefillRaw['client_id'] ?? '')
                .toString()
                .trim(),
            clientName: (approvedOnboardingPrefillRaw['client_name'] ?? '')
                .toString()
                .trim(),
            siteId: (approvedOnboardingPrefillRaw['site_id'] ?? '')
                .toString()
                .trim(),
            siteName: (approvedOnboardingPrefillRaw['site_name'] ?? '')
                .toString()
                .trim(),
            cameraCount: int.tryParse(
              (approvedOnboardingPrefillRaw['camera_count'] ?? '')
                  .toString()
                  .trim(),
            ),
            vendor: (approvedOnboardingPrefillRaw['vendor'] ?? '')
                .toString()
                .trim(),
            contactName: (approvedOnboardingPrefillRaw['contact_name'] ?? '')
                .toString()
                .trim(),
            inviteLinks: <String>[
              if (approvedInviteLinksRaw is List)
                for (final entry in approvedInviteLinksRaw)
                  (entry ?? '').toString().trim(),
            ].where((entry) => entry.isNotEmpty).toList(growable: false),
            wantsTelegramBinding:
                (approvedOnboardingPrefillRaw['wants_telegram_binding'] ??
                        false)
                    .toString() ==
                'true',
          )
        : null;
    final approvedOnboardingFollowUpDismissed =
        _summaryBool(state['approved_onboarding_follow_up_dismissed']) ?? false;
    final approvedBridgeRunbookProgressRaw =
        state['approved_onboarding_bridge_runbook_progress'];
    final approvedBridgeRunbookProgress =
        approvedOnboardingPrefill != null &&
            approvedBridgeRunbookProgressRaw is Map
        ? AdminApprovedTelegramBridgeRunbookProgress(
            clientId: (approvedBridgeRunbookProgressRaw['client_id'] ?? '')
                .toString()
                .trim(),
            siteId: (approvedBridgeRunbookProgressRaw['site_id'] ?? '')
                .toString()
                .trim(),
            vendorValidated:
                (approvedBridgeRunbookProgressRaw['vendor_validated'] ?? false)
                    .toString() ==
                'true',
            cctvPolled:
                (approvedBridgeRunbookProgressRaw['cctv_polled'] ?? false)
                    .toString() ==
                'true',
            operationsOpened:
                (approvedBridgeRunbookProgressRaw['operations_opened'] ?? false)
                    .toString() ==
                'true',
          )
        : null;
    final normalizedApprovedBridgeRunbookProgress =
        approvedOnboardingPrefill != null &&
            approvedBridgeRunbookProgress != null &&
            approvedBridgeRunbookProgress.matchesPrefill(
              approvedOnboardingPrefill,
            )
        ? approvedBridgeRunbookProgress
        : null;
    final approvedClientSeed = approvedOnboardingPrefill == null
        ? null
        : _approvedTelegramClientSeedForPrefill(approvedOnboardingPrefill);
    final approvedSiteSeed = approvedOnboardingPrefill == null
        ? null
        : _approvedTelegramSiteSeedForPrefill(approvedOnboardingPrefill);
    final commandAuditRaw = state['command_audit'];
    final commandAudit = <String>[
      if (commandAuditRaw is List)
        for (final entry in commandAuditRaw) (entry ?? '').toString().trim(),
    ].where((entry) => entry.isNotEmpty).take(40).toList(growable: false);
    final aiAssistantEnabledOverride = _summaryBool(
      state['ai_assistant_enabled_override'],
    );
    final aiApprovalRequiredOverride = _summaryBool(
      state['ai_approval_required_override'],
    );
    final aiClientProfileOverridesRaw = state['ai_client_profile_overrides'];
    final aiClientProfileOverrides = <String, String>{
      if (aiClientProfileOverridesRaw is Map)
        for (final entry in aiClientProfileOverridesRaw.entries)
          if (entry.key.toString().trim().isNotEmpty &&
              (entry.value ?? '').toString().trim().isNotEmpty)
            entry.key.toString().trim(): (entry.value ?? '').toString().trim(),
    };
    final aiApprovedRewriteExamplesRaw =
        state['ai_approved_rewrite_examples_by_scope'];
    final aiApprovedRewriteExamples =
        <String, List<TelegramAiLearnedReplyExample>>{
          if (aiApprovedRewriteExamplesRaw is Map)
            for (final entry in aiApprovedRewriteExamplesRaw.entries)
              if (entry.key.toString().trim().isNotEmpty)
                entry.key.toString().trim():
                    _parseTelegramAiLearnedReplyExamples(entry.value),
        };
    final aiPendingDraftsRaw = state['ai_pending_drafts'];
    final aiPendingDrafts =
        <_TelegramAiPendingDraft>[
              if (aiPendingDraftsRaw is List)
                for (final entry in aiPendingDraftsRaw)
                  if (entry is Map)
                    _TelegramAiPendingDraft.fromJson(
                      entry.cast<Object?, Object?>().map(
                        (key, value) => MapEntry(key.toString(), value),
                      ),
                    ),
            ]
            .where(
              (entry) =>
                  entry.inboundUpdateId > 0 &&
                  entry.chatId.trim().isNotEmpty &&
                  entry.draftText.trim().isNotEmpty,
            )
            .take(100)
            .toList(growable: false);
    final liveOperationsQueueHintSeen =
        _summaryBool(state['live_operations_queue_hint_seen']) ?? false;
    final cameraBridgeHealthSnapshotRaw =
        state['camera_bridge_health_snapshot'];
    final cameraBridgeHealthSnapshot = cameraBridgeHealthSnapshotRaw is Map
        ? OnyxAgentCameraBridgeHealthSnapshot.fromJson(
            cameraBridgeHealthSnapshotRaw.cast<Object?, Object?>().map(
              (key, value) => MapEntry(key.toString(), value),
            ),
          )
        : null;
    final partnerBindingsRaw = state['partner_dispatch_bindings'];
    final partnerBindings =
        <_TelegramPartnerDispatchBinding>[
              if (partnerBindingsRaw is List)
                for (final entry in partnerBindingsRaw)
                  if (entry is Map)
                    _TelegramPartnerDispatchBinding.fromJson(
                      entry.cast<Object?, Object?>().map(
                        (key, value) => MapEntry(key.toString(), value),
                      ),
                    ),
            ]
            .where(
              (entry) =>
                  entry.chatId.trim().isNotEmpty &&
                  entry.telegramMessageId > 0 &&
                  entry.dispatchId.trim().isNotEmpty &&
                  entry.clientId.trim().isNotEmpty &&
                  entry.siteId.trim().isNotEmpty,
            )
            .take(200)
            .toList(growable: false);
    final alarmScopeBindingsRaw = state['listener_alarm_scope_bindings'];
    final alarmScopeBindings =
        <ListenerAlarmScopeMappingEntry>[
              if (alarmScopeBindingsRaw is List)
                for (final entry in alarmScopeBindingsRaw)
                  if (entry is Map)
                    ListenerAlarmScopeMappingEntry.fromJson(
                      entry.cast<Object?, Object?>().map(
                        (key, value) => MapEntry(key.toString(), value),
                      ),
                    ),
            ]
            .where(
              (entry) =>
                  entry.accountNumber.trim().isNotEmpty &&
                  entry.clientId.trim().isNotEmpty &&
                  entry.siteId.trim().isNotEmpty,
            )
            .take(500)
            .toList(growable: false);
    if (!mounted) {
      _telegramAdminPollIntervalSecondsOverride = pollOverride;
      _telegramAdminCriticalReminderSecondsOverride = reminderOverride;
      _telegramAdminExecutionEnabledOverride = executionEnabledOverride;
      _telegramAdminAllowedUserIdsOverride = allowedUserIdsOverride;
      _telegramAdminTargetClientIdOverride = targetClientOverride;
      _telegramAdminTargetSiteIdOverride = targetSiteOverride;
      _telegramAdminCriticalSnoozedUntilUtc = criticalSnoozedUntil;
      _telegramAdminCriticalAckFingerprint = criticalAckFingerprint;
      _telegramAdminCriticalAckAtUtc = criticalAckAt;
      _telegramAdminCriticalAlertFingerprint = criticalAlertFingerprint;
      _telegramAdminLastCriticalAlertAtUtc = lastCriticalAlertAt;
      _telegramAdminLastCriticalAlertSummary = lastCriticalAlertSummary;
      _telegramAdminLastCommandAtUtc = lastCommandAt;
      _telegramAdminLastCommandSummary = lastCommandSummary;
      _telegramAdminLastUpdateId = lastUpdateId;
      _telegramAdminHandledOutOfOrderUpdateIds = handledOutOfOrderUpdateIds;
      _telegramAdminPendingOnboardingIntake = pendingOnboarding;
      _telegramApprovedOnboardingPrefill = approvedOnboardingPrefill;
      _telegramApprovedBridgeRunbookProgress =
          normalizedApprovedBridgeRunbookProgress;
      _telegramApprovedOnboardingFollowUpDismissed =
          approvedOnboardingFollowUpDismissed;
      _telegramAdminDirectoryRefreshToken = approvedOnboardingPrefill == null
          ? 0
          : 1;
      _telegramApprovedDirectoryClientSeeds = approvedClientSeed == null
          ? const <AdminDirectoryClientSeed>[]
          : <AdminDirectoryClientSeed>[approvedClientSeed];
      _telegramApprovedDirectorySiteSeeds = approvedSiteSeed == null
          ? const <AdminDirectorySiteSeed>[]
          : <AdminDirectorySiteSeed>[approvedSiteSeed];
      _telegramAdminCommandAudit = commandAudit;
      _telegramAiAssistantEnabledOverride = aiAssistantEnabledOverride;
      _telegramAiApprovalRequiredOverride = aiApprovalRequiredOverride;
      _telegramAiClientProfileOverrideByScope = aiClientProfileOverrides;
      _liveOperationsQueueHintSeen = liveOperationsQueueHintSeen;
      _onyxAgentCameraBridgeHealthSnapshot = cameraBridgeHealthSnapshot;
      _telegramAiApprovedRewriteExamplesByScope = aiApprovedRewriteExamples;
      _telegramAiPendingDrafts = aiPendingDrafts;
      _telegramPartnerDispatchBindings = partnerBindings;
      _listenerAlarmScopeRegistry.replaceAll(alarmScopeBindings);
      return;
    }
    setState(() {
      _telegramAdminPollIntervalSecondsOverride = pollOverride;
      _telegramAdminCriticalReminderSecondsOverride = reminderOverride;
      _telegramAdminExecutionEnabledOverride = executionEnabledOverride;
      _telegramAdminAllowedUserIdsOverride = allowedUserIdsOverride;
      _telegramAdminTargetClientIdOverride = targetClientOverride;
      _telegramAdminTargetSiteIdOverride = targetSiteOverride;
      _telegramAdminCriticalSnoozedUntilUtc = criticalSnoozedUntil;
      _telegramAdminCriticalAckFingerprint = criticalAckFingerprint;
      _telegramAdminCriticalAckAtUtc = criticalAckAt;
      _telegramAdminCriticalAlertFingerprint = criticalAlertFingerprint;
      _telegramAdminLastCriticalAlertAtUtc = lastCriticalAlertAt;
      _telegramAdminLastCriticalAlertSummary = lastCriticalAlertSummary;
      _telegramAdminLastCommandAtUtc = lastCommandAt;
      _telegramAdminLastCommandSummary = lastCommandSummary;
      _telegramAdminPendingOnboardingIntake = pendingOnboarding;
      _telegramApprovedOnboardingPrefill = approvedOnboardingPrefill;
      _telegramApprovedBridgeRunbookProgress =
          normalizedApprovedBridgeRunbookProgress;
      _telegramApprovedOnboardingFollowUpDismissed =
          approvedOnboardingFollowUpDismissed;
      _telegramAdminDirectoryRefreshToken = approvedOnboardingPrefill == null
          ? 0
          : 1;
      _telegramApprovedDirectoryClientSeeds = approvedClientSeed == null
          ? const <AdminDirectoryClientSeed>[]
          : <AdminDirectoryClientSeed>[approvedClientSeed];
      _telegramApprovedDirectorySiteSeeds = approvedSiteSeed == null
          ? const <AdminDirectorySiteSeed>[]
          : <AdminDirectorySiteSeed>[approvedSiteSeed];
      _telegramAdminCommandAudit = commandAudit;
      _telegramAiAssistantEnabledOverride = aiAssistantEnabledOverride;
      _telegramAiApprovalRequiredOverride = aiApprovalRequiredOverride;
      _telegramAiClientProfileOverrideByScope = aiClientProfileOverrides;
      _liveOperationsQueueHintSeen = liveOperationsQueueHintSeen;
      _onyxAgentCameraBridgeHealthSnapshot = cameraBridgeHealthSnapshot;
      _telegramAiApprovedRewriteExamplesByScope = aiApprovedRewriteExamples;
      _telegramAiPendingDrafts = aiPendingDrafts;
      _telegramPartnerDispatchBindings = partnerBindings;
      _listenerAlarmScopeRegistry.replaceAll(alarmScopeBindings);
    });
  }

  Future<void> _hydrateOnyxAgentThreadSessionState() async {
    final persistence = await _persistenceServiceFuture;
    final state = await persistence.readOnyxAgentThreadSessionState();
    if (state.isEmpty) {
      return;
    }
    final rawSessions = state['sessions_by_scope'];
    if (rawSessions is! Map) {
      return;
    }
    final sessions = rawSessions.map(
      (key, value) => MapEntry(key.toString(), value as Object?),
    );
    if (!mounted) {
      return;
    }
    setState(() {
      _onyxAgentThreadSessionStateByScope = sessions;
    });
  }

  Future<void> _hydrateMonitoringWatchRuntimeState() async {
    final persistence = await _persistenceServiceFuture;
    final raw = await persistence.readMonitoringWatchRuntimeState();
    final restored = _watchRuntimeStore.parsePersistedState(raw);
    _monitoringWatchByScope
      ..clear()
      ..addAll(restored);
    if (mounted) {
      setState(() {});
    }
    _syncMonitoringContinuousVisualWatchLoop();
    if (_monitoringShiftAutoEligible) {
      unawaited(_syncMonitoringWatchScheduleNow());
    }
  }

  Future<void> _persistMonitoringWatchRuntimeState() async {
    final persistence = await _persistenceServiceFuture;
    final prepared = _watchRuntimeStore.preparePersistedState(
      _monitoringWatchByScope,
    );
    if (prepared.shouldClear) {
      await persistence.clearMonitoringWatchRuntimeState();
      return;
    }
    await persistence.saveMonitoringWatchRuntimeState(prepared.serializedState);
  }

  Future<void> _hydrateMonitoringWatchAuditState() async {
    final persistence = await _persistenceServiceFuture;
    final restored = await persistence.readMonitoringWatchAuditHistory();
    final restoredSummary = await persistence.readMonitoringWatchAuditSummary();
    final normalized = _watchRecoveryStore.restoreAuditState(
      persistedHistory: restored,
      persistedSummary: restoredSummary,
    );
    if (!mounted) {
      _monitoringWatchAuditHistory = normalized.history;
      _monitoringWatchAuditSummary = normalized.summary;
      return;
    }
    setState(() {
      _monitoringWatchAuditHistory = normalized.history;
      _monitoringWatchAuditSummary = normalized.summary;
    });
  }

  Future<void> _persistMonitoringWatchAuditSummary() async {
    final persistence = await _persistenceServiceFuture;
    final summary = _watchRecoveryStore.normalizeAuditSummaryForPersist(
      _monitoringWatchAuditSummary,
    );
    if (summary == null) {
      await persistence.clearMonitoringWatchAuditSummary();
      return;
    }
    await persistence.saveMonitoringWatchAuditSummary(summary);
  }

  Future<void> _persistMonitoringWatchAuditHistory() async {
    final persistence = await _persistenceServiceFuture;
    final prepared = _watchRecoveryStore.prepareAuditHistoryForPersist(
      auditHistory: _monitoringWatchAuditHistory,
    );
    if (prepared.shouldClear) {
      await persistence.clearMonitoringWatchAuditHistory();
      return;
    }
    if (prepared.history.length != _monitoringWatchAuditHistory.length) {
      _monitoringWatchAuditHistory = prepared.history;
    }
    await persistence.saveMonitoringWatchAuditHistory(prepared.history);
  }

  Future<void> _hydrateMonitoringWatchRecoveryState() async {
    final persistence = await _persistenceServiceFuture;
    final raw = await persistence.readMonitoringWatchRecoveryState();
    final nowUtc = DateTime.now().toUtc();
    final restore = _watchRecoveryStore.restoreState(
      raw: raw,
      auditHistory: _monitoringWatchAuditHistory,
      scopes: _watchRecoveryScopeResolver.resolve(
        scopes: _configuredDvrScopes,
        siteLabelForScope: (clientId, siteId) => _monitoringSiteProfileFor(
          clientId: clientId,
          siteId: siteId,
        ).siteName,
      ),
      nowUtc: nowUtc,
    );
    _monitoringWatchRecoveryByScope
      ..clear()
      ..addAll(restore.stateByScope);
    if (restore.shouldPersist) {
      unawaited(_persistMonitoringWatchRecoveryState());
    }
    if (mounted) {
      setState(() {});
    }
  }

