              .toString(),
      previousShiftReviewCommand:
          activityReviewShortcuts['previousShiftReviewCommand']?.toString(),
      previousShiftCaseFileCommand:
          activityReviewShortcuts['previousShiftCaseFileCommand']?.toString(),
      targetScope: targetScope,
      targetScopeRequired: true,
      utcStamp: _telegramUtcStamp(),
    );
    try {
      await _sendTelegramMessageWithChunks(
        messageKeyPrefix: 'tg-admin-morning-governance-${report.date}',
        chatId: adminChatId,
        messageThreadId: adminThreadId,
        responseText: responseText,
        failureContext: 'Morning governance digest',
        replyMarkup: _telegramAdminQuickReplyMarkup(),
        parseMode: 'HTML',
      );
    } catch (_) {
      // Governance digests must not block the morning report cycle.
    }
  }

  SovereignReport? _morningSovereignReportForDate(String? reportDate) {
    final normalizedDate = (reportDate ?? '').trim();
    if (normalizedDate.isEmpty) {
      return _morningSovereignReport;
    }
    final current = _morningSovereignReport;
    if (current != null && current.date.trim() == normalizedDate) {
      return current;
    }
    for (final item in _morningSovereignReportHistory) {
      if (item.date.trim() == normalizedDate) {
        return item;
      }
    }
    return null;
  }

  bool _isHistoricalReadinessFocus(String reportDate) {
    return buildOversightFocusState(
          reportDate: reportDate,
          currentReportDate: _morningSovereignReport?.date ?? '',
        ) ==
        'historical_command_target';
  }

  String _readinessFocusState(String reportDate) {
    return buildOversightFocusState(
      reportDate: reportDate,
      currentReportDate: _morningSovereignReport?.date ?? '',
    );
  }

  String _readinessFocusSummary(String reportDate) {
    return buildOversightFocusSummary(
      reportDate: reportDate,
      currentReportDate: _morningSovereignReport?.date ?? '',
    );
  }

  List<SovereignReport> _governanceHistoryForFocusedReport(
    SovereignReport? focusedReport,
  ) {
    final combined = <SovereignReport>[
      ...?switch (_morningSovereignReport) {
        final report? => <SovereignReport>[report],
        null => null,
      },
      ..._morningSovereignReportHistory,
    ];
    final normalized = _normalizedMorningSovereignReportHistory(combined);
    final focusKey = focusedReport == null
        ? ''
        : _morningSovereignReportHistoryKeyFor(focusedReport);
    if (focusKey.isEmpty) {
      return normalized;
    }
    return normalized
        .where(
          (report) => _morningSovereignReportHistoryKeyFor(report) != focusKey,
        )
        .toList(growable: false);
  }

  List<DispatchEvent> _eventsScopedToWindow(
    DateTime? startUtcValue,
    DateTime? endUtcValue,
  ) {
    final startUtc = startUtcValue?.toUtc();
    final endUtc = endUtcValue?.toUtc();
    if (startUtc == null || endUtc == null) {
      return store.allEvents();
    }
    return store
        .allEvents()
        .where(
          (event) =>
              !event.occurredAt.toUtc().isBefore(startUtc) &&
              !event.occurredAt.toUtc().isAfter(endUtc),
        )
        .toList(growable: false);
  }

