  String _shadowMoSummaryForSites(List<MonitoringGlobalSitePosture> sites) {
    if (sites.isEmpty) {
      return '';
    }
    final leadSite = sites.first;
    final totalMatches = sites.fold<int>(
      0,
      (current, site) => current + site.moShadowMatchCount,
    );
    final parts = <String>[
      'Sites ${sites.length}',
      'Matches $totalMatches',
      if (leadSite.siteId.trim().isNotEmpty) leadSite.siteId.trim(),
      if (leadSite.moShadowSummary.trim().isNotEmpty) leadSite.moShadowSummary,
    ];
    return _singleLine(parts.join(' • '), maxLength: 220);
  }

  String _shadowMoValidationSummaryForSites(
    List<MonitoringGlobalSitePosture> sites,
  ) {
    if (sites.isEmpty) {
      return '';
    }
    final counts = <String, int>{};
    for (final site in sites) {
      for (final match in site.moShadowMatches) {
        final status = match.validationStatus.trim();
        if (status.isEmpty) {
          continue;
        }
        counts.update(status, (value) => value + 1, ifAbsent: () => 1);
      }
    }
    if (counts.isEmpty) {
      return '';
    }
    const priority = <String>[
      'production',
      'validated',
      'shadowMode',
      'candidate',
    ];
    final ordered = counts.keys.toList(growable: false)
      ..sort((left, right) {
        final leftIndex = priority.indexOf(left);
        final rightIndex = priority.indexOf(right);
        if (leftIndex == -1 && rightIndex == -1) {
          return left.compareTo(right);
        }
        if (leftIndex == -1) {
          return 1;
        }
        if (rightIndex == -1) {
          return -1;
        }
        return leftIndex.compareTo(rightIndex);
      });
    final parts = ordered
        .map(
          (status) =>
              '${_humanizeShadowValidationStatus(status)} ${counts[status]}',
        )
        .toList(growable: false);
    return _singleLine(parts.join(' • '), maxLength: 220);
  }

  String _shadowMoPostureSummaryForReport(SovereignReport report) {
    return _singleLine(
      shadowMoPostureStrengthSummaryForSites(_shadowMoSitesForReport(report)),
      maxLength: 220,
    );
  }

  String _humanizeShadowValidationStatus(String status) {
    switch (status.trim()) {
      case 'shadowMode':
        return 'Shadow mode';
      case 'validated':
        return 'Validated';
      case 'production':
        return 'Production';
      case 'candidate':
        return 'Candidate';
      default:
        final trimmed = status.trim();
        if (trimmed.isEmpty) {
          return '';
        }
        return trimmed[0].toUpperCase() + trimmed.substring(1);
    }
  }

  int _shadowMoMatchCountForSites(List<MonitoringGlobalSitePosture> sites) {
    return sites.fold<int>(
      0,
      (current, site) => current + site.moShadowMatchCount,
    );
  }

