  Map<String, Object?> _tomorrowPostureCaseFilePayload({String? reportDate}) {
    final normalizedReportDate = reportDate?.trim() ?? '';
    final report = _morningSovereignReportForDate(normalizedReportDate);
    if (report == null) {
      return <String, Object?>{
        'available': false,
        'reportDate': normalizedReportDate,
        'summary': 'No morning sovereign report is available for that shift.',
      };
    }
    final readinessEvidence = _globalReadinessCaseFilePayload(
      reportDate: report.date,
    );
    final drafts = _tomorrowPostureDraftsForReport(report);
    final history = _governanceHistoryForFocusedReport(report)
        .where((item) => item.date.trim() != report.date.trim())
        .take(3)
        .map((item) {
          final itemDrafts = _tomorrowPostureDraftsForReport(item);
          final leadDraft = itemDrafts.isEmpty ? null : itemDrafts.first;
          return <String, Object?>{
            'reportDate': item.date,
            'summary': _globalReadinessTomorrowPostureSummary(itemDrafts),
            'shadowSummary': _globalReadinessTomorrowShadowSummary(
              item,
              itemDrafts,
            ),
            'shadowPostureSummary': _shadowMoPostureSummaryForReport(item),
            'urgencySummary': _globalReadinessTomorrowUrgencySummary(
              itemDrafts,
            ),
            'promotionPressureSummary':
                buildTomorrowPromotionPressureSummaryForDraft(draft: leadDraft),
            'promotionExecutionSummary':
                buildTomorrowPromotionExecutionSummaryForDraft(
                  draft: leadDraft,
                ),
            'draftCount': itemDrafts.length,
            ...buildReviewCommandPair(
              reportDate: item.date,
              reviewCommandBuilder: (value) => '/tomorrowreview $value',
              caseFileCommandBuilder: (value) => '/tomorrowcase json $value',
            ),
          };
        })
        .toList(growable: false);
    return <String, Object?>{
      'available': true,
      'reportDate': report.date,
      'generatedAtUtc': report.generatedAtUtc.toIso8601String(),
      'focusSummary': _readinessFocusSummary(report.date),
      'summary': _globalReadinessTomorrowPostureSummary(drafts),
      'shadowSummary': _globalReadinessTomorrowShadowSummary(report, drafts),
      'shadowPostureSummary': _shadowMoPostureSummaryForReport(report),
      'urgencySummary': _globalReadinessTomorrowUrgencySummary(drafts),
      'promotionPressureSummary': buildTomorrowPromotionPressureSummaryForDraft(
        draft: drafts.isEmpty ? null : drafts.first,
      ),
      'promotionExecutionSummary':
          buildTomorrowPromotionExecutionSummaryForDraft(
            draft: drafts.isEmpty ? null : drafts.first,
          ),
      'draftCount': drafts.length,
      'eventIds': readinessEvidence['eventIds'] ?? const <Object?>[],
      'reviewRefs': readinessEvidence['reviewRefs'] ?? const <Object?>[],
      'selectedEventId': readinessEvidence['selectedEventId'],
      'reviewCommand': '/tomorrowreview ${report.date}',
      'caseFileCommand': '/tomorrowcase json ${report.date}',
      'governanceCommand': '/readinessgovernance ${report.date}',
      'drafts': drafts
          .take(5)
          .map(
            (draft) => <String, Object?>{
              'actionType': draft.actionType,
              'siteId': draft.siteId,
              'priority': draft.priority.name,
              'description': draft.description,
              'countdownSeconds': draft.countdownSeconds,
              'learningLabel': draft.metadata['learning_label'] ?? '',
              'repeatCount': draft.metadata['learning_repeat_count'] ?? '',
              'shadowLabel': draft.metadata['shadow_mo_label'] ?? '',
              'shadowTitle': draft.metadata['shadow_mo_title'] ?? '',
              'shadowRepeatCount':
                  draft.metadata['shadow_mo_repeat_count'] ?? '',
              'urgencySummary': _globalReadinessTomorrowUrgencySummary([draft]),
              'promotionPressureSummary':
                  buildTomorrowPromotionPressureSummaryForDraft(draft: draft),
              'promotionExecutionSummary':
                  buildTomorrowPromotionExecutionSummaryForDraft(draft: draft),
              'hazardSignal': draft.metadata['hazard_signal'] ?? '',
              'metadata': draft.metadata,
            },
          )
          .toList(growable: false),
      'history': history,
    };
  }

  String _tomorrowPostureCaseFileCsv({String? reportDate}) {
    final payload = _tomorrowPostureCaseFilePayload(reportDate: reportDate);
    final history = (payload['history'] as List<Object?>?) ?? const [];
    final drafts = (payload['drafts'] as List<Object?>?) ?? const [];
    final lines = <String>[
      'metric,value',
      'report_date,${payload['reportDate'] ?? ''}',
      'available,${payload['available'] == false ? 'false' : 'true'}',
      'generated_at_utc,${payload['generatedAtUtc'] ?? ''}',
      'focus_summary,"${(payload['focusSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'summary,"${(payload['summary'] ?? '').toString().replaceAll('"', '""')}"',
      'shadow_summary,"${(payload['shadowSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'shadow_posture_summary,"${(payload['shadowPostureSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'urgency_summary,"${(payload['urgencySummary'] ?? '').toString().replaceAll('"', '""')}"',
      'promotion_pressure_summary,"${(payload['promotionPressureSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'promotion_execution_summary,"${(payload['promotionExecutionSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'draft_count,${payload['draftCount'] ?? 0}',
      'selected_event_id,${payload['selectedEventId'] ?? ''}',
      'review_refs,"${((payload['reviewRefs'] as List<Object?>?) ?? const <Object?>[]).join(', ').replaceAll('"', '""')}"',
      'review_command,${payload['reviewCommand'] ?? ''}',
      'case_file_command,${payload['caseFileCommand'] ?? ''}',
      'governance_command,${payload['governanceCommand'] ?? ''}',
    ];
    for (var i = 0; i < drafts.length; i += 1) {
      final draft = drafts[i];
      if (draft is! Map) continue;
      lines.add(
        'draft_${i + 1},"${(draft['actionType'] ?? '').toString().replaceAll('"', '""')} • ${(draft['siteId'] ?? '').toString().replaceAll('"', '""')} • ${(draft['description'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'draft_${i + 1}_learning_label,${draft['learningLabel'] ?? ''}',
      );
      lines.add('draft_${i + 1}_repeat_count,${draft['repeatCount'] ?? ''}');
      final shadowParts = <String>[
        (draft['shadowLabel'] ?? '').toString().trim(),
        (draft['shadowTitle'] ?? '').toString().trim(),
        ((draft['shadowRepeatCount'] ?? '').toString().trim().isEmpty)
            ? ''
            : 'x${(draft['shadowRepeatCount'] ?? '').toString().trim()}',
      ].where((value) => value.isNotEmpty).join(' • ');
      lines.add(
        'draft_${i + 1}_shadow_summary,"${shadowParts.replaceAll('"', '""')}"',
      );
      lines.add(
        'draft_${i + 1}_urgency_summary,"${(draft['urgencySummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'draft_${i + 1}_promotion_pressure_summary,"${(draft['promotionPressureSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'draft_${i + 1}_promotion_execution_summary,"${(draft['promotionExecutionSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
    }
    for (var i = 0; i < history.length; i += 1) {
      final row = history[i];
      if (row is! Map) continue;
      lines.add(
        'history_${i + 1},"${(row['summary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_shadow_summary,"${(row['shadowSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_shadow_posture_summary,"${(row['shadowPostureSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_urgency_summary,"${(row['urgencySummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_promotion_pressure_summary,"${(row['promotionPressureSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_promotion_execution_summary,"${(row['promotionExecutionSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.addAll(
        buildHistoryReviewCommandCsvRows(
          row: i + 1,
          reportDate: (row['reportDate'] ?? '').toString(),
          reviewCommandBuilder: (value) => '/tomorrowreview $value',
          caseFileCommandBuilder: (value) => '/tomorrowcase json $value',
        ),
      );
    }
    return lines.join('\n');
  }

