  List<IntelligenceReceived> _reviewedIntelligenceEventsForReport(
    SovereignReport report,
  ) {
    final scopedEvents = _eventsScopedToWindow(
      report.shiftWindowStartUtc,
      report.shiftWindowEndUtc,
    );
    final reviewed =
        scopedEvents
            .whereType<IntelligenceReceived>()
            .where(
              (event) => _monitoringSceneReviewByIntelligenceId.containsKey(
                event.intelligenceId.trim(),
              ),
            )
            .toList(growable: false)
          ..sort((left, right) => right.occurredAt.compareTo(left.occurredAt));
    return reviewed;
  }

  Map<String, Object?> _globalReadinessEvidenceForSite({
    required SovereignReport report,
    required String siteId,
  }) {
    final normalizedSiteId = siteId.trim();
    if (normalizedSiteId.isEmpty) {
      return const <String, Object?>{
        'eventIds': <String>[],
        'reviewRefs': <String>[],
        'selectedEventId': null,
      };
    }
    final matches = _reviewedIntelligenceEventsForReport(report)
        .where((event) => event.siteId.trim() == normalizedSiteId)
        .toList(growable: false);
    final eventIds = matches
        .map((event) => event.eventId.trim())
        .where((value) => value.isNotEmpty)
        .take(6)
        .toList(growable: false);
    final reviewRefs = matches
        .map((event) => event.intelligenceId.trim())
        .where((value) => value.isNotEmpty)
        .take(6)
        .toList(growable: false);
    return <String, Object?>{
      'eventIds': eventIds,
      'reviewRefs': reviewRefs,
      'selectedEventId': eventIds.isEmpty ? null : eventIds.first,
    };
  }

  Map<String, Object?> _globalReadinessEvidenceForRegion({
    required SovereignReport report,
    required String regionId,
  }) {
    final normalizedRegionId = regionId.trim();
    if (normalizedRegionId.isEmpty) {
      return const <String, Object?>{
        'eventIds': <String>[],
        'reviewRefs': <String>[],
        'selectedEventId': null,
      };
    }
    final matches = _reviewedIntelligenceEventsForReport(report)
        .where((event) => event.regionId.trim() == normalizedRegionId)
        .toList(growable: false);
    final eventIds = matches
        .map((event) => event.eventId.trim())
        .where((value) => value.isNotEmpty)
        .take(8)
        .toList(growable: false);
    final reviewRefs = matches
        .map((event) => event.intelligenceId.trim())
        .where((value) => value.isNotEmpty)
        .take(8)
        .toList(growable: false);
    return <String, Object?>{
      'eventIds': eventIds,
      'reviewRefs': reviewRefs,
      'selectedEventId': eventIds.isEmpty ? null : eventIds.first,
    };
  }

  Map<String, Object?> _globalReadinessCaseFilePayload({String? reportDate}) {
    final report = _morningSovereignReportForDate(reportDate);
    if (report == null) {
      return <String, Object?>{
        'reportDate': (reportDate ?? '').trim(),
        'available': false,
        'message': 'No morning sovereign report is available for that shift.',
      };
    }
    final snapshot = _globalReadinessSnapshotForReport(report);
    final intents = _globalReadinessIntentsForReport(report);
    final posturalEchoes = intents
        .where(
          (intent) => intent.actionType.trim().toUpperCase() == 'POSTURAL ECHO',
        )
        .toList(growable: false);
    final leadRegion = snapshot.regions.isEmpty ? null : snapshot.regions.first;
    final leadSite = snapshot.sites.isEmpty ? null : snapshot.sites.first;
    final leadRegionEvidence = leadRegion == null
        ? const <String, Object?>{
            'eventIds': <String>[],
            'reviewRefs': <String>[],
            'selectedEventId': null,
          }
        : _globalReadinessEvidenceForRegion(
            report: report,
            regionId: leadRegion.regionId,
          );
    final leadSiteEvidence = leadSite == null
        ? const <String, Object?>{
            'eventIds': <String>[],
            'reviewRefs': <String>[],
            'selectedEventId': null,
          }
        : _globalReadinessEvidenceForSite(
            report: report,
            siteId: leadSite.siteId,
          );
    final primaryEvidence =
        ((leadSiteEvidence['eventIds'] as List<Object?>?) ?? const <Object?>[])
            .isNotEmpty
        ? leadSiteEvidence
        : leadRegionEvidence;
    final history =
        _morningSovereignReportHistory
            .where((item) => item.date.trim() != report.date.trim())
            .toList(growable: false)
          ..sort(
            (left, right) =>
                right.generatedAtUtc.compareTo(left.generatedAtUtc),
          );
    return <String, Object?>{
      'reportDate': report.date,
      'generatedAtUtc': report.generatedAtUtc.toIso8601String(),
      'focusState': _readinessFocusState(report.date),
      'historicalFocus': _isHistoricalReadinessFocus(report.date),
      'focusSummary': _readinessFocusSummary(report.date),
      'liveReportDate': (_morningSovereignReport?.date ?? '').trim(),
      'modeLabel': _globalReadinessModeLabel(snapshot, intents),
      'summary': _globalReadinessSummaryForReport(
        snapshot: snapshot,
        intents: intents,
      ),
      'totalSites': snapshot.totalSites,
      'criticalSiteCount': snapshot.criticalSiteCount,
      'elevatedSiteCount': snapshot.elevatedSiteCount,
      'intentCount': intents.length,
      'posturalEchoCount': posturalEchoes.length,
      'posturalEchoSummary': _globalReadinessEchoSummary(intents),
      'topIntentSummary': _globalReadinessTopIntentSummary(intents),
      'hazardSummary': _globalReadinessHazardSummary(intents),
      'shadowBiasSummary': _globalReadinessShadowBiasSummary(intents),
      'eventIds': primaryEvidence['eventIds'] ?? const <Object?>[],
      'reviewRefs': primaryEvidence['reviewRefs'] ?? const <Object?>[],
      'selectedEventId': primaryEvidence['selectedEventId'],
      'leadRegion': leadRegion == null
          ? null
          : <String, Object?>{
              'regionId': leadRegion.regionId,
              'summary': leadRegion.summary,
              'heatLevel': leadRegion.heatLevel.name,
              'eventIds': leadRegionEvidence['eventIds'] ?? const <Object?>[],
              'reviewRefs':
                  leadRegionEvidence['reviewRefs'] ?? const <Object?>[],
              'selectedEventId': leadRegionEvidence['selectedEventId'],
            },
      'leadSite': leadSite == null
          ? null
          : <String, Object?>{
              'siteId': leadSite.siteId,
              'summary': leadSite.latestSummary,
              'dominantSignals': leadSite.dominantSignals,
              'heatLevel': leadSite.heatLevel.name,
              'eventIds': leadSiteEvidence['eventIds'] ?? const <Object?>[],
              'reviewRefs': leadSiteEvidence['reviewRefs'] ?? const <Object?>[],
              'selectedEventId': leadSiteEvidence['selectedEventId'],
            },
      'reviewCommand': '/readinessreview ${report.date}',
      'caseFileCommand': '/readinesscase json ${report.date}',
      'governanceCommand': '/readinessgovernance ${report.date}',
      'topIntents': intents
          .take(5)
          .map(
            (intent) => <String, Object?>{
              'actionType': intent.actionType,
              'siteId': intent.siteId,
              'priority': intent.priority.name,
              'description': intent.description,
              'countdownSeconds': intent.countdownSeconds,
              'incidentId': intent.incidentId,
              'metadata': intent.metadata,
            },
          )
          .toList(growable: false),
      'posturalEchoes': posturalEchoes
          .take(3)
          .map(
            (intent) => <String, Object?>{
              'siteId': intent.siteId,
              'priority': intent.priority.name,
              'description': intent.description,
              'leadSite': intent.metadata['lead_site'] ?? '',
              'echoTarget': intent.metadata['echo_target'] ?? intent.siteId,
              'echoHeat': intent.metadata['echo_heat'] ?? '',
              'echoSignals': intent.metadata['echo_signals'] ?? '',
              'incidentId': intent.incidentId,
              'reviewRefs': <String>[
                if (intent.incidentId.trim().isNotEmpty)
                  intent.incidentId.trim(),
              ],
            },
          )
          .toList(growable: false),
      'history': history
          .take(3)
          .map((item) {
            final itemSnapshot = _globalReadinessSnapshotForReport(item);
            final itemIntents = _globalReadinessIntentsForReport(item);
            final itemEchoCount = itemIntents
                .where(
                  (intent) =>
                      intent.actionType.trim().toUpperCase() == 'POSTURAL ECHO',
                )
                .length;
            return <String, Object?>{
              'reportDate': item.date,
              'focusState': _readinessFocusState(item.date),
              'historicalFocus': _isHistoricalReadinessFocus(item.date),
              'focusSummary': _readinessFocusSummary(item.date),
              'modeLabel': _globalReadinessModeLabel(itemSnapshot, itemIntents),
              'summary': _globalReadinessSummaryForReport(
                snapshot: itemSnapshot,
                intents: itemIntents,
              ),
              'posturalEchoCount': itemEchoCount,
              'topIntentSummary': _globalReadinessTopIntentSummary(itemIntents),
              'hazardSummary': _globalReadinessHazardSummary(itemIntents),
              'shadowBiasSummary': _globalReadinessShadowBiasSummary(
                itemIntents,
              ),
              ...buildReviewCommandPair(
                reportDate: item.date,
                reviewCommandBuilder: (reportDate) =>
                    '/readinessreview $reportDate',
                caseFileCommandBuilder: (reportDate) =>
                    '/readinesscase json $reportDate',
              ),
              'governanceCommand': '/readinessgovernance ${item.date}',
            };
          })
          .toList(growable: false),
    };
  }

  String _globalReadinessCaseFileCsv({String? reportDate}) {
    final payload = _globalReadinessCaseFilePayload(reportDate: reportDate);
    final history = (payload['history'] as List<Object?>?) ?? const [];
    final lines = <String>[
      'metric,value',
      'report_date,${payload['reportDate'] ?? ''}',
      'available,${payload['available'] == false ? 'false' : 'true'}',
      'generated_at_utc,${payload['generatedAtUtc'] ?? ''}',
      'focus_state,${payload['focusState'] ?? ''}',
      'historical_focus,${payload['historicalFocus'] == true ? 'true' : 'false'}',
      'focus_summary,"${(payload['focusSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'live_report_date,${payload['liveReportDate'] ?? ''}',
      'mode_label,"${(payload['modeLabel'] ?? '').toString().replaceAll('"', '""')}"',
      'summary,"${(payload['summary'] ?? '').toString().replaceAll('"', '""')}"',
      'total_sites,${payload['totalSites'] ?? 0}',
      'critical_site_count,${payload['criticalSiteCount'] ?? 0}',
      'elevated_site_count,${payload['elevatedSiteCount'] ?? 0}',
      'intent_count,${payload['intentCount'] ?? 0}',
      'postural_echo_count,${payload['posturalEchoCount'] ?? 0}',
      'postural_echo_summary,"${(payload['posturalEchoSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'top_intent_summary,"${(payload['topIntentSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'hazard_summary,"${(payload['hazardSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'shadow_bias_summary,"${(payload['shadowBiasSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'selected_event_id,${payload['selectedEventId'] ?? ''}',
      'review_refs,"${(((payload['reviewRefs'] as List<Object?>?) ?? const <Object?>[]).join(', ')).replaceAll('"', '""')}"',
      'lead_region_review_refs,"${(((payload['leadRegion'] as Map<Object?, Object?>?)?['reviewRefs'] as List<Object?>?) ?? const <Object?>[]).join(', ').replaceAll('"', '""')}"',
      'lead_site_review_refs,"${(((payload['leadSite'] as Map<Object?, Object?>?)?['reviewRefs'] as List<Object?>?) ?? const <Object?>[]).join(', ').replaceAll('"', '""')}"',
      'review_command,${payload['reviewCommand'] ?? ''}',
      'case_file_command,${payload['caseFileCommand'] ?? ''}',
      'governance_command,${payload['governanceCommand'] ?? ''}',
    ];
    final topIntents = (payload['topIntents'] as List<Object?>?) ?? const [];
    for (var i = 0; i < topIntents.length; i += 1) {
      final row = topIntents[i];
      if (row is! Map) continue;
      lines.add(
        'top_intent_${i + 1},"${(row['actionType'] ?? '').toString().replaceAll('"', '""')} • ${(row['siteId'] ?? '').toString().replaceAll('"', '""')} • ${(row['description'] ?? '').toString().replaceAll('"', '""')}"',
      );
    }
    final echoes = (payload['posturalEchoes'] as List<Object?>?) ?? const [];
    for (var i = 0; i < echoes.length; i += 1) {
      final row = echoes[i];
      if (row is! Map) continue;
      lines.add(
        'postural_echo_${i + 1},"${(row['leadSite'] ?? '').toString().replaceAll('"', '""')} -> ${(row['echoTarget'] ?? '').toString().replaceAll('"', '""')} • ${(row['echoHeat'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'postural_echo_${i + 1}_review_refs,"${(((row['reviewRefs'] as List<Object?>?) ?? const <Object?>[]).join(', ')).replaceAll('"', '""')}"',
      );
    }
    for (var i = 0; i < history.length; i += 1) {
      final row = history[i];
      if (row is! Map) continue;
      lines.add(
        'history_${i + 1},"${(row['summary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add('history_${i + 1}_focus_state,${row['focusState'] ?? ''}');
      lines.add(
        'history_${i + 1}_historical_focus,${row['historicalFocus'] == true ? 'true' : 'false'}',
      );
      lines.add(
        'history_${i + 1}_focus_summary,"${(row['focusSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_postural_echo_count,${row['posturalEchoCount'] ?? 0}',
      );
      lines.add(
        'history_${i + 1}_top_intent_summary,"${(row['topIntentSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_hazard_summary,"${(row['hazardSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_shadow_bias_summary,"${(row['shadowBiasSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.addAll(
        buildHistoryReviewCommandCsvRows(
          row: i + 1,
          reportDate: (row['reportDate'] ?? '').toString(),
          reviewCommandBuilder: (reportDate) => '/readinessreview $reportDate',
          caseFileCommandBuilder: (reportDate) =>
              '/readinesscase json $reportDate',
        ),
      );
      lines.add(
        'history_${i + 1}_governance_command,${row['governanceCommand'] ?? ''}',
      );
    }
    return lines.join('\n');
  }

  Map<String, Object?> _shadowMoCaseFilePayload({String? reportDate}) {
    final report = _morningSovereignReportForDate(reportDate);
    if (report == null) {
      return <String, Object?>{
        'reportDate': (reportDate ?? '').trim(),
        'available': false,
        'message': 'No morning sovereign report is available for that shift.',
      };
    }
    final shadowSites = _shadowMoSitesForReport(report);
    final history =
        _morningSovereignReportHistory
            .where((item) => item.date.trim() != report.date.trim())
            .toList(growable: false)
          ..sort(
            (left, right) =>
                right.generatedAtUtc.compareTo(left.generatedAtUtc),
          );
    final previousReport = history.isEmpty ? null : history.first;
    final currentMatchCount = _shadowMoMatchCountForSites(shadowSites);
    final baseline = history
        .take(3)
        .map(
          (item) => _shadowMoMatchCountForSites(_shadowMoSitesForReport(item)),
        )
        .toList(growable: false);
    final baselineAverage = baseline.isEmpty
        ? null
        : baseline.reduce((left, right) => left + right) / baseline.length;
    final historyHeadline = baselineAverage == null
        ? 'NEW • 1d'
        : currentMatchCount > baselineAverage
        ? 'RISING • ${baseline.length + 1}d'
        : currentMatchCount < baselineAverage
        ? 'EASING • ${baseline.length + 1}d'
        : 'STABLE • ${baseline.length + 1}d';
    final historySummary = baselineAverage == null
        ? 'Current matches $currentMatchCount • Baseline n/a • No prior shadow-MO history is available yet.'
        : 'Current matches $currentMatchCount • Baseline ${baselineAverage.toStringAsFixed(1)} • ${currentMatchCount > baselineAverage
              ? 'Shadow-MO match pressure is increasing against recent shifts.'
              : currentMatchCount < baselineAverage
              ? 'Shadow-MO match pressure eased against recent shifts.'
              : 'Shadow-MO match pressure is holding close to the recent baseline.'}';
    final strengthSummary = shadowMoStrengthSummaryForSites(shadowSites);
    final strengthHistorySummary = buildShadowMoStrengthDriftSummary(
      currentSites: shadowSites,
      historySiteSets: history
          .take(3)
          .map(_shadowMoSitesForReport)
          .toList(growable: false),
    ).summary;
    final tomorrowUrgencySummary = _globalReadinessTomorrowUrgencySummary(
      _globalReadinessIntentsForReport(report),
    );
    final previousTomorrowUrgencySummary = previousReport == null
        ? ''
        : _globalReadinessTomorrowUrgencySummary(
            _globalReadinessIntentsForReport(previousReport),
          );
    final eventIds = shadowSites
        .expand((site) => site.moShadowEventIds)
        .map((value) => value.trim())
        .where((value) => value.isNotEmpty)
        .toSet()
        .toList(growable: false);
    final reviewRefs = shadowSites
        .expand((site) => site.moShadowReviewRefs)
        .map((value) => value.trim())
        .where((value) => value.isNotEmpty)
        .toSet()
        .toList(growable: false);
    final selectedEventId = shadowSites
        .map((site) => site.moShadowSelectedEventId?.trim() ?? '')
        .firstWhere((value) => value.isNotEmpty, orElse: () => '');
    final syntheticPayload = _syntheticWarRoomCaseFilePayload(
      reportDate: report.date,
    );
    final promotionMoId = (syntheticPayload['promotionMoId'] ?? '')
        .toString()
        .trim();
    final promotionAnchorPayload = buildPromotionShadowAnchorPayloadForSites(
      promotionMoId: promotionMoId,
      sites: shadowSites,
      reportDate: report.date,
    );
    return buildShadowMoDossierPayload(
      sites: shadowSites,
      generatedAtUtc: report.generatedAtUtc,
      countKey: 'shadowSiteCount',
      metadata: <String, Object?>{
        'reportDate': report.date,
        'available': true,
        'focusState': _readinessFocusState(report.date),
        'historicalFocus': _isHistoricalReadinessFocus(report.date),
        'focusSummary': _readinessFocusSummary(report.date),
        'liveReportDate': (_morningSovereignReport?.date ?? '').trim(),
        'summary': _shadowMoSummaryForSites(shadowSites),
        'validationSummary': _shadowMoValidationSummaryForSites(shadowSites),
        'strengthSummary': strengthSummary,
        'strengthHistorySummary': strengthHistorySummary,
        'tomorrowUrgencySummary': tomorrowUrgencySummary,
        'previousTomorrowUrgencySummary': previousTomorrowUrgencySummary,
        'historyHeadline': historyHeadline,
        'historySummary': historySummary,
        'eventIds': eventIds,
        'reviewRefs': reviewRefs,
        'selectedEventId': selectedEventId.isEmpty ? null : selectedEventId,
        ...promotionAnchorPayload,
        'reviewCommand': '/shadowreview ${report.date}',
        'caseFileCommand': '/shadowcase json ${report.date}',
        'previousReviewCommand': previousReport == null
            ? ''
            : '/shadowreview ${previousReport.date}',
        'previousCaseFileCommand': previousReport == null
            ? ''
            : '/shadowcase json ${previousReport.date}',
        'reviewShortcuts': buildReviewShortcuts(
          currentReportDate: report.date,
          previousReportDate: previousReport?.date,
          reviewCommandBuilder: (value) => '/shadowreview $value',
          caseFileCommandBuilder: (value) => '/shadowcase json $value',
        ),
        'history': history
            .take(3)
            .map((item) {
              final itemSites = _shadowMoSitesForReport(item);
              return <String, Object?>{
                'reportDate': item.date,
                'shadowSiteCount': itemSites.length,
                'matchCount': _shadowMoMatchCountForSites(itemSites),
                'summary': _shadowMoSummaryForSites(itemSites),
                'validationSummary': _shadowMoValidationSummaryForSites(
                  itemSites,
                ),
                'strengthSummary': shadowMoStrengthSummaryForSites(itemSites),
                'tomorrowUrgencySummary':
                    _globalReadinessTomorrowUrgencySummary(
                      _globalReadinessIntentsForReport(item),
                    ),
                ...buildReviewCommandPair(
                  reportDate: item.date,
                  reviewCommandBuilder: (value) => '/shadowreview $value',
                  caseFileCommandBuilder: (value) => '/shadowcase json $value',
                ),
              };
            })
            .toList(growable: false),
      },
    );
  }

  String _shadowMoCaseFileCsv({String? reportDate}) {
    final payload = _shadowMoCaseFilePayload(reportDate: reportDate);
    final sites = (payload['sites'] as List<Object?>?) ?? const [];
    final history = (payload['history'] as List<Object?>?) ?? const [];
    final lines = <String>[
      'metric,value',
      'report_date,${payload['reportDate'] ?? ''}',
      'available,${payload['available'] == false ? 'false' : 'true'}',
      'generated_at_utc,${payload['generatedAtUtc'] ?? ''}',
      'focus_state,${payload['focusState'] ?? ''}',
      'historical_focus,${payload['historicalFocus'] == true ? 'true' : 'false'}',
      'focus_summary,"${(payload['focusSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'live_report_date,${payload['liveReportDate'] ?? ''}',
      'shadow_site_count,${payload['shadowSiteCount'] ?? 0}',
      'summary,"${(payload['summary'] ?? '').toString().replaceAll('"', '""')}"',
      'validation_summary,"${(payload['validationSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'strength_summary,"${(payload['strengthSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'strength_history_summary,"${(payload['strengthHistorySummary'] ?? '').toString().replaceAll('"', '""')}"',
      'tomorrow_urgency_summary,"${(payload['tomorrowUrgencySummary'] ?? '').toString().replaceAll('"', '""')}"',
      'previous_tomorrow_urgency_summary,"${(payload['previousTomorrowUrgencySummary'] ?? '').toString().replaceAll('"', '""')}"',
      ...buildPromotionShadowAnchorCsvRows(payload: payload),
      'history_headline,"${(payload['historyHeadline'] ?? '').toString().replaceAll('"', '""')}"',
      'history_summary,"${(payload['historySummary'] ?? '').toString().replaceAll('"', '""')}"',
      'selected_event_id,${payload['selectedEventId'] ?? ''}',
      'review_refs,"${(((payload['reviewRefs'] as List<Object?>?) ?? const <Object?>[]).join(', ')).replaceAll('"', '""')}"',
      'review_command,${payload['reviewCommand'] ?? ''}',
      'case_file_command,${payload['caseFileCommand'] ?? ''}',
      'previous_review_command,${payload['previousReviewCommand'] ?? ''}',
      'previous_case_file_command,${payload['previousCaseFileCommand'] ?? ''}',
    ];
    for (var i = 0; i < sites.length; i += 1) {
      final site = sites[i];
      if (site is! Map) continue;
      lines.add('site_${i + 1}_id,${site['siteId'] ?? ''}');
      lines.add(
        'site_${i + 1}_summary,"${(site['summary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add('site_${i + 1}_match_count,${site['matchCount'] ?? 0}');
      lines.add(
        'site_${i + 1}_review_refs,"${(((site['reviewRefs'] as List<Object?>?) ?? const <Object?>[]).join(', ')).replaceAll('"', '""')}"',
      );
      final matches = (site['matches'] as List<Object?>?) ?? const [];
      for (var j = 0; j < matches.length; j += 1) {
        final match = matches[j];
        if (match is! Map) continue;
        lines.add(
          'site_${i + 1}_match_${j + 1},"${(match['title'] ?? '').toString().replaceAll('"', '""')}"',
        );
      }
    }
    for (var i = 0; i < history.length; i += 1) {
      final row = history[i];
      if (row is! Map) continue;
      lines.add('history_${i + 1}_date,${row['reportDate'] ?? ''}');
      lines.add(
        'history_${i + 1}_shadow_site_count,${row['shadowSiteCount'] ?? 0}',
      );
      lines.add('history_${i + 1}_match_count,${row['matchCount'] ?? 0}');
      lines.add(
        'history_${i + 1}_summary,"${(row['summary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_validation_summary,"${(row['validationSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_strength_summary,"${(row['strengthSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_tomorrow_urgency_summary,"${(row['tomorrowUrgencySummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.addAll(
        buildHistoryReviewCommandCsvRows(
          row: i + 1,
          reportDate: (row['reportDate'] ?? '').toString(),
          reviewCommandBuilder: (value) => '/shadowreview $value',
          caseFileCommandBuilder: (value) => '/shadowcase json $value',
        ),
      );
    }
    return lines.join('\n');
  }

  Map<String, Object?> _syntheticWarRoomCaseFilePayload({String? reportDate}) {
    final report = _morningSovereignReportForDate(reportDate);
    if (report == null) {
      return <String, Object?>{
        'reportDate': (reportDate ?? '').trim(),
        'available': false,
        'message': 'No morning sovereign report is available for that shift.',
      };
    }
    final plans = _syntheticWarRoomPlansForReport(report);
    final policyPlans = plans
        .where((plan) => plan.actionType == 'POLICY RECOMMENDATION')
        .toList(growable: false);
    final leadPlan = plans.isEmpty ? null : plans.first;
    final leadPolicyPlan = policyPlans.isEmpty ? null : policyPlans.first;
    final history =
        _morningSovereignReportHistory
            .where((item) => item.date.trim() != report.date.trim())
            .toList(growable: false)
          ..sort(
            (left, right) =>
                right.generatedAtUtc.compareTo(left.generatedAtUtc),
          );
    final baseline = history.take(3).toList(growable: false);
    final baselinePressure = baseline.isEmpty
        ? null
        : baseline
                  .map((item) {
                    final itemPlans = _syntheticWarRoomPlansForReport(item);
                    final itemPolicyCount = itemPlans
                        .where(
                          (plan) => plan.actionType == 'POLICY RECOMMENDATION',
                        )
                        .length;
                    return itemPlans.length + itemPolicyCount;
                  })
                  .reduce((left, right) => left + right) /
              baseline.length;
    final currentPressure = plans.length + policyPlans.length;
    final historyHeadline = baselinePressure == null
        ? 'NEW • ${history.isEmpty ? 1 : history.take(3).length + 1}d'
        : currentPressure >= baselinePressure + 1
        ? 'RISING • ${history.take(3).length + 1}d'
        : currentPressure <= baselinePressure - 1
        ? 'EASING • ${history.take(3).length + 1}d'
        : 'STABLE • ${history.take(3).length + 1}d';
    final historySummary = baselinePressure == null
        ? 'Current pressure $currentPressure • Baseline n/a • No prior synthetic rehearsal history is available yet.'
        : 'Current pressure $currentPressure • Baseline ${baselinePressure.toStringAsFixed(1)} • ${currentPressure >= baselinePressure + 1
              ? 'Synthetic rehearsal is recommending stronger action than recent shifts.'
              : currentPressure <= baselinePressure - 1
              ? 'Synthetic rehearsal pressure eased against recent shifts.'
              : 'Synthetic rehearsal pressure is holding close to the recent baseline.'}';
    final previousReport = history.isEmpty ? null : history.first;
    final learningLabel = _syntheticWarRoomLearningLabel(plans);
    final shadowValidationDrift = buildShadowMoValidationDriftSummary(
      currentSites: _shadowMoSitesForReport(report),
      historySiteSets: baseline
          .map(_shadowMoSitesForReport)
          .toList(growable: false),
    );
    final shadowTomorrowUrgencySummary =
        _syntheticWarRoomShadowTomorrowUrgencySummaryForReport(report);
    final previousShadowTomorrowUrgencySummary = previousReport == null
        ? ''
        : _syntheticWarRoomShadowTomorrowUrgencySummaryForReport(
            previousReport,
          );
    final promotionMoId = _syntheticWarRoomPromotionId(plans);
    final promotionAnchorPayload = buildPromotionShadowAnchorPayloadForSites(
      promotionMoId: promotionMoId,
      sites: _shadowMoSitesForReport(report),
      reportDate: report.date,
    );
    return <String, Object?>{
      'reportDate': report.date,
      'available': true,
      'generatedAtUtc': report.generatedAtUtc.toIso8601String(),
      'focusState': _readinessFocusState(report.date),
      'historicalFocus': _isHistoricalReadinessFocus(report.date),
      'focusSummary': _readinessFocusSummary(report.date),
      'liveReportDate': (_morningSovereignReport?.date ?? '').trim(),
      'modeLabel': _syntheticWarRoomModeLabel(plans),
      'summary': _syntheticWarRoomSummary(plans),
      'policySummary': _syntheticWarRoomPolicySummary(plans),
      'hazardSummary': _syntheticWarRoomHazardSummary(plans),
      'shadowSummary': _syntheticWarRoomShadowSummary(plans),
      'shadowPostureSummary': _shadowMoPostureSummaryForReport(report),
      'shadowValidationSummary': shadowValidationDrift.summary,
      'shadowValidationHeadline': shadowValidationDrift.headline,
      'shadowValidationHistorySummary': shadowValidationDrift.historySummary,
      'shadowTomorrowUrgencySummary': shadowTomorrowUrgencySummary,
      'previousShadowTomorrowUrgencySummary':
          previousShadowTomorrowUrgencySummary,
      'shadowLearningSummary': _syntheticWarRoomShadowLearningSummary(plans),
      'shadowMemorySummary': _syntheticWarRoomShadowMemorySummary(plans),
      'shadowPostureBiasSummary':
          _syntheticWarRoomShadowPostureBiasSummaryForPlan(
            leadPolicyPlan?.id.isEmpty ?? true ? null : leadPolicyPlan,
          ),
      'promotionPressureSummary': _syntheticWarRoomPromotionPressureSummary(
        plans,
        shadowTomorrowUrgencySummary: shadowTomorrowUrgencySummary,
        previousShadowTomorrowUrgencySummary:
            previousShadowTomorrowUrgencySummary,
        shadowPostureBiasSummary:
            _syntheticWarRoomShadowPostureBiasSummaryForPlan(
              leadPolicyPlan?.id.isEmpty ?? true ? null : leadPolicyPlan,
            ),
      ),
      'promotionExecutionSummary': _syntheticWarRoomPromotionExecutionSummary(
        plans,
      ),
      'promotionSummary': _syntheticWarRoomPromotionSummary(
        plans,
        shadowTomorrowUrgencySummary: shadowTomorrowUrgencySummary,
        previousShadowTomorrowUrgencySummary:
            previousShadowTomorrowUrgencySummary,
        shadowPostureBiasSummary:
            _syntheticWarRoomShadowPostureBiasSummaryForPlan(
              leadPolicyPlan?.id.isEmpty ?? true ? null : leadPolicyPlan,
            ),
      ),
      'promotionMoId': promotionMoId,
      'promotionTargetStatus': _syntheticWarRoomPromotionTargetStatus(plans),
      'promotionDecisionStatus': _syntheticWarRoomPromotionDecisionStatus(
        plans,
      ),
      'promotionDecisionSummary': _syntheticWarRoomPromotionDecisionSummary(
        plans,
        shadowTomorrowUrgencySummary: shadowTomorrowUrgencySummary,
        previousShadowTomorrowUrgencySummary:
            previousShadowTomorrowUrgencySummary,
        shadowPostureBiasSummary:
            _syntheticWarRoomShadowPostureBiasSummaryForPlan(
              leadPolicyPlan?.id.isEmpty ?? true ? null : leadPolicyPlan,
            ),
      ),
      ...promotionAnchorPayload,
      'learningLabel': learningLabel,
      'learningSummary': _syntheticWarRoomLearningSummary(plans),
      'learningMemorySummary': _syntheticWarRoomLearningMemorySummary(
        currentLearningLabel: learningLabel,
        history: history,
      ),
      'actionBias': buildSyntheticActionBiasFromPlans(plans: plans),
      'memoryPriorityBoost': buildSyntheticMemoryPriorityBoostFromPlans(
        plans: plans,
      ),
      'memoryCountdownBias': buildSyntheticMemoryCountdownBiasFromPlans(
        plans: plans,
      ),
      'biasSummary': _syntheticWarRoomBiasSummaryForPlan(leadPolicyPlan),
      'planCount': plans.length,
      'policyCount': buildSyntheticPolicyCountFromPlans(plans: plans),
      'leadRegionId': buildSyntheticLeadRegionIdFromPlans(plans: plans),
      'leadSiteId': buildSyntheticLeadSiteIdFromPlans(plans: plans),
      'topIntentSummary': (leadPlan?.metadata['top_intent'] ?? '')
          .toString()
          .trim(),
      'reviewCommand': '/syntheticreview ${report.date}',
      'caseFileCommand': '/syntheticcase json ${report.date}',
      'previousReviewCommand': previousReport == null
          ? ''
          : '/syntheticreview ${previousReport.date}',
      'previousCaseFileCommand': previousReport == null
          ? ''
          : '/syntheticcase json ${previousReport.date}',
      'reviewShortcuts': buildReviewShortcuts(
        currentReportDate: report.date,
        previousReportDate: previousReport?.date,
        reviewCommandBuilder: (reportDate) => '/syntheticreview $reportDate',
        caseFileCommandBuilder: (reportDate) =>
            '/syntheticcase json $reportDate',
      ),
      'historyHeadline': historyHeadline,
      'historySummary': historySummary,
      'plans': plans
          .take(5)
          .map(
            (plan) => <String, Object?>{
              'actionType': plan.actionType,
              'siteId': plan.siteId,
              'priority': plan.priority.name,
              'description': plan.description,
              'countdownSeconds': plan.countdownSeconds,
              'incidentId': plan.incidentId,
              'metadata': plan.metadata,
            },
          )
          .toList(growable: false),
      'history': history
          .take(3)
          .map((item) {
            final itemPlans = _syntheticWarRoomPlansForReport(item);
            final itemPolicyPlan = itemPlans.firstWhere(
              (plan) => plan.actionType == 'POLICY RECOMMENDATION',
              orElse: () => const MonitoringWatchAutonomyActionPlan(
                id: '',
                incidentId: '',
                siteId: '',
                priority: MonitoringWatchAutonomyPriority.medium,
                actionType: '',
                description: '',
                countdownSeconds: 0,
              ),
            );
            final itemShadowTomorrowUrgencySummary =
                _syntheticWarRoomShadowTomorrowUrgencySummaryForReport(item);
            return <String, Object?>{
              'reportDate': item.date,
              'focusState': _readinessFocusState(item.date),
              'historicalFocus': _isHistoricalReadinessFocus(item.date),
              'focusSummary': _readinessFocusSummary(item.date),
              'modeLabel': _syntheticWarRoomModeLabel(itemPlans),
              'summary': _syntheticWarRoomSummary(itemPlans),
              'policySummary': _syntheticWarRoomPolicySummary(itemPlans),
              'hazardSummary': _syntheticWarRoomHazardSummary(itemPlans),
              'shadowSummary': _syntheticWarRoomShadowSummary(itemPlans),
              'shadowPostureSummary': _shadowMoPostureSummaryForReport(item),
              'shadowValidationSummary': _shadowMoValidationSummaryForSites(
                _shadowMoSitesForReport(item),
              ),
              'shadowTomorrowUrgencySummary': itemShadowTomorrowUrgencySummary,
              'shadowLearningSummary': _syntheticWarRoomShadowLearningSummary(
                itemPlans,
              ),
              'shadowMemorySummary': _syntheticWarRoomShadowMemorySummary(
                itemPlans,
              ),
              'shadowPostureBiasSummary':
                  _syntheticWarRoomShadowPostureBiasSummaryForPlan(
                    itemPolicyPlan.id.isEmpty ? null : itemPolicyPlan,
                  ),
              'promotionPressureSummary':
                  _syntheticWarRoomPromotionPressureSummary(
                    itemPlans,
                    shadowTomorrowUrgencySummary:
                        itemShadowTomorrowUrgencySummary,
                    shadowPostureBiasSummary:
                        _syntheticWarRoomShadowPostureBiasSummaryForPlan(
                          itemPolicyPlan.id.isEmpty ? null : itemPolicyPlan,
                        ),
                  ),
              'promotionExecutionSummary':
                  _syntheticWarRoomPromotionExecutionSummary(itemPlans),
              'promotionSummary': _syntheticWarRoomPromotionSummary(
                itemPlans,
                shadowTomorrowUrgencySummary: itemShadowTomorrowUrgencySummary,
                shadowPostureBiasSummary:
                    _syntheticWarRoomShadowPostureBiasSummaryForPlan(
                      itemPolicyPlan.id.isEmpty ? null : itemPolicyPlan,
                    ),
              ),
              'promotionMoId': _syntheticWarRoomPromotionId(itemPlans),
              'promotionTargetStatus': _syntheticWarRoomPromotionTargetStatus(
                itemPlans,
              ),
              'promotionDecisionStatus':
                  _syntheticWarRoomPromotionDecisionStatus(itemPlans),
              'promotionDecisionSummary':
                  _syntheticWarRoomPromotionDecisionSummary(
                    itemPlans,
                    shadowTomorrowUrgencySummary:
                        itemShadowTomorrowUrgencySummary,
                    shadowPostureBiasSummary:
                        _syntheticWarRoomShadowPostureBiasSummaryForPlan(
                          itemPolicyPlan.id.isEmpty ? null : itemPolicyPlan,
                        ),
                  ),
              'learningLabel': _syntheticWarRoomLearningLabel(itemPlans),
              'learningSummary': _syntheticWarRoomLearningSummary(itemPlans),
              'actionBias': buildSyntheticActionBiasFromPlans(plans: itemPlans),
              'memoryPriorityBoost': buildSyntheticMemoryPriorityBoostFromPlans(
                plans: itemPlans,
              ),
              'memoryCountdownBias': buildSyntheticMemoryCountdownBiasFromPlans(
                plans: itemPlans,
              ),
              'biasSummary': _syntheticWarRoomBiasSummaryForPlan(
                itemPolicyPlan.id.isEmpty ? null : itemPolicyPlan,
              ),
              'planCount': itemPlans.length,
              'policyCount': buildSyntheticPolicyCountFromPlans(
                plans: itemPlans,
              ),
              ...buildReviewCommandPair(
                reportDate: item.date,
                reviewCommandBuilder: (reportDate) =>
                    '/syntheticreview $reportDate',
                caseFileCommandBuilder: (reportDate) =>
                    '/syntheticcase json $reportDate',
              ),
            };
          })
          .toList(growable: false),
    };
  }

