      'memory_countdown_bias,${payload['memoryCountdownBias'] ?? ''}',
      'bias_summary,"${(payload['biasSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'plan_count,${payload['planCount'] ?? 0}',
      'policy_count,${payload['policyCount'] ?? 0}',
      'lead_region_id,${payload['leadRegionId'] ?? ''}',
      'lead_site_id,${payload['leadSiteId'] ?? ''}',
      'top_intent_summary,"${(payload['topIntentSummary'] ?? '').toString().replaceAll('"', '""')}"',
      'review_command,${payload['reviewCommand'] ?? ''}',
      'case_file_command,${payload['caseFileCommand'] ?? ''}',
      'previous_review_command,${payload['previousReviewCommand'] ?? ''}',
      'previous_case_file_command,${payload['previousCaseFileCommand'] ?? ''}',
      'history_headline,"${(payload['historyHeadline'] ?? '').toString().replaceAll('"', '""')}"',
      'history_summary,"${(payload['historySummary'] ?? '').toString().replaceAll('"', '""')}"',
    ];
    final plans = (payload['plans'] as List<Object?>?) ?? const [];
    for (var i = 0; i < plans.length; i += 1) {
      final row = plans[i];
      if (row is! Map) continue;
      lines.add(
        'plan_${i + 1},"${(row['actionType'] ?? '').toString().replaceAll('"', '""')} • ${(row['siteId'] ?? '').toString().replaceAll('"', '""')} • ${(row['description'] ?? '').toString().replaceAll('"', '""')}"',
      );
    }
    for (var i = 0; i < history.length; i += 1) {
      final row = history[i];
      if (row is! Map) continue;
      lines.add(
        'history_${i + 1},"${(row['summary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add('history_${i + 1}_focus_state,${row['focusState'] ?? ''}');
      lines.add(
        'history_${i + 1}_historical_focus,${row['historicalFocus'] == true ? 'true' : 'false'}',
      );
      lines.add(
        'history_${i + 1}_focus_summary,"${(row['focusSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_hazard_summary,"${(row['hazardSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_shadow_summary,"${(row['shadowSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_shadow_posture_summary,"${(row['shadowPostureSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_shadow_validation_summary,"${(row['shadowValidationSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_shadow_tomorrow_urgency_summary,"${(row['shadowTomorrowUrgencySummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_shadow_learning_summary,"${(row['shadowLearningSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_shadow_memory_summary,"${(row['shadowMemorySummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_shadow_posture_bias_summary,"${(row['shadowPostureBiasSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_promotion_pressure_summary,"${(row['promotionPressureSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_promotion_summary,"${(row['promotionSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_promotion_mo_id,${row['promotionMoId'] ?? ''}',
      );
      lines.add(
        'history_${i + 1}_promotion_target_status,${row['promotionTargetStatus'] ?? ''}',
      );
      lines.add(
        'history_${i + 1}_promotion_decision_status,${row['promotionDecisionStatus'] ?? ''}',
      );
      lines.add(
        'history_${i + 1}_promotion_decision_summary,"${(row['promotionDecisionSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_learning_label,${row['learningLabel'] ?? ''}',
      );
      lines.add(
        'history_${i + 1}_learning_summary,"${(row['learningSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_action_bias,"${(row['actionBias'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add(
        'history_${i + 1}_memory_priority_boost,${row['memoryPriorityBoost'] ?? ''}',
      );
      lines.add(
        'history_${i + 1}_memory_countdown_bias,${row['memoryCountdownBias'] ?? ''}',
      );
      lines.add(
        'history_${i + 1}_bias_summary,"${(row['biasSummary'] ?? '').toString().replaceAll('"', '""')}"',
      );
      lines.add('history_${i + 1}_plan_count,${row['planCount'] ?? 0}');
      lines.add('history_${i + 1}_policy_count,${row['policyCount'] ?? 0}');
      lines.addAll(
        buildHistoryReviewCommandCsvRows(
          row: i + 1,
          reportDate: (row['reportDate'] ?? '').toString(),
          reviewCommandBuilder: (reportDate) => '/syntheticreview $reportDate',
          caseFileCommandBuilder: (reportDate) =>
              '/syntheticcase json $reportDate',
        ),
      );
    }
    return lines.join('\n');
  }

