    } catch (error) {
      if (updateStatus && mounted) {
        setState(() {
          _lastIntakeStatus = 'Wearable ingest failed: $error';
        });
      }
      return _recordOpsIntegrationHealth(
        _OpsIntegrationIngestResult(
          source: 'wearable',
          success: false,
          detail: error.toString(),
        ),
      );
    }
