  Future<void> _ensureTelegramPollingPrimaryTab() async {
    if (!_telegramInboundRouterEnabled ||
        _telegramAdminPollTimer != null ||
        _telegramPollingLockAcquisitionInFlight) {
      return;
    }
    _telegramPollingLockAcquisitionInFlight = true;
    try {
      final isPrimary = await _telegramPollingTabLock.ensurePrimary();
      _telegramPollingPrimaryTab = isPrimary;
      if (!_telegramInboundRouterEnabled || _telegramAdminPollTimer != null) {
        return;
      }
      if (!isPrimary) {
        debugPrint(
          'ONYX Telegram admin loop skipped in secondary browser tab.',
        );
        return;
      }
    } finally {
      _telegramPollingLockAcquisitionInFlight = false;
    }
    debugPrint(
      'ONYX Telegram admin loop start: '
      'router=${_telegramInboundRouterEnabled ? 'on' : 'off'} '
      'admin=${_telegramAdminControlEnabled ? 'on' : 'off'} '
      'ai=${_telegramAiAssistantEnabled ? 'on' : 'off'} '
      'chat=${_resolvedTelegramAdminChatId().isEmpty ? 'unset' : _resolvedTelegramAdminChatId()} '
      'tab=${_telegramPollingPrimaryTab ? 'primary' : 'secondary'} '
      'bridge=${_telegramBridge.isConfigured ? 'configured' : 'disabled'}',
    );
    unawaited(_registerTelegramBotCommandsIfNeeded());
    _scheduleNextTelegramAdminPoll(1);
    _startSiteAwarenessAlertLoop();
  }

  Future<void> _registerTelegramBotCommandsIfNeeded() async {
    if (_telegramBotCommandsRegistered ||
        !_telegramPollingPrimaryTab ||
        !_telegramBridge.isConfigured) {
      return;
    }
    final inFlight = _telegramBotCommandsRegistrationFuture;
    if (inFlight != null) {
      await inFlight;
      return;
    }
    final future = () async {
      try {
        final registered = await _telegramBridge.setMyCommands(
          commands: _telegramPrimaryBotCommands,
        );
        if (registered) {
          _telegramBotCommandsRegistered = true;
          developer.log(
            'Telegram command menu registered for primary ONYX bot.',
            name: 'TelegramBridge',
          );
          return;
        }
        developer.log(
          'Telegram command menu registration was not accepted by Telegram.',
          name: 'TelegramBridge',
          level: 900,
        );
      } catch (error, stackTrace) {
        developer.log(
          'Telegram command menu registration failed.',
          name: 'TelegramBridge',
          error: error,
          stackTrace: stackTrace,
          level: 1000,
        );
      }
    }();
    _telegramBotCommandsRegistrationFuture = future;
    try {
      await future;
    } finally {
      if (identical(_telegramBotCommandsRegistrationFuture, future)) {
        _telegramBotCommandsRegistrationFuture = null;
      }
    }
  }

  Future<void> _ensureTelegramPrimaryTabForSiteAwarenessAlerts() async {
    if (!_siteAwarenessAlertWatcherEnabled ||
        _telegramPollingLockAcquisitionInFlight) {
      return;
    }
    _telegramPollingLockAcquisitionInFlight = true;
    try {
      final isPrimary = await _telegramPollingTabLock.ensurePrimary();
      _telegramPollingPrimaryTab = isPrimary;
      if (!isPrimary) {
        return;
      }
    } finally {
      _telegramPollingLockAcquisitionInFlight = false;
    }
    if (_telegramInboundRouterEnabled && _telegramAdminPollTimer == null) {
      _scheduleNextTelegramAdminPoll(1);
    }
    _siteAwarenessAlertBootCutoffUtc ??= DateTime.now().toUtc();
    _scheduleNextSiteAwarenessAlertPoll(1);
  }

  Future<void> _ensureTelegramPrimaryTabForPatrolMonitor() async {
    if (!_patrolMonitorEnabled || _telegramPollingLockAcquisitionInFlight) {
      return;
    }
    _telegramPollingLockAcquisitionInFlight = true;
    try {
      final isPrimary = await _telegramPollingTabLock.ensurePrimary();
      _telegramPollingPrimaryTab = isPrimary;
      if (!isPrimary) {
        return;
      }
    } finally {
      _telegramPollingLockAcquisitionInFlight = false;
    }
    if (_telegramInboundRouterEnabled && _telegramAdminPollTimer == null) {
      _scheduleNextTelegramAdminPoll(1);
    }
    _startSiteAwarenessAlertLoop();
    _scheduleNextPatrolMonitorPoll(5);
    _scheduleNextOperatorDisciplinePoll(5);
    _scheduleNextClientTrustSnapshotPoll(5 * 60);
  }

  Future<void> _ensureTelegramPrimaryTabForBehaviourMonitor() async {
    if (!_behaviourMonitorEnabled || _telegramPollingLockAcquisitionInFlight) {
      return;
    }
    _telegramPollingLockAcquisitionInFlight = true;
    try {
      final isPrimary = await _telegramPollingTabLock.ensurePrimary();
      _telegramPollingPrimaryTab = isPrimary;
      if (!isPrimary) {
        return;
      }
    } finally {
      _telegramPollingLockAcquisitionInFlight = false;
    }
    if (_telegramInboundRouterEnabled && _telegramAdminPollTimer == null) {
      _scheduleNextTelegramAdminPoll(1);
    }
    _startSiteAwarenessAlertLoop();
    _scheduleNextBehaviourMonitorPoll(5);
    _scheduleNextOperatorDisciplinePoll(5);
    _scheduleNextClientTrustSnapshotPoll(5 * 60);
  }

  void _scheduleNextSiteAwarenessAlertPoll(int delaySeconds) {
    _siteAwarenessAlertPollTimer?.cancel();
    if (!_siteAwarenessAlertWatcherEnabled || !_telegramPollingPrimaryTab) {
      _siteAwarenessAlertPollTimer = null;
      return;
    }
    _siteAwarenessAlertPollTimer = Timer(Duration(seconds: delaySeconds), () {
      unawaited(_pollSiteAwarenessAlertsOnce());
    });
  }

  void _scheduleNextPatrolMonitorPoll(int delaySeconds) {
    _patrolMonitorTimer?.cancel();
    if (!_patrolMonitorEnabled || !_telegramPollingPrimaryTab) {
      _patrolMonitorTimer = null;
      return;
    }
    _patrolMonitorTimer = Timer(Duration(seconds: delaySeconds), () {
      unawaited(_pollPatrolMonitorOnce());
    });
  }

  void _scheduleNextBehaviourMonitorPoll(int delaySeconds) {
    _behaviourMonitorTimer?.cancel();
    if (!_behaviourMonitorEnabled || !_telegramPollingPrimaryTab) {
      _behaviourMonitorTimer = null;
      return;
    }
    _behaviourMonitorTimer = Timer(Duration(seconds: delaySeconds), () {
      unawaited(_pollBehaviourMonitorOnce());
    });
  }

  void _scheduleNextOperatorDisciplinePoll(int delaySeconds) {
    _operatorDisciplineTimer?.cancel();
    if (!_operatorDisciplineEnabled || !_telegramPollingPrimaryTab) {
      _operatorDisciplineTimer = null;
      return;
    }
    _operatorDisciplineTimer = Timer(Duration(seconds: delaySeconds), () {
      unawaited(_pollOperatorDisciplineOnce());
    });
  }

  void _scheduleNextClientTrustSnapshotPoll(int delaySeconds) {
    _clientTrustSnapshotTimer?.cancel();
    if (!_clientTrustSnapshotEnabled || !_telegramPollingPrimaryTab) {
      _clientTrustSnapshotTimer = null;
      return;
    }
    _clientTrustSnapshotTimer = Timer(Duration(seconds: delaySeconds), () {
      unawaited(_pollClientTrustSnapshotOnce());
    });
  }

  void _pruneSiteAwarenessAlertDeduplicationState(DateTime nowUtc) {
    _siteAwarenessLastDeliveredAlertAtByCameraType.removeWhere(
      (_, sentAtUtc) =>
          nowUtc.toUtc().difference(sentAtUtc.toUtc()) >
          const Duration(minutes: 10),
    );
  }

  String _siteAwarenessAlertDeliveryDeduplicationKey(
    _SiteAwarenessActiveAlertRecord alert,
  ) {
    final siteId = alert.siteId.trim().isEmpty
        ? _selectedSite.trim()
        : alert.siteId.trim();
    return '$siteId|${alert.deliveryDeduplicationKey}';
  }

  bool _shouldSkipSiteAwarenessAlertDelivery(
    _SiteAwarenessActiveAlertRecord alert,
  ) {
    final lastDeliveredAtUtc =
        _siteAwarenessLastDeliveredAlertAtByCameraType[_siteAwarenessAlertDeliveryDeduplicationKey(
          alert,
        )];
    if (lastDeliveredAtUtc == null) {
      return false;
    }
    return alert.detectedAt
            .toUtc()
            .difference(lastDeliveredAtUtc.toUtc())
            .abs() <
        const Duration(seconds: 60);
  }

  OnyxAwarenessLatencyService? get _awarenessLatencyServiceOrNull {
    if (!widget.supabaseReady) {
      return null;
    }
    return OnyxAwarenessLatencyService(client: Supabase.instance.client);
  }

  OnyxEnvironmentEngine? get _environmentEngineOrNull {
    final outcomeService = _outcomeFeedbackServiceOrNull;
    final latencyService = _awarenessLatencyServiceOrNull;
    if (outcomeService == null || latencyService == null) {
      return null;
    }
    return OnyxEnvironmentEngine(
      powerModeService: _powerModeService,
      outcomeFeedbackService: outcomeService,
      awarenessLatencyService: latencyService,
    );
  }

  Future<void> _recordSiteAwarenessLatency({
    required _SiteAwarenessActiveAlertRecord alert,
    required DateTime telegramAtUtc,
  }) async {
    final latency = alert.latency;
    if (latency == null || latency.isEmpty) {
      return;
    }
    final dvrEventAt = DateTime.tryParse(
      (latency['dvr_event_at'] ?? '').toString(),
    )?.toUtc();
    if (dvrEventAt == null) {
      return;
    }
    final service = _awarenessLatencyServiceOrNull;
    if (service == null) {
      return;
    }
    final record = OnyxLatencyRecord.fromJsonMap(<String, Object?>{
      ...latency,
      'alert_id': alert.alertId,
      'site_id': alert.siteId.trim().isEmpty ? _selectedSite : alert.siteId,
      'client_id': alert.clientId.trim().isEmpty
          ? _selectedClient
          : alert.clientId,
      'telegram_at': telegramAtUtc.toUtc().toIso8601String(),
      'total_ms': telegramAtUtc.toUtc().difference(dvrEventAt).inMilliseconds,
    });
    try {
      await service.recordLatency(record);
    } catch (error, stackTrace) {
      developer.log(
        'Failed to persist ONYX awareness latency for ${alert.alertId}.',
        name: 'OnyxAwarenessLatency',
        error: error,
        stackTrace: stackTrace,
        level: 1000,
      );
    }
  }

  Future<void> _pollSiteAwarenessAlertsOnce() async {
    if (!_siteAwarenessAlertWatcherEnabled ||
        !_telegramPollingPrimaryTab ||
        _siteAwarenessAlertPollInFlight) {
      return;
    }
    _siteAwarenessAlertPollInFlight = true;
    try {
      final nowUtc = DateTime.now().toUtc();
      _pruneSiteAwarenessAlertDeduplicationState(nowUtc);
      final siteProfile = await _siteProfileService.loadProfile(_selectedSite);
      final row = await _readLatestSiteAwarenessSnapshotRow(
        siteId: _selectedSite,
      );
      if (row != null && _isSiteAwarenessSnapshotFresh(row, nowUtc)) {
        _siteAwarenessAlertBootCutoffUtc ??= nowUtc;
        final activeAlerts = _siteAwarenessActiveAlertsFromRow(row);
        for (final alert in activeAlerts.reversed) {
          final alertId = alert.alertId.trim();
          if (alertId.isEmpty ||
              alert.isAcknowledged ||
              alert.message.trim().isEmpty) {
            if (alertId.isNotEmpty) {
              _siteAwarenessDeliveredAlertIds.add(alertId);
            }
            continue;
          }
          final bootCutoffUtc = _siteAwarenessAlertBootCutoffUtc;
          if (bootCutoffUtc != null &&
              alert.detectedAt.isBefore(bootCutoffUtc)) {
            _siteAwarenessDeliveredAlertIds.add(alertId);
            continue;
          }
          if (_siteAwarenessDeliveredAlertIds.contains(alertId)) {
            continue;
          }
          if (_shouldSkipSiteAwarenessAlertDelivery(alert)) {
            _siteAwarenessDeliveredAlertIds.add(alertId);
            continue;
          }
          final deliveryDeduplicationKey =
              _siteAwarenessAlertDeliveryDeduplicationKey(alert);
          final presentation = await _buildTelegramProactiveAlertPresentation(
            alert: alert,
            siteProfile: siteProfile,
            nowUtc: nowUtc,
          );
          final alertClientId = alert.clientId.trim().isEmpty
              ? _selectedClient
              : alert.clientId.trim();
          final alertSiteId = alert.siteId.trim().isEmpty
              ? _selectedSite
              : alert.siteId.trim();
          final dispatch = await _telegramPushCoordinator
              .sendProactiveSiteAlert(
                clientId: alertClientId,
                siteId: alertSiteId,
                alertId: alertId,
                text: presentation.markdownText,
                replyMarkup: presentation.replyMarkup,
                parseMode: 'Markdown',
                photoBytes: presentation.photoBytes,
                photoFilename: presentation.photoFilename,
              );
          if (!mounted) {
            continue;
          }
          setState(() {
            _telegramBridgeHealthLabel = dispatch.healthLabel;
            _telegramBridgeHealthDetail = dispatch.healthDetail;
            _telegramBridgeHealthUpdatedAtUtc = _telegramFlowNowUtc();
          });
          if (dispatch.attemptStatus != 'telegram-ok') {
            continue;
          }
          final telegramAtUtc = DateTime.now().toUtc();
          _siteAwarenessLastDeliveredAlertAtByCameraType[deliveryDeduplicationKey] =
              alert.detectedAt.toUtc();
          _siteAwarenessDeliveredAlertIds.add(alertId);
          unawaited(
            _recordSiteAwarenessLatency(
              alert: alert,
              telegramAtUtc: telegramAtUtc,
            ),
          );
          final autoResponseText = await _maybeAutoRespondToProactiveAlert(
            alert: alert,
            siteProfile: siteProfile,
            presentation: presentation,
            nowUtc: nowUtc,
          );
          if (autoResponseText != null && autoResponseText.trim().isNotEmpty) {
            await _telegramPushCoordinator.sendScopedAlert(
              clientId: _selectedClient,
              siteId: _selectedSite,
              messageKeyPrefix: 'tg-site-awareness-auto-$alertId',
              text: autoResponseText,
            );
          }
          await _appendTelegramConversationMessage(
            clientId: alertClientId,
            siteId: alertSiteId,
            author: 'ONYX Watch',
            body: presentation.plainText,
            occurredAtUtc: alert.detectedAt,
            roomKey: 'Residents',
            viewerRole: ClientAppViewerRole.client.name,
            incidentStatusLabel: 'Proactive Alert',
            messageSource: 'telegram',
            messageProvider: 'site_awareness',
          );
        }
      }
      await _pollVehiclePresenceNotifications(nowUtc: nowUtc);
    } finally {
      _siteAwarenessAlertPollInFlight = false;
      _scheduleNextSiteAwarenessAlertPoll(5);
    }
  }

  Future<void> _pollVehiclePresenceNotifications({
    required DateTime nowUtc,
  }) async {
    if (!_siteAwarenessAlertWatcherEnabled) {
      return;
    }
    _vehiclePresenceBootCutoffUtc ??= nowUtc;
    _pruneVehiclePresenceNotificationState(nowUtc);
    final registryRows = await _readSiteVehicleRegistryRows(
      siteId: _selectedSite,
    );
    if (registryRows.isEmpty) {
      return;
    }
    final siteProfile = await _siteProfileService.loadProfile(_selectedSite);
    final recentPresenceRows = await _readSiteVehiclePresenceRows(
      siteId: _selectedSite,
      sinceUtc: nowUtc.subtract(const Duration(hours: 6)),
    );
    for (final row in recentPresenceRows.reversed) {
      final record = _SiteVehiclePresenceRecord.fromRow(row);
      if (record.eventType != 'arrived' || record.id.isEmpty) {
        continue;
      }
      final bootCutoffUtc = _vehiclePresenceBootCutoffUtc;
      if (bootCutoffUtc != null &&
          record.occurredAtUtc.isBefore(bootCutoffUtc)) {
        _vehiclePresenceDeliveredArrivalIds.add(record.id);
        continue;
      }
      if (_vehiclePresenceDeliveredArrivalIds.contains(record.id)) {
        continue;
      }
      final zoneLabel = record.zoneName?.trim().isNotEmpty == true
          ? record.zoneName!.trim()
          : 'site';
      final isUnknownOwner =
          record.ownerName.trim().isEmpty ||
          record.ownerName.trim().toLowerCase() == 'unknown';
      if (isUnknownOwner &&
          !_siteProfileService.isAfterHours(
            profile: siteProfile,
            observedAtUtc: record.occurredAtUtc,
          )) {
        _vehiclePresenceDeliveredArrivalIds.add(record.id);
        continue;
      }
      final registry = registryRows
          .map(_SiteVehicleRegistryRecord.fromRow)
          .firstWhere(
            (entry) => entry.plateNumber == record.plateNumber,
            orElse: () => _SiteVehicleRegistryRecord(
              siteId: _selectedSite,
              plateNumber: record.plateNumber,
              vehicleDescription: record.plateNumber,
              ownerName: record.ownerName,
              ownerRole: 'vehicle',
            ),
          );
      final text = isUnknownOwner
          ? '🚗 Unknown vehicle detected at $zoneLabel '
                '(${_telegramCommandLocalTimeLabel(record.occurredAtUtc)})'
                '${record.plateNumber.isEmpty || record.plateNumber == 'UNKNOWN' ? '' : ' — plate: ${record.plateNumber}'}'
          : '🚗 ${_vehiclePresenceOwnerLabel(registry)} arrived home — '
                '${_vehiclePresenceVehicleLabel(registry)} detected at '
                '$zoneLabel (${_telegramCommandLocalTimeLabel(record.occurredAtUtc)})';
      final dispatch = await _telegramPushCoordinator.sendScopedAlert(
        clientId: _selectedClient,
        siteId: _selectedSite,
        messageKeyPrefix: 'tg-vehicle-arrival-${record.id}',
        text: text,
      );
      if (dispatch.attemptStatus != 'telegram-ok') {
        continue;
      }
      _vehiclePresenceDeliveredArrivalIds.add(record.id);
      await _appendTelegramConversationMessage(
        clientId: _selectedClient,
        siteId: _selectedSite,
        author: 'ONYX Watch',
        body: text,
        occurredAtUtc: record.occurredAtUtc,
        roomKey: 'Residents',
        viewerRole: ClientAppViewerRole.client.name,
        incidentStatusLabel: 'Vehicle Arrival',
        messageSource: 'telegram',
        messageProvider: 'vehicle_presence',
      );
    }

    final todayLocal = _telegramFlowNowLocal();
    final todayPresenceRows = await _readSiteVehiclePresenceRows(
      siteId: _selectedSite,
      sinceUtc: DateTime(
        todayLocal.year,
        todayLocal.month,
        todayLocal.day,
      ).toUtc(),
    );
    final statuses = _buildVehiclePresenceStatuses(
      registryRows: registryRows,
      presenceRows: todayPresenceRows,
      nowUtc: nowUtc,
    );
    for (final status in statuses) {
      final latest = status.latestPresence;
      if (latest == null || status.isHome) {
        continue;
      }
      if (nowUtc.difference(latest.occurredAtUtc) <= const Duration(hours: 2)) {
        continue;
      }
      final bootCutoffUtc = _vehiclePresenceBootCutoffUtc;
      if (bootCutoffUtc != null &&
          latest.occurredAtUtc.isBefore(bootCutoffUtc)) {
        continue;
      }
      final lastAlertAt =
          _vehiclePresenceDepartureAlertedAtByPlate[status
              .registry
              .plateNumber];
      if (lastAlertAt != null && !lastAlertAt.isBefore(latest.occurredAtUtc)) {
        continue;
      }
      final text =
          '${_vehiclePresenceOwnerLabel(status.registry)} may have left — '
          '${_vehiclePresenceVehicleLabel(status.registry)} not detected since '
          '${_telegramCommandLocalTimeLabel(latest.occurredAtUtc)}';
      final dispatch = await _telegramPushCoordinator.sendScopedAlert(
        clientId: _selectedClient,
        siteId: _selectedSite,
        messageKeyPrefix:
            'tg-vehicle-departure-${status.registry.plateNumber}-${latest.occurredAtUtc.microsecondsSinceEpoch}',
        text: text,
      );
      if (dispatch.attemptStatus != 'telegram-ok') {
        continue;
      }
      _vehiclePresenceDepartureAlertedAtByPlate[status.registry.plateNumber] =
          nowUtc;
      await _appendTelegramConversationMessage(
        clientId: _selectedClient,
        siteId: _selectedSite,
        author: 'ONYX Watch',
        body: text,
        occurredAtUtc: nowUtc,
        roomKey: 'Residents',
        viewerRole: ClientAppViewerRole.client.name,
        incidentStatusLabel: 'Vehicle Departure',
        messageSource: 'telegram',
        messageProvider: 'vehicle_presence',
      );
    }
  }

  Future<_TelegramProactiveAlertPresentation>
  _buildTelegramProactiveAlertPresentation({
    required _SiteAwarenessActiveAlertRecord alert,
    required SiteIntelligenceProfile siteProfile,
    required DateTime nowUtc,
  }) async {
    final alertKind = _telegramProactiveAlertKindFor(
      alert: alert,
      siteProfile: siteProfile,
    );
    final cameraLabel = _telegramAlertCameraLabel(alert);
    final localDetectedAt = _telegramSiteProfileLocalTime(
      siteProfile.timezone,
      alert.detectedAt,
    );
    final timeLabel =
        '${localDetectedAt.hour.toString().padLeft(2, '0')}:${localDetectedAt.minute.toString().padLeft(2, '0')}';
    final activeMinutes = math.max(
      1,
      nowUtc.difference(alert.detectedAt.toUtc()).inMinutes,
    );
    final subjectLabel = _telegramAlertSubjectLabel(alert);
    final zoneTypeLabel = _telegramAlertZoneTypeLabel(alert);
    final timeContextLabel = _telegramAlertTimeContextLabel(
      alert: alert,
      siteProfile: siteProfile,
    );
    final alertTypeLabel = _telegramAlertTypeLabel(alertKind);
    final reasonBullets = _telegramAlertReasonBullets(alert);
    final markdownText = <String>[
      '⚠️ *${_telegramMarkdownEscape(alertTypeLabel)}* — ${_telegramMarkdownEscape(cameraLabel)}',
      '🕐 $timeLabel — Active $activeMinutes ${activeMinutes == 1 ? 'minute' : 'minutes'}',
      '👤 Detection: ${_telegramMarkdownEscape(subjectLabel)}',
      '📍 ${_telegramMarkdownEscape(zoneTypeLabel)} — ${_telegramMarkdownEscape(timeContextLabel)}',
      if (reasonBullets.isNotEmpty) '📋 *Why this alert fired:*',
      ...reasonBullets.map((bullet) => '• ${_telegramMarkdownEscape(bullet)}'),
    ].join('\n');
    final plainText = <String>[
      '⚠️ $alertTypeLabel — $cameraLabel',
      '🕐 $timeLabel — Active $activeMinutes ${activeMinutes == 1 ? 'minute' : 'minutes'}',
      '👤 Detection: $subjectLabel',
      '📍 $zoneTypeLabel — $timeContextLabel',
      if (reasonBullets.isNotEmpty) '📋 Why this alert fired:',
      ...reasonBullets.map((bullet) => '• $bullet'),
    ].join('\n');
    final replyMarkup = _telegramInlineKeyboardForProactiveAlert(alert: alert);
    List<int>? photoBytes;
    if (siteProfile.alertWithSnapshot) {
      photoBytes = await _fetchProactiveAlertSnapshotBytes(
        alert.channelId,
      ).timeout(const Duration(seconds: 2), onTimeout: () => null);
    }
    return _TelegramProactiveAlertPresentation(
      markdownText: markdownText,
      plainText: plainText,
      replyMarkup: replyMarkup,
      photoBytes: photoBytes,
      photoFilename: photoBytes == null || photoBytes.isEmpty
          ? null
          : 'onyx-alert-ch${alert.channelId.trim().isEmpty ? '0' : alert.channelId.trim()}.jpg',
      alertKind: alertKind,
    );
  }

  Future<List<int>?> _fetchProactiveAlertSnapshotBytes(String channelId) async {
    final normalizedChannelId = channelId.trim();
    if (normalizedChannelId.isEmpty) {
      return null;
    }
    const base = String.fromEnvironment(
      'ONYX_RTSP_FRAME_SERVER_BASE_URL',
      defaultValue: 'http://127.0.0.1:11638',
    );
    final baseUri = Uri.tryParse(base);
    if (baseUri == null) {
      return null;
    }
    final frameUri = baseUri.replace(
      path:
          '${baseUri.path.endsWith('/') ? baseUri.path.substring(0, baseUri.path.length - 1) : baseUri.path}/frame/$normalizedChannelId',
    );
    return _fetchTelegramSnapshotBytes(frameUri);
  }

  Future<String?> _maybeAutoRespondToProactiveAlert({
    required _SiteAwarenessActiveAlertRecord alert,
    required SiteIntelligenceProfile siteProfile,
    required _TelegramProactiveAlertPresentation presentation,
    required DateTime nowUtc,
  }) async {
    final mode = siteProfile.responseMode.trim().toLowerCase();
    if (presentation.alertKind != _TelegramProactiveAlertKind.perimeterBreach) {
      return null;
    }
    if (mode == 'proactive') {
      final cameraLabel = _telegramAlertCameraLabel(alert);
      await _recordTelegramAlertActionEvent(
        siteId: _selectedSite,
        channelId: alert.channelId,
        zoneName: alert.zoneName,
        eventType: 'voice_warning_requested',
        occurredAtUtc: nowUtc,
        rawPayload: <String, Object?>{
          'source': 'site_intelligence_profile',
          'response_mode': mode,
          'alert_id': alert.alertId,
          'camera_name': cameraLabel,
        },
      );
      return '🔊 Proactive voice warning requested automatically on $cameraLabel.';
    }
    if (mode == 'tactical') {
      final incidentId = _telegramInlineIncidentId(nowUtc);
      await _recordTelegramAlertActionEvent(
        siteId: _selectedSite,
        channelId: alert.channelId,
        zoneName: alert.zoneName,
        eventType: 'armed_response_requested',
        occurredAtUtc: nowUtc,
        rawPayload: <String, Object?>{
          'source': 'site_intelligence_profile',
          'response_mode': mode,
          'alert_id': alert.alertId,
          'incident_id': incidentId,
        },
      );
      return '📞 Tactical profile auto-notified armed response. Incident #$incidentId logged.';
    }
    return null;
  }

  Future<void> _recordTelegramAlertActionEvent({
    required String siteId,
    required String channelId,
    required String? zoneName,
    required String eventType,
    required DateTime occurredAtUtc,
    required Map<String, Object?> rawPayload,
  }) async {
    if (!widget.supabaseReady) {
      return;
    }
    try {
      await Supabase.instance.client
          .from('site_alarm_events')
          .insert(<String, Object?>{
            'site_id': siteId.trim(),
            'device_id': channelId.trim().isEmpty
                ? 'telegram-inline'
                : 'camera-ch${channelId.trim()}',
            'event_type': eventType,
            'zone_name': (zoneName ?? '').trim().isEmpty
                ? null
                : zoneName!.trim(),
            'occurred_at': occurredAtUtc.toUtc().toIso8601String(),
            'raw_payload': rawPayload,
          });
    } catch (_) {}
  }

  _TelegramProactiveAlertKind _telegramProactiveAlertKindFor({
    required _SiteAwarenessActiveAlertRecord alert,
    required SiteIntelligenceProfile siteProfile,
  }) {
    final normalizedStoredKind = (alert.alertKind ?? '').trim().toLowerCase();
    if (normalizedStoredKind == 'perimeterbreach' ||
        normalizedStoredKind == 'perimeter_breach') {
      return _TelegramProactiveAlertKind.perimeterBreach;
    }
    if (normalizedStoredKind == 'unknownvehicleatgate' ||
        normalizedStoredKind == 'unknown_vehicle_at_gate') {
      return _TelegramProactiveAlertKind.unknownVehicleAtGate;
    }
    if (normalizedStoredKind == 'loitering') {
      return _TelegramProactiveAlertKind.loitering;
    }
    final isAfterHours = _siteProfileService.isAfterHours(
      profile: siteProfile,
      observedAtUtc: alert.detectedAt,
    );
    final zoneName = (alert.zoneName ?? '').trim().toLowerCase();
    if (alert.isLoitering) {
      return _TelegramProactiveAlertKind.loitering;
    }
    if (alert.eventType.trim().toLowerCase().contains('vehicle')) {
      if (zoneName.contains('gate')) {
        return _TelegramProactiveAlertKind.unknownVehicleAtGate;
      }
    }
    if (_telegramAlertZoneTypeLabel(alert).toLowerCase() == 'perimeter' &&
        isAfterHours) {
      return _TelegramProactiveAlertKind.perimeterBreach;
    }
    return _TelegramProactiveAlertKind.generalMovement;
  }

  String _telegramAlertCameraLabel(_SiteAwarenessActiveAlertRecord alert) {
    final zoneName = (alert.zoneName ?? '').trim();
    if (zoneName.isNotEmpty) {
      return zoneName;
    }
    final channelId = alert.channelId.trim();
    return channelId.isEmpty ? 'Unknown Camera' : 'Channel $channelId';
  }

  String _telegramAlertTypeLabel(_TelegramProactiveAlertKind kind) {
    return switch (kind) {
      _TelegramProactiveAlertKind.perimeterBreach => 'Perimeter Breach',
      _TelegramProactiveAlertKind.unknownVehicleAtGate => 'Unknown Vehicle',
      _TelegramProactiveAlertKind.loitering => 'Loitering',
      _TelegramProactiveAlertKind.generalMovement => 'Movement Alert',
    };
  }

  String _telegramAlertSubjectLabel(_SiteAwarenessActiveAlertRecord alert) {
    final stored = (alert.subjectLabel ?? '').trim();
    final normalizedStored = stored.toLowerCase();
    if (normalizedStored.contains('vehicle') ||
        normalizedStored.contains('car') ||
        normalizedStored.contains('truck')) {
      return 'vehicle';
    }
    if (normalizedStored.contains('animal') ||
        normalizedStored.contains('dog') ||
        normalizedStored.contains('cat') ||
        normalizedStored.contains('bird')) {
      return 'animal';
    }
    if (normalizedStored.contains('unknown') ||
        normalizedStored.contains('unclassified') ||
        normalizedStored.contains('unidentified')) {
      return 'unclassified';
    }
    if (normalizedStored.contains('person') ||
        normalizedStored.contains('human') ||
        normalizedStored.contains('intruder') ||
        normalizedStored.contains('face')) {
      return 'human';
    }
    final normalizedEventType = alert.eventType.trim().toLowerCase();
    if (normalizedEventType.contains('vehicle')) {
      return 'vehicle';
    }
    if (normalizedEventType.contains('animal')) {
      return 'animal';
    }
    return 'human';
  }

  String _telegramAlertZoneTypeLabel(_SiteAwarenessActiveAlertRecord alert) {
    final normalized = (alert.zoneType ?? '').trim().toLowerCase();
    if (normalized == 'perimeter') {
      return 'Perimeter';
    }
    if (normalized == 'indoor') {
      return 'Indoor';
    }
    if (normalized == 'semi_perimeter' || normalized == 'semi-perimeter') {
      return 'Semi-perimeter';
    }
    return 'Camera zone';
  }

  String _telegramAlertTimeContextLabel({
    required _SiteAwarenessActiveAlertRecord alert,
    required SiteIntelligenceProfile siteProfile,
  }) {
    final stored = (alert.timeContext ?? '').trim().toLowerCase();
    if (stored == 'after_hours' || stored == 'after-hours') {
      return 'after hours';
    }
    if (stored == 'daytime' || stored == 'during_hours') {
      return 'daytime';
    }
    return _siteProfileService.isAfterHours(
          profile: siteProfile,
          observedAtUtc: alert.detectedAt,
        )
        ? 'after hours'
        : 'daytime';
  }

  List<String> _telegramAlertReasonBullets(
    _SiteAwarenessActiveAlertRecord alert,
  ) {
    final reason = alert.alertReason;
    if (reason == null || reason.isEmpty) {
      return const <String>[];
    }
    final signals = _telegramAlertReasonStringList(reason['signals']);
    if (signals.isEmpty) {
      return const <String>[];
    }
    final bullets = <String>[...signals.take(2)];
    final ruleOrContext = <String>[
      ..._telegramAlertReasonStringList(reason['rules_fired']),
      (reason['context_note']?.toString().trim() ?? ''),
    ].where((entry) => entry.isNotEmpty);
    if (bullets.length < 3) {
      final summary = ruleOrContext.join(' — ').trim();
      if (summary.isNotEmpty) {
        bullets.add(summary);
      }
    }
    return bullets.take(3).toList(growable: false);
  }

  List<String> _telegramAlertReasonStringList(Object? value) {
    if (value is! List) {
      return const <String>[];
    }
    return value
        .map((entry) => entry.toString().trim())
        .where((entry) => entry.isNotEmpty)
        .toList(growable: false);
  }

  DateTime _telegramSiteProfileLocalTime(String timezone, DateTime utc) {
    final normalized = timezone.trim();
    if (normalized == 'Africa/Johannesburg') {
      return utc.toUtc().add(const Duration(hours: 2));
    }
    if (normalized.toUpperCase() == 'UTC') {
      return utc.toUtc();
    }
    return utc.toLocal();
  }

  String _telegramMarkdownEscape(String value) {
    return value
        .replaceAll('\\', '\\\\')
        .replaceAll('*', r'\*')
        .replaceAll('_', r'\_')
        .replaceAll('[', r'\[')
        .replaceAll(']', r'\]')
        .replaceAll('`', r'\`');
  }

  Map<String, Object?> _telegramInlineKeyboardForProactiveAlert({
    required _SiteAwarenessActiveAlertRecord alert,
  }) {
    final channelId = alert.channelId.trim().isEmpty
        ? '0'
        : alert.channelId.trim();
    final siteId = alert.siteId.trim().isEmpty
        ? _selectedSite.trim()
        : alert.siteId.trim();
    final alertId = alert.alertId.trim();
    Map<String, String> button(String label, String callbackData) =>
        <String, String>{'text': label, 'callback_data': callbackData};
    return <String, Object?>{
      'inline_keyboard': <List<Map<String, String>>>[
        <Map<String, String>>[
          button('👁 View camera', 'view:$alertId:$channelId'),
          button('🚨 Dispatch', 'dispatch:$alertId:$siteId'),
        ],
        <Map<String, String>>[
          button('✅ Acknowledge', 'ack:$alertId'),
          button('❌ False alarm', 'dismiss:$alertId'),
        ],
      ],
    };
  }

  String _telegramInlineIncidentId(DateTime nowUtc) {
    final millis = nowUtc.toUtc().millisecondsSinceEpoch.toString();
    return 'INC-${millis.substring(math.max(0, millis.length - 6))}';
  }

  void _pruneVehiclePresenceNotificationState(DateTime nowUtc) {
    final cutoff = nowUtc.subtract(const Duration(days: 1));
    _vehiclePresenceDepartureAlertedAtByPlate.removeWhere(
      (_, sentAtUtc) => sentAtUtc.isBefore(cutoff),
    );
  }

  Future<void> _pollPatrolMonitorOnce() async {
    if (!_patrolMonitorEnabled ||
        !_telegramPollingPrimaryTab ||
        _patrolMonitorInFlight) {
      return;
    }
    _patrolMonitorInFlight = true;
    try {
      _prunePatrolMissedAlertKeys();
      final occupancyConfigRow = await _readSiteOccupancyConfigRow(
        siteId: _selectedSite,
      );
      if (occupancyConfigRow == null ||
          !_siteOccupancyHasGuard(occupancyConfigRow)) {
        return;
      }
      final assignments = await _readPatrolAssignmentsForSite(
        siteId: _selectedSite,
      );
      if (assignments.isEmpty) {
        return;
      }
      final routeIds = assignments
          .map((assignment) => assignment.routeId.trim())
          .where((value) => value.isNotEmpty)
          .toSet()
          .toList(growable: false);
      final checkpoints = await _readPatrolCheckpointsForSite(
        siteId: _selectedSite,
        routeIds: routeIds,
      );
      final scans = await _readPatrolScansForSite(siteId: _selectedSite);
      final outcome = const OnyxPatrolMonitorService().evaluate(
        siteId: _selectedSite,
        assignments: assignments,
        checkpoints: checkpoints,
        scans: scans,
        nowLocal: _telegramFlowNowLocal(),
      );
      for (final snapshot in outcome.complianceSnapshots) {
        await _upsertPatrolComplianceSnapshot(snapshot);
      }
      final siteLabel = _deliverySiteLabelFor(
        clientId: _selectedClient,
        siteId: _selectedSite,
      );
      for (final alert in outcome.missedAlerts) {
        if (_patrolMissedAlertSentAtUtcByKey.containsKey(alert.alertKey)) {
          continue;
        }
        final text = _formatPatrolMissedAlertText(
          siteLabel: siteLabel,
          alert: alert,
        );
        final messageKeyPrefix =
            'tg-patrol-missed-${alert.guardId}-${alert.expectedNextPatrolByUtc.millisecondsSinceEpoch}';
        final adminChatId = _resolvedTelegramAdminChatId();
        if (adminChatId.isNotEmpty) {
          await _sendTelegramMessageWithChunks(
            messageKeyPrefix: '$messageKeyPrefix-admin',
            chatId: adminChatId,
            messageThreadId: _resolvedTelegramAdminThreadId(),
            responseText: text,
            failureContext: 'Guard patrol missed alert',
          );
        }
        await _telegramPushCoordinator.sendScopedAlert(
          clientId: _selectedClient,
          siteId: _selectedSite,
          messageKeyPrefix: '$messageKeyPrefix-client',
          text: text,
        );
        _patrolMissedAlertSentAtUtcByKey[alert.alertKey] = DateTime.now()
            .toUtc();
      }
    } catch (error, stackTrace) {
      developer.log(
        'ONYX patrol monitor poll failed',
        name: 'PatrolMonitor',
        error: error,
        stackTrace: stackTrace,
      );
    } finally {
      _patrolMonitorInFlight = false;
      _scheduleNextPatrolMonitorPoll(15 * 60);
    }
  }

  Future<void> _pollBehaviourMonitorOnce() async {
    if (!_behaviourMonitorEnabled ||
        !_telegramPollingPrimaryTab ||
        _behaviourMonitorInFlight) {
      return;
    }
    _behaviourMonitorInFlight = true;
    try {
      final profile = await _siteProfileService.loadProfile(_selectedSite);
      final latestSnapshotRow = await _readLatestSiteAwarenessSnapshotRow(
        siteId: _selectedSite,
      );
      if (latestSnapshotRow != null) {
        final humanZones = _siteAwarenessHumanZones(latestSnapshotRow);
        final observedAtUtc =
            _siteAwarenessSummaryDate(latestSnapshotRow['snapshot_at']) ??
            DateTime.now().toUtc();
        for (final zone in humanZones) {
          final channelId = int.tryParse(zone.channelId) ?? 0;
          if (channelId <= 0) {
            continue;
          }
          await _behaviourMonitorService.recordPresence(
            siteId: _selectedSite,
            channelId: channelId,
            zoneName: zone.zoneName,
            detectedAt: zone.lastDetectedAtUtc ?? observedAtUtc,
          );
        }
      }
      final zoneRules = await _siteProfileService.loadZoneRules(_selectedSite);
      final inactivityAlerts = await _behaviourMonitorService.checkInactivity(
        _selectedSite,
        profile,
      );
      final tillAlerts = await _behaviourMonitorService.checkTillAttendance(
        _selectedSite,
        profile,
      );
      final zoneViolations = await _behaviourMonitorService.checkZoneViolations(
        _selectedSite,
        zoneRules,
      );
      if (inactivityAlerts.isNotEmpty ||
          tillAlerts.isNotEmpty ||
          zoneViolations.isNotEmpty) {
        developer.log(
          'Behaviour monitor: inactivity=${inactivityAlerts.length} '
          'till=${tillAlerts.length} zone_violations=${zoneViolations.length}',
          name: 'OnyxBehaviourMonitor',
        );
      }
    } catch (error, stackTrace) {
      developer.log(
        'ONYX behaviour monitor poll failed',
        name: 'OnyxBehaviourMonitor',
        error: error,
        stackTrace: stackTrace,
      );
    } finally {
      _behaviourMonitorInFlight = false;
      _scheduleNextBehaviourMonitorPoll(5 * 60);
    }
  }

  Future<void> _pollOperatorDisciplineOnce() async {
    if (!_operatorDisciplineEnabled ||
        !_telegramPollingPrimaryTab ||
        _operatorDisciplineInFlight) {
      return;
    }
    _operatorDisciplineInFlight = true;
    try {
      final service = _operatorDisciplineServiceOrNull;
      if (service == null) {
        return;
      }
      final profile = await _siteProfileService.loadProfile(_selectedSite);
      final nowUtc = _telegramFlowNowUtc();
      final withinMonitoringHours = !_siteProfileService.isAfterHours(
        profile: profile,
        observedAtUtc: nowUtc,
      );
      final evaluation = await service.evaluatePendingSimulations(
        siteId: _selectedSite,
      );
      for (final completed in evaluation.completed) {
        final adminChatId = _resolvedTelegramAdminChatId();
        if (adminChatId.isEmpty) {
          continue;
        }
        await _sendTelegramMessageWithChunks(
          messageKeyPrefix: 'tg-sim-reveal-${completed.id}',
          chatId: adminChatId,
          messageThreadId: _resolvedTelegramAdminThreadId(),
          responseText:
              '🧪 Simulation revealed — ${completed.operatorId} at ${completed.siteId}\n'
              'Result: ${completed.resultLabel}\n'
              'Response: ${(completed.responseSeconds ?? 0).toStringAsFixed(0)}s\n'
              'Action: ${completed.actionTaken ?? 'reviewed'}',
          failureContext: 'Operator simulation reveal',
        );
      }
      await service.maybeInjectScheduledSimulation(
        siteId: _selectedSite,
        clientId: _selectedClient,
        operatorId: _operatorId,
        withinMonitoringHours: withinMonitoringHours,
      );
      await _maybeSendWeeklyOperatorReport(service);
    } catch (error, stackTrace) {
      developer.log(
        'ONYX operator discipline poll failed',
        name: 'OnyxOperatorDiscipline',
        error: error,
        stackTrace: stackTrace,
      );
    } finally {
      _operatorDisciplineInFlight = false;
      _scheduleNextOperatorDisciplinePoll(20 * 60);
    }
  }

