  Future<void> _maybePersistWeeklyClientTrustSnapshot() async {
    final service = _clientTrustServiceOrNull;
    if (service == null) {
      return;
    }
    final nowLocal = _telegramFlowNowLocal();
    if (nowLocal.weekday != DateTime.sunday) {
      return;
    }
    if (nowLocal.hour != 23 || nowLocal.minute < 55) {
      return;
    }
    final weekKey =
        '${_selectedClient.trim()}|${_selectedSite.trim()}|${nowLocal.year.toString().padLeft(4, '0')}-${nowLocal.month.toString().padLeft(2, '0')}-${nowLocal.day.toString().padLeft(2, '0')}';
    if (_clientTrustLastWeeklySnapshotKey == weekKey) {
      return;
    }
    final period = DateTimeRange(
      start: nowLocal.subtract(const Duration(days: 30)),
      end: nowLocal,
    );
    await service.persistWeeklySnapshot(
      clientId: _selectedClient,
      siteId: _selectedSite,
      period: period,
    );
    _clientTrustLastWeeklySnapshotKey = weekKey;
  }

  Future<void> _maybeSendWeeklyOperatorReport(
    OnyxOperatorDisciplineService service,
  ) async {
    final nowLocal = _telegramFlowNowLocal();
    if (nowLocal.weekday != DateTime.monday || nowLocal.hour < 7) {
      return;
    }
    final weekKey =
        '${nowLocal.year.toString().padLeft(4, '0')}-${nowLocal.month.toString().padLeft(2, '0')}-${nowLocal.day.toString().padLeft(2, '0')}';
    if (_operatorDisciplineLastWeeklyReportKey == weekKey) {
      return;
    }
    final scores = await service.getCurrentScores(siteId: _selectedSite);
    final adminChatId = _resolvedTelegramAdminChatId();
    if (adminChatId.isEmpty) {
      return;
    }
    var reportText = service.weeklyReportText(
      weekOf: DateTime(nowLocal.year, nowLocal.month, nowLocal.day),
      scores: scores,
    );
    final signalAccuracySummary = await _weeklySignalAccuracySummaryOrNull(
      siteId: _selectedSite,
      siteLabel: _deliverySiteLabelFor(
        clientId: _selectedClient,
        siteId: _selectedSite,
      ),
    );
    if (signalAccuracySummary != null) {
      reportText = '$reportText\n\n$signalAccuracySummary';
    }
    final delivered = await _sendTelegramMessageWithChunks(
      messageKeyPrefix: 'tg-operator-weekly-$weekKey',
      chatId: adminChatId,
      messageThreadId: _resolvedTelegramAdminThreadId(),
      responseText: reportText,
      failureContext: 'Operator weekly report',
    );
    if (delivered) {
      _operatorDisciplineLastWeeklyReportKey = weekKey;
    }
  }

  void _prunePatrolMissedAlertKeys() {
    if (_patrolMissedAlertSentAtUtcByKey.isEmpty) {
      return;
    }
    final cutoff = DateTime.now().toUtc().subtract(const Duration(hours: 24));
    _patrolMissedAlertSentAtUtcByKey.removeWhere(
      (_, sentAtUtc) => sentAtUtc.isBefore(cutoff),
    );
  }

  String _formatPatrolMissedAlertText({
    required String siteLabel,
    required OnyxMissedPatrolAlert alert,
  }) {
    final lastCheckpointLine = alert.lastCheckpointName == null
        ? 'Last checkpoint: none logged yet.'
        : 'Last checkpoint: ${alert.lastCheckpointName} at ${_telegramCommandLocalTimeLabel(alert.lastScanAtUtc)}.';
    return [
      '⚠️ Missed patrol — ${alert.guardId} at $siteLabel.',
      lastCheckpointLine,
      'Expected next patrol by: ${_telegramCommandLocalTimeLabel(alert.expectedNextPatrolByUtc)}.',
      'Current time: ${_telegramCommandLocalTimeLabel(alert.currentTimeUtc)}.',
    ].join('\n');
  }

  void _scheduleNextTelegramAdminPoll(int delaySeconds) {
    _telegramAdminPollTimer?.cancel();
    if (!_telegramInboundRouterEnabled || !_telegramPollingPrimaryTab) {
      _telegramAdminPollTimer = null;
      return;
    }
    _telegramAdminPollTimer = Timer(Duration(seconds: delaySeconds), () {
      unawaited(_pollTelegramAdminCommandsOnce());
    });
  }

  List<String> _splitTelegramAdminResponse(String text) {
    final content = text.trim().isEmpty ? '(no output)' : text.trim();
    if (content.length <= _telegramAdminMaxMessageChars) {
      return <String>[content];
    }
    final chunks = <String>[];
    var cursor = 0;
    while (cursor < content.length) {
      final remaining = content.length - cursor;
      if (remaining <= _telegramAdminMaxMessageChars) {
        chunks.add(content.substring(cursor));
        break;
      }
      final windowEnd = cursor + _telegramAdminMaxMessageChars;
      final slice = content.substring(cursor, windowEnd);
      var cut = slice.lastIndexOf('\n');
      if (cut < _telegramAdminMaxMessageChars ~/ 2) {
        cut = slice.lastIndexOf(' ');
      }
      if (cut <= 0) {
        cut = _telegramAdminMaxMessageChars;
      }
      chunks.add(content.substring(cursor, cursor + cut).trimRight());
      cursor += cut;
      while (cursor < content.length && content[cursor] == ' ') {
        cursor += 1;
      }
    }
    return chunks
        .where((entry) => entry.trim().isNotEmpty)
        .toList(growable: false);
  }

  Future<bool> _sendTelegramMessageWithChunks({
    required String messageKeyPrefix,
    required String chatId,
    required int? messageThreadId,
    required String responseText,
    String? failureContext,
    Map<String, Object?>? replyMarkup,
    String? parseMode,
  }) async {
    final chunks = _splitTelegramAdminResponse(responseText);
    final stamp = DateTime.now().microsecondsSinceEpoch;
    final messages = <TelegramBridgeMessage>[
      for (var index = 0; index < chunks.length; index += 1)
        TelegramBridgeMessage(
          messageKey: '$messageKeyPrefix-$index-$stamp',
          chatId: chatId,
          messageThreadId: messageThreadId,
          text: chunks[index],
          replyMarkup: index == 0 ? replyMarkup : null,
          parseMode: parseMode,
        ),
    ];
    final result = await _telegramBridge.sendMessages(messages: messages);
    if (result.failedCount <= 0) {
      return true;
    }
    final reasons = result.failureReasonsByMessageKey.values
        .map((value) => value.trim())
        .where((value) => value.isNotEmpty)
        .toSet()
        .take(2)
        .join(' | ');
    if (mounted) {
      setState(() {
        _telegramBridgeHealthLabel = 'degraded';
        _telegramBridgeHealthDetail = reasons.isEmpty
            ? '${failureContext ?? 'Telegram response'} delivery failed.'
            : '${failureContext ?? 'Telegram response'} delivery failed: $reasons';
        _telegramBridgeHealthUpdatedAtUtc = DateTime.now().toUtc();
      });
    }
    return false;
  }

  Future<bool> _sendTelegramPhotoMessage({
    required String messageKey,
    required String chatId,
    required int? messageThreadId,
    required String caption,
    required List<int> photoBytes,
    required String photoFilename,
    String? failureContext,
    Map<String, Object?>? replyMarkup,
    String? parseMode,
  }) async {
    final result = await _telegramBridge.sendMessages(
      messages: <TelegramBridgeMessage>[
        TelegramBridgeMessage(
          messageKey: messageKey,
          chatId: chatId,
          messageThreadId: messageThreadId,
          text: caption,
          photoBytes: photoBytes,
          photoFilename: photoFilename,
          replyMarkup: replyMarkup,
          parseMode: parseMode,
        ),
      ],
    );
    if (result.failedCount <= 0) {
      return true;
    }
    final reasons = result.failureReasonsByMessageKey.values
        .map((value) => value.trim())
        .where((value) => value.isNotEmpty)
        .toSet()
        .take(2)
        .join(' | ');
    if (mounted) {
      setState(() {
        _telegramBridgeHealthLabel = 'degraded';
        _telegramBridgeHealthDetail = reasons.isEmpty
            ? '${failureContext ?? 'Telegram photo'} delivery failed.'
            : '${failureContext ?? 'Telegram photo'} delivery failed: $reasons';
        _telegramBridgeHealthUpdatedAtUtc = DateTime.now().toUtc();
      });
    }
    return false;
  }

  String _telegramAdminSignalHeader() {
    final events = store.allEvents();
    final activeIncidents = _activeIncidentCount(events);
    final guardsOnline = _guardsOnlineCount(events);
    final critical = _telegramAdminCriticalAlerts();
    final criticalCount = critical.length;
    final telemetryGate = _guardTelemetryLiveReadyGateViolated
        ? 'VIOLATION'
        : 'OK';
    final hasWarningSignal =
        _telegramBridgeHealthLabel.toLowerCase() == 'degraded' ||
        _telegramBridgeHealthLabel.toLowerCase() == 'blocked' ||
        _clientAppPushSyncStatusLabel.trim().toLowerCase() == 'failed' ||
        _pendingAiActionCount(events) > 0;
    final posture = criticalCount > 0
        ? 'RED'
        : (hasWarningSignal ? 'AMBER' : 'GREEN');
    return '[$posture] ONYX SIGNAL'
        ' | critical=$criticalCount'
        ' | inc=$activeIncidents'
        ' | guards=$guardsOnline'
        ' | telemetry=${_guardTelemetryReadiness.name}/$telemetryGate'
        ' | tg=${_telegramBridgeHealthLabel.toUpperCase()}'
        ' | utc=${DateTime.now().toUtc().toIso8601String()}';
  }

  Future<bool> _sendTelegramAdminResponse({
    required int updateId,
    required String chatId,
    required int? messageThreadId,
    required String responseText,
    bool includeSignalHeader = false,
    bool includeQuickActions = true,
    bool richText = false,
  }) async {
    final payload = includeSignalHeader
        ? '${_telegramAdminSignalHeader()}\n$responseText'
        : responseText;
    return _sendTelegramMessageWithChunks(
      messageKeyPrefix: 'tg-admin-$updateId',
      chatId: chatId,
      messageThreadId: messageThreadId,
      responseText: payload,
      failureContext: 'Admin response',
      replyMarkup: includeQuickActions
          ? _telegramAdminQuickReplyMarkup()
          : null,
      parseMode: richText ? 'HTML' : null,
    );
  }

  Map<String, Object?> _telegramAdminQuickReplyMarkup() {
    return const <String, Object?>{'remove_keyboard': true};
  }

  Future<void> _pollTelegramAdminCommandsOnce() async {
    if (!_telegramInboundRouterEnabled ||
        _telegramAdminPollInFlight ||
        !_telegramPollingPrimaryTab) {
      return;
    }
    _telegramAdminPollInFlight = true;
    try {
      await (_telegramAdminRuntimeStateHydrationFuture ?? Future<void>.value());
      if (!_telegramAdminOffsetBootstrapped) {
        await _bootstrapTelegramAdminOffset();
      }
      final updates = await _telegramBridge.fetchUpdates(
        offset: _telegramAdminLastUpdateId == null
            ? null
            : _telegramAdminLastUpdateId! + 1,
        limit: 40,
      );
      if (updates.isEmpty) {
        if (!_telegramAiBootGracePeriodComplete) {
          _telegramAiBootGracePeriodComplete = true;
          developer.log(
            'ONYX: boot grace period complete — no queued updates',
            name: 'TelegramBoot',
          );
        }
        return;
      }
      var updatesToProcess = updates;
      if (!_telegramAiBootGracePeriodComplete) {
        final appStartTime = DateTime.now().toUtc().subtract(
          const Duration(seconds: 30),
        );
        final staleUpdates = <TelegramBridgeInboundMessage>[];
        final freshUpdates = <TelegramBridgeInboundMessage>[];
        for (final update in updates) {
          final sentAtUtc = update.sentAtUtc?.toUtc();
          if (sentAtUtc != null && sentAtUtc.isBefore(appStartTime)) {
            staleUpdates.add(update);
          } else {
            freshUpdates.add(update);
          }
        }
        await _seedTelegramAdminUpdateTracking(updates);
        for (final staleUpdate in staleUpdates) {
          await _markTelegramInboundUpdateProcessed(staleUpdate.updateId);
        }
        _telegramAiBootGracePeriodComplete = true;
        developer.log(
          'ONYX: boot grace period complete — '
          '${staleUpdates.length} stale queued updates skipped, '
          '${freshUpdates.length} recent updates kept '
          '(cutoff ${appStartTime.toIso8601String()})',
          name: 'TelegramBoot',
        );
        if (freshUpdates.isEmpty) {
          return;
        }
        updatesToProcess = freshUpdates;
      } else {
        await _seedTelegramAdminUpdateTracking(updates);
      }
      final adminChatId = _resolvedTelegramAdminChatId();
      final adminThreadId = _resolvedTelegramAdminThreadId();
      for (final update in updatesToProcess) {
        if (_telegramInboundUpdateAlreadyProcessed(update.updateId)) {
          continue;
        }
        if (update.fromIsBot) {
          await _markTelegramInboundUpdateProcessed(update.updateId);
          continue;
        }
        try {
          final handled = await _processTelegramInboundUpdate(
            update,
            adminChatId: adminChatId,
            adminThreadId: adminThreadId,
          );
          if (handled) {
            await _markTelegramInboundUpdateProcessed(update.updateId);
          }
        } catch (error) {
          _recordTelegramInboundUpdateFailure(update: update, error: error);
        }
      }
    } catch (error) {
      if (mounted) {
        setState(() {
          _telegramBridgeHealthLabel = 'degraded';
          _telegramBridgeHealthDetail = 'Admin command poll failed: $error';
          _telegramBridgeHealthUpdatedAtUtc = DateTime.now().toUtc();
        });
      }
    } finally {
      _telegramAdminPollInFlight = false;
      unawaited(
        _maybeSendTelegramAdminCriticalDigest(source: 'admin-control-loop'),
      );
      _scheduleNextTelegramAdminPoll(
        _normalizedTelegramAdminPollIntervalSeconds,
      );
    }
  }

  void _handleTelegramPollingPrimaryLost() {
    _telegramAdminPollTimer?.cancel();
    _telegramAdminPollTimer = null;
    _siteAwarenessAlertPollTimer?.cancel();
    _siteAwarenessAlertPollTimer = null;
    _patrolMonitorTimer?.cancel();
    _patrolMonitorTimer = null;
    _behaviourMonitorTimer?.cancel();
    _behaviourMonitorTimer = null;
    _operatorDisciplineTimer?.cancel();
    _operatorDisciplineTimer = null;
    _clientTrustSnapshotTimer?.cancel();
    _clientTrustSnapshotTimer = null;
    _telegramPollingPrimaryTab = false;
    if (!mounted) {
      return;
    }
    setState(() {
      _telegramBridgeHealthDetail =
          'Telegram polling moved to another browser tab.';
      _telegramBridgeHealthUpdatedAtUtc = DateTime.now().toUtc();
    });
  }

  void _handleTelegramPollingPrimaryAvailable() {
    if (!_telegramInboundRouterEnabled ||
        _telegramAdminPollTimer != null ||
        _telegramPollingLockAcquisitionInFlight) {
      _startSiteAwarenessAlertLoop();
      _startPatrolMonitorLoop();
      _startBehaviourMonitorLoop();
      _startOperatorDisciplineLoop();
      _startClientTrustSnapshotLoop();
      return;
    }
    unawaited(_ensureTelegramPollingPrimaryTab());
    _startSiteAwarenessAlertLoop();
    _startPatrolMonitorLoop();
    _startBehaviourMonitorLoop();
    _startOperatorDisciplineLoop();
    _startClientTrustSnapshotLoop();
  }

  void _recordTelegramInboundUpdateFailure({
    required TelegramBridgeInboundMessage update,
    required Object error,
  }) {
    if (!mounted) {
      return;
    }
    setState(() {
      _telegramBridgeHealthLabel = 'degraded';
      _telegramBridgeHealthDetail =
          'Telegram inbound update ${update.updateId} failed: $error';
      _telegramBridgeHealthUpdatedAtUtc = DateTime.now().toUtc();
    });
  }

  bool _telegramInboundUpdateAlreadyProcessed(int updateId) {
    final lastUpdateId = _telegramAdminLastUpdateId;
    if (lastUpdateId != null && updateId <= lastUpdateId) {
      return true;
    }
    return _telegramAdminHandledOutOfOrderUpdateIds.contains(updateId);
  }

  Future<void> _seedTelegramAdminUpdateTracking(
    List<TelegramBridgeInboundMessage> updates,
  ) async {
    if (_telegramAdminLastUpdateId != null || updates.isEmpty) {
      return;
    }
    _telegramAdminLastUpdateId = updates.first.updateId - 1;
    await _persistTelegramAdminRuntimeState();
  }

  Future<void> _markTelegramInboundUpdateProcessed(int updateId) async {
    final currentLastUpdateId = _telegramAdminLastUpdateId;
    if (currentLastUpdateId == null) {
      _telegramAdminLastUpdateId = updateId;
    } else if (updateId == currentLastUpdateId + 1) {
      _telegramAdminLastUpdateId = updateId;
    } else if (updateId > currentLastUpdateId + 1) {
      _telegramAdminHandledOutOfOrderUpdateIds = <int>{
        ..._telegramAdminHandledOutOfOrderUpdateIds,
        updateId,
      };
    } else {
      return;
    }
    var nextUpdateId = (_telegramAdminLastUpdateId ?? updateId) + 1;
    while (_telegramAdminHandledOutOfOrderUpdateIds.contains(nextUpdateId)) {
      _telegramAdminHandledOutOfOrderUpdateIds = <int>{
        for (final existing in _telegramAdminHandledOutOfOrderUpdateIds)
          if (existing != nextUpdateId) existing,
      };
      _telegramAdminLastUpdateId = nextUpdateId;
      nextUpdateId = nextUpdateId + 1;
    }
    await _persistTelegramAdminRuntimeState();
  }

  Future<bool> _processTelegramInboundUpdate(
    TelegramBridgeInboundMessage update, {
    required String adminChatId,
    required int? adminThreadId,
  }) async {
    final handledProactiveCallback =
        await _handleTelegramProactiveAlertCallback(update);
    if (handledProactiveCallback) {
      if (mounted) {
        setState(() {});
      }
      return true;
    }
    final handledAdmin = await _handleTelegramAdminInboundUpdate(
      update,
      adminChatId: adminChatId,
      adminThreadId: adminThreadId,
    );
    if (handledAdmin) {
      if (mounted) {
        setState(() {});
      }
      return true;
    }
    final handledPartner = await _handleTelegramPartnerInboundUpdate(
      update,
      adminChatId: adminChatId,
      adminThreadId: adminThreadId,
    );
    if (handledPartner) {
      if (mounted) {
        setState(() {});
      }
      return true;
    }
    final handledAi = await _handleTelegramAiInboundUpdate(
      update,
      adminChatId: adminChatId,
      adminThreadId: adminThreadId,
    );
    if (handledAi && mounted) {
      setState(() {});
    }
    return handledAi;
  }

  Future<bool> _handleTelegramAdminInboundUpdate(
    TelegramBridgeInboundMessage update, {
    required String adminChatId,
    required int? adminThreadId,
  }) async {
    if (adminChatId.trim().isEmpty) {
      return false;
    }
    final inAdminChat =
        update.chatId.trim() == adminChatId &&
        (adminThreadId == null || update.messageThreadId == adminThreadId);
    if (!inAdminChat) {
      return false;
    }
    final parsed = _telegramAdminCommand(update.text);
    if (!_isTelegramAdminSenderAllowed(update)) {
      final senderIdLabel = update.fromUserId?.toString() ?? 'unknown';
      final aclLabel = _telegramAdminAllowedUserIds.isEmpty
          ? 'none'
          : _telegramAdminAllowedUserIds.join(',');
      if (parsed?.command == 'whoami') {
        final delivered = await _sendTelegramAdminResponse(
          updateId: update.updateId,
          chatId: adminChatId,
          messageThreadId: adminThreadId,
          responseText:
              '${_telegramAdminWhoAmISnapshot(update)}\n'
              'ACL status: denied for command scope.\n'
              'Current allow list: $aclLabel\n'
              'Ask an authorized admin to run /acl add $senderIdLabel.',
          includeSignalHeader: false,
        );
        _recordTelegramRecentPrompt(
          roomLabel: 'Onyx',
          scopeLabel:
              '${_telegramAdminScopeLabel(_telegramAdminTargetClientId)} / ${_telegramAdminScopeLabel(_telegramAdminTargetSiteId)}',
          prompt: update.text,
          outcomeLabel: delivered ? 'denied' : 'send failed',
        );
      } else {
        final delivered = await _sendTelegramAdminResponse(
          updateId: update.updateId,
          chatId: adminChatId,
          messageThreadId: adminThreadId,
          responseText:
              'ONYX ADMIN ACL DENY\n'
              'sender_user_id=$senderIdLabel is not allowed.\n'
              'Allowed user ids: $aclLabel\n'
              'Ask an authorized admin to run /acl add $senderIdLabel.\n'
              'Then retry your command.',
          includeSignalHeader: false,
        );
        _recordTelegramRecentPrompt(
          roomLabel: 'Onyx',
          scopeLabel:
              '${_telegramAdminScopeLabel(_telegramAdminTargetClientId)} / ${_telegramAdminScopeLabel(_telegramAdminTargetSiteId)}',
          prompt: update.text,
          outcomeLabel: delivered ? 'denied' : 'send failed',
        );
      }
      return true;
    }
    if (parsed != null) {
      final allowReadOnlyWhileControlDisabled =
          !_telegramAdminControlEnabled &&
          _telegramAdminReadOnlyCommand(parsed.command);
      if (_telegramAdminControlEnabled || allowReadOnlyWhileControlDisabled) {
        final response = await _telegramAdminResponseFor(
          parsed.command,
          update,
          arguments: parsed.arguments,
        );
        final richText = _telegramAdminUseRichTextForCommand(
          parsed.command,
          arguments: parsed.arguments,
        );
        final renderedResponse = richText
            ? _telegramAdminRenderCommandCard(parsed.command, response)
            : response;
        final delivered = await _sendTelegramAdminResponse(
          updateId: update.updateId,
          chatId: adminChatId,
          messageThreadId: adminThreadId,
          responseText: renderedResponse,
          richText: richText,
        );
        _recordTelegramRecentPrompt(
          roomLabel: 'Onyx',
          scopeLabel:
              '${_telegramAdminScopeLabel(_telegramAdminTargetClientId)} / ${_telegramAdminScopeLabel(_telegramAdminTargetSiteId)}',
          prompt: update.text,
          outcomeLabel: delivered ? 'answered' : 'send failed',
        );
        _telegramAdminLastCommandAtUtc = DateTime.now().toUtc();
        final origin = update.fromUsername?.trim().isNotEmpty == true
            ? '@${update.fromUsername!.trim()}'
            : (update.fromUserId?.toString() ?? 'unknown');
        _telegramAdminLastCommandSummary = '/${parsed.command} by $origin';
        final auditEntry =
            '/${parsed.command}${parsed.arguments.isEmpty ? '' : ' ${parsed.arguments}'} by $origin (${update.chatId}${update.messageThreadId == null ? '' : '#${update.messageThreadId}'}) @ ${_telegramAdminLastCommandAtUtc!.toIso8601String()}';
        _telegramAdminCommandAudit = <String>[
          auditEntry,
          ..._telegramAdminCommandAudit,
        ].take(40).toList(growable: false);
        unawaited(_persistTelegramAdminRuntimeState());
        return true;
      }
      final delivered = await _sendTelegramAdminResponse(
        updateId: update.updateId,
        chatId: adminChatId,
        messageThreadId: adminThreadId,
        responseText:
            'ONYX ADMIN CONTROL DISABLED\n'
            'Command "/${parsed.command}" is blocked by runtime config.\n'
            'Allowed while disabled: status, brief, next, critical, ops, incidents, whoami, help.\n'
            'Set ONYX_TELEGRAM_ADMIN_CONTROL_ENABLED=true to unlock full command set.',
        includeSignalHeader: false,
      );
      _recordTelegramRecentPrompt(
        roomLabel: 'Onyx',
        scopeLabel:
            '${_telegramAdminScopeLabel(_telegramAdminTargetClientId)} / ${_telegramAdminScopeLabel(_telegramAdminTargetSiteId)}',
        prompt: update.text,
        outcomeLabel: delivered ? 'denied' : 'send failed',
      );
      return true;
    }
    final handledOnyxOperational =
        await _handleTelegramAdminOnyxOperationalCommand(
          update,
          adminChatId: adminChatId,
          adminThreadId: adminThreadId,
        );
    if (handledOnyxOperational) {
      return true;
    }
    final handledOnboardingIntake = await _handleTelegramAdminOnboardingIntake(
      update,
      adminChatId: adminChatId,
      adminThreadId: adminThreadId,
    );
    if (handledOnboardingIntake) {
      return true;
    }
    final handledOnboardingApproval =
        await _handleTelegramAdminOnboardingApproval(
          update,
          adminChatId: adminChatId,
          adminThreadId: adminThreadId,
        );
    if (handledOnboardingApproval) {
      return true;
    }
    if (!_telegramAiAssistantEnabled) {
      final fallbackText = _telegramAdminConversationalFallback(update.text);
      final delivered = await _sendTelegramAdminResponse(
        updateId: update.updateId,
        chatId: adminChatId,
        messageThreadId: adminThreadId,
        responseText: fallbackText,
      );
      _recordTelegramRecentPrompt(
        roomLabel: 'Onyx',
        scopeLabel:
            '${_telegramAdminScopeLabel(_telegramAdminTargetClientId)} / ${_telegramAdminScopeLabel(_telegramAdminTargetSiteId)}',
        prompt: update.text,
        outcomeLabel: delivered ? 'assistant disabled fallback' : 'send failed',
      );
      return true;
    }
    TelegramAiDraftReply aiDraft;
    try {
      aiDraft = _telegramAiAssistant.isConfigured
          ? await _telegramAiAssistant
                .draftReply(
                  audience: TelegramAiAudience.admin,
                  messageText: update.text,
                  clientId: _telegramAdminTargetClientId,
                  siteId: _telegramAdminTargetSiteId,
                )
                .timeout(const Duration(seconds: 5))
          : TelegramAiDraftReply(
              text: _telegramAdminConversationalFallback(update.text),
              usedFallback: true,
              providerLabel: 'local-router',
            );
    } on TimeoutException {
      aiDraft = TelegramAiDraftReply(
        text: _telegramAdminConversationalFallback(update.text),
        usedFallback: true,
        providerLabel: 'timeout-fallback',
      );
    }
    final delivered = await _sendTelegramAdminResponse(
      updateId: update.updateId,
      chatId: adminChatId,
      messageThreadId: adminThreadId,
      responseText: aiDraft.text,
    );
    _telegramAdminLastCommandAtUtc = DateTime.now().toUtc();
    _telegramAdminLastCommandSummary =
        'free-text by ${_telegramInboundAuthor(update)}';
    _telegramAiLastHandledAtUtc = DateTime.now().toUtc();
    _telegramAiLastHandledSummary =
        'admin/${delivered ? 'sent' : 'failed'} • ${aiDraft.providerLabel}';
    _recordTelegramRecentPrompt(
      roomLabel: 'Onyx',
      scopeLabel:
          '${_telegramAdminScopeLabel(_telegramAdminTargetClientId)} / ${_telegramAdminScopeLabel(_telegramAdminTargetSiteId)}',
      prompt: update.text,
      outcomeLabel: delivered ? 'assistant reply' : 'send failed',
      handledAtUtc: _telegramAiLastHandledAtUtc,
    );
    await _appendTelegramAiLedger(
      clientId: _telegramAdminTargetClientId,
      siteId: _telegramAdminTargetSiteId,
      lane: 'admin',
      action: delivered ? 'sent' : 'send_failed',
      inboundText: update.text,
      outboundText: aiDraft.text,
      providerLabel: aiDraft.providerLabel,
      update: update,
    );
    return true;
  }

  Future<bool> _handleTelegramPartnerInboundUpdate(
    TelegramBridgeInboundMessage update, {
    required String adminChatId,
    required int? adminThreadId,
  }) async {
    final target = await _resolveInboundPartnerTarget(
      chatId: update.chatId,
      messageThreadId: update.messageThreadId,
    );
    if (target == null) {
      return false;
    }
    final scopedSiteId = (target.siteId ?? '').trim();
    final siteId = scopedSiteId.isEmpty ? 'default' : scopedSiteId;
    final action = _telegramPartnerDispatchService.parseActionText(update.text);
    if (action == null) {
      final handledOnyxOperational =
          await _handleTelegramPartnerOnyxOperationalCommand(
            update: update,
            target: target,
            siteId: scopedSiteId,
          );
      if (handledOnyxOperational) {
        return true;
      }
      await _sendTelegramMessageWithChunks(
        messageKeyPrefix: 'tg-partner-help-${update.updateId}',
        chatId: update.chatId,
        messageThreadId: update.messageThreadId,
        responseText:
            'ONYX partner lane\n'
            'You can ask scoped questions like "show dispatches today", "check status of Guard001", "show last patrol report for Guard001", or "show incidents last night".\n'
            'Reply with ACCEPT, ON SITE, ALL CLEAR, or CANCEL.\n'
            'If multiple dispatches are active, reply to the dispatch card or include the dispatch id, for example: ON SITE DSP-1001.',
        failureContext: 'Partner dispatch guidance',
        replyMarkup: _telegramPartnerDispatchService.replyKeyboardMarkup(),
      );
      return true;
    }
    final openContexts = _openPartnerDispatchContextsForScope(
      clientId: target.clientId,
      siteId: siteId,
    );
    if (openContexts.isEmpty) {
      await _sendTelegramMessageWithChunks(
        messageKeyPrefix: 'tg-partner-none-${update.updateId}',
        chatId: update.chatId,
        messageThreadId: update.messageThreadId,
        responseText:
            'ONYX found no open partner dispatches for ${target.clientId}/$siteId. Control should resend the dispatch if needed.',
        failureContext: 'Partner dispatch missing context',
      );
      return true;
    }
    final requestedDispatchId = _dispatchIdFromPartnerUpdate(
      update,
      clientId: target.clientId,
      siteId: siteId,
    );
    final matchingContexts = requestedDispatchId == null
        ? openContexts
        : openContexts
              .where(
                (context) =>
                    context.dispatchId.toUpperCase() ==
                    requestedDispatchId.toUpperCase(),
              )
              .toList(growable: false);
    if (matchingContexts.isEmpty) {
      await _sendTelegramMessageWithChunks(
        messageKeyPrefix: 'tg-partner-unknown-${update.updateId}',
        chatId: update.chatId,
        messageThreadId: update.messageThreadId,
        responseText:
            'ONYX could not match that dispatch id in ${target.clientId}/$siteId.\n'
            'Open dispatches: ${openContexts.map((context) => context.dispatchId).join(', ')}',
        failureContext: 'Partner dispatch unknown dispatch id',
      );
      return true;
    }
    if (matchingContexts.length > 1) {
      await _sendTelegramMessageWithChunks(
        messageKeyPrefix: 'tg-partner-ambiguous-${update.updateId}',
        chatId: update.chatId,
        messageThreadId: update.messageThreadId,
        responseText:
            'ONYX needs the dispatch id because multiple partner dispatches are active.\n'
            'Reply to the dispatch card or send: ${action.label} ${matchingContexts.first.dispatchId}\n'
            'Open dispatches: ${matchingContexts.map((context) => context.dispatchId).join(', ')}',
        failureContext: 'Partner dispatch ambiguous context',
      );
      return true;
    }
    final actorLabel = update.fromUsername?.trim().isNotEmpty == true
        ? '@${update.fromUsername!.trim()}'
        : _telegramInboundAuthor(update);
    final occurredAtUtc = update.sentAtUtc ?? DateTime.now().toUtc();
    final resolution = _telegramPartnerDispatchService.resolveReply(
      action: action,
      context: matchingContexts.single,
      actorLabel: actorLabel,
      occurredAtUtc: occurredAtUtc,
      events: store.allEvents(),
    );
    if (resolution == null) {
      await _sendTelegramMessageWithChunks(
        messageKeyPrefix: 'tg-partner-invalid-${update.updateId}',
        chatId: update.chatId,
        messageThreadId: update.messageThreadId,
        responseText:
            'ONYX could not apply ${action.label} for ${matchingContexts.single.dispatchId}.\n'
            'The dispatch may already be closed or that transition is not allowed.',
        failureContext: 'Partner dispatch invalid transition',
      );
      return true;
    }
    store.append(resolution.event);
    await _sendTelegramMessageWithChunks(
      messageKeyPrefix: 'tg-partner-confirm-${update.updateId}',
      chatId: update.chatId,
      messageThreadId: update.messageThreadId,
      responseText:
          '${_telegramPartnerDispatchService.partnerConfirmationText(action)}\n'
          'Dispatch: ${matchingContexts.single.dispatchId}',
      failureContext: 'Partner dispatch acknowledgement',
      replyMarkup: _telegramPartnerDispatchService.replyKeyboardMarkup(),
    );
    await _appendTelegramConversationMessage(
      clientId: target.clientId,
      siteId: siteId,
      author: matchingContexts.single.partnerLabel,
      body:
          'Partner declared ${action.label} for ${matchingContexts.single.dispatchId} via Telegram by $actorLabel.',
      occurredAtUtc: occurredAtUtc,
      roomKey: 'Security Desk',
      viewerRole: ClientAppViewerRole.control.name,
      incidentStatusLabel: resolution.clientStatusLabel,
      messageSource: 'telegram',
      messageProvider: 'partner_dispatch',
    );
    if (adminChatId.trim().isNotEmpty) {
      await _sendTelegramMessageWithChunks(
        messageKeyPrefix: 'tg-admin-partner-${update.updateId}',
        chatId: adminChatId,
        messageThreadId: adminThreadId,
        responseText: resolution.adminAuditSummary,
        failureContext: 'Admin partner dispatch relay',
      );
    }
    return true;
  }

  Future<bool> _handleTelegramAiInboundUpdate(
    TelegramBridgeInboundMessage update, {
    required String adminChatId,
    required int? adminThreadId,
  }) async {
    final trimmed = update.text.trim();
    if (trimmed.isEmpty || trimmed.startsWith('/')) {
      return false;
    }
    final target = await _resolveInboundClientTarget(
      chatId: update.chatId,
      messageThreadId: update.messageThreadId,
    );
    if (target == null) {
      return false;
    }
    final siteId = (target.siteId ?? '').trim().isEmpty
        ? 'default'
        : target.siteId!.trim();
    await _appendTelegramConversationMessage(
      clientId: target.clientId,
      siteId: siteId,
      author: _telegramInboundAuthor(update),
      body: trimmed,
      occurredAtUtc: update.sentAtUtc ?? DateTime.now().toUtc(),
      roomKey: 'Residents',
      viewerRole: ClientAppViewerRole.client.name,
      incidentStatusLabel: 'Telegram Inbound',
      messageSource: 'telegram',
      messageProvider: 'telegram',
    );
    final canNotifyAdmin = adminChatId.trim().isNotEmpty;
    final handledClientApproval = await _handleTelegramClientApprovalReply(
      update: update,
      target: target,
      siteId: siteId,
      adminChatId: adminChatId,
      adminThreadId: adminThreadId,
    );
    if (handledClientApproval) {
      return true;
    }
    final handledClientAllowance = await _handleTelegramClientAllowanceReply(
      update: update,
      target: target,
      siteId: siteId,
      adminChatId: adminChatId,
      adminThreadId: adminThreadId,
    );
    if (handledClientAllowance) {
      return true;
    }
    final handledIdentityIntake = await _handleTelegramIdentityIntake(
      update: update,
      target: target,
      siteId: siteId,
      adminChatId: adminChatId,
      adminThreadId: adminThreadId,
    );
    if (handledIdentityIntake) {
      return true;
    }
    final handledMovementImageWatchRequest =
        await _handleTelegramClientMovementImageWatchRequest(
          update: update,
          target: target,
          siteId: siteId,
        );
    if (handledMovementImageWatchRequest) {
      return true;
    }
    final handledEventImageRequest =
        await _handleTelegramClientEventImageRequest(
          update: update,
          target: target,
          siteId: siteId,
        );
    if (handledEventImageRequest) {
      return true;
    }
    final handledCurrentImageRequest =
        await _handleTelegramClientCurrentImageRequest(
          update: update,
          target: target,
          siteId: siteId,
        );
    if (handledCurrentImageRequest) {
      return true;
    }
    if (_isHighRiskTelegramMessage(trimmed)) {
      final escalationText = _telegramHighRiskClientAcknowledgement(trimmed);
      await _sendTelegramMessageWithChunks(
        messageKeyPrefix: 'tg-client-escalated-${update.updateId}',
        chatId: update.chatId,
        messageThreadId: update.messageThreadId,
        responseText: escalationText,
        failureContext: 'Client escalation acknowledgement',
      );
      await _appendTelegramConversationMessage(
        clientId: target.clientId,
        siteId: siteId,
        author: 'ONYX AI',
        body: escalationText,
        occurredAtUtc: DateTime.now().toUtc(),
        roomKey: 'Residents',
        viewerRole: ClientAppViewerRole.client.name,
        incidentStatusLabel: 'Escalated',
        messageSource: 'telegram',
        messageProvider: 'ai_policy',
      );
      if (canNotifyAdmin) {
        await _sendTelegramMessageWithChunks(
          messageKeyPrefix: 'tg-admin-escalated-${update.updateId}',
          chatId: adminChatId,
          messageThreadId: adminThreadId,
          responseText:
              'ONYX AI escalation\n'
              'scope=${target.clientId}/$siteId\n'
              'chat=${update.chatId}${update.messageThreadId == null ? '' : '#${update.messageThreadId}'}\n'
              'from=${update.fromUsername?.trim().isNotEmpty == true ? '@${update.fromUsername!.trim()}' : (update.fromUserId?.toString() ?? 'unknown')}\n'
              'message=${_singleLine(trimmed)}',
          failureContext: 'Admin escalation relay',
        );
      }
      _telegramAiLastHandledAtUtc = DateTime.now().toUtc();
      _telegramAiLastHandledSummary = '${target.clientId}/$siteId • escalated';
      await _appendTelegramAiLedger(
        clientId: target.clientId,
        siteId: siteId,
        lane: 'client',
        action: 'escalated',
        inboundText: update.text,
        outboundText: escalationText,
        providerLabel: 'policy:high-risk',
        update: update,
      );
      return true;
    }
    final handledQuickAction = await _handleTelegramClientQuickAction(
      update: update,
      target: target,
      siteId: siteId,
    );
    if (handledQuickAction) {
      return true;
    }
    final handledStructuredCommand = await _handleTelegramStructuredCommand(
      update: update,
      target: target,
      siteId: siteId,
    );
    if (handledStructuredCommand) {
      return true;
    }
    final handledTrustReport = await _handleTelegramClientTrustReportRequest(
      update: update,
      target: target,
      siteId: siteId,
    );
    if (handledTrustReport) {
      return true;
    }
    final handledOnyxCommand = await _handleTelegramOnyxOperationalCommand(
      update: update,
      target: target,
      siteId: siteId,
    );
    if (handledOnyxCommand) {
      return true;
    }
    if (!_telegramAiAssistantEnabled) {
      return false;
    }
    final aiContext = await _telegramAiClientDraftingContextForScope(
      clientId: target.clientId,
      siteId: siteId,
      messageText: update.text,
      limit: 8,
    );
    _touchTelegramAiApprovedRewriteExamplesForScope(
      clientId: target.clientId,
      siteId: siteId,
      selectedExamples: aiContext.preferredReplyExamples,
    );
    String? siteAwarenessContext;
    TelegramAiSiteAwarenessSummary? siteAwarenessSummary;
    final siteAwarenessRow = await _readLatestSiteAwarenessSnapshotRow(
      siteId: siteId,
    );
    if (siteAwarenessRow != null &&
        _isSiteAwarenessSnapshotFresh(
          siteAwarenessRow,
          _telegramFlowNowUtc(),
        )) {
      siteAwarenessContext = await _formatTelegramAiSiteAwarenessContext(
        clientId: target.clientId,
        siteId: siteId,
        row: siteAwarenessRow,
      );
      siteAwarenessSummary = _telegramAiSiteAwarenessSummaryFromRow(
        siteAwarenessRow,
      );
    }
    TelegramAiDraftReply aiDraft;
    try {
      aiDraft = await _telegramAiAssistant
          .draftReply(
            audience: TelegramAiAudience.client,
            messageText: update.text,
            clientId: target.clientId,
            siteId: siteId,
            deliveryMode: _telegramAiApprovalRequired && canNotifyAdmin
                ? TelegramAiDeliveryMode.approvalDraft
                : TelegramAiDeliveryMode.telegramLive,
            clientProfileSignals: aiContext.clientProfileSignals,
            preferredReplyExamples: aiContext.preferredReplyExamples,
            preferredReplyStyleTags: aiContext.preferredReplyStyleTags,
            learnedReplyExamples: aiContext.learnedReplyExamples,
            learnedReplyStyleTags: aiContext.learnedReplyStyleTags,
            recentConversationTurns: aiContext.recentConversationTurns,
            cameraHealthFactPacket: aiContext.cameraHealthFactPacket,
            siteAwarenessContext: siteAwarenessContext,
            siteAwarenessSummary: siteAwarenessSummary,
          )
          .timeout(const Duration(seconds: 5));
    } on TimeoutException {
      final fallbackText = siteAwarenessRow != null
          ? await _telegramLiveStatusReply(
              clientId: target.clientId,
              siteId: siteId,
              prompt: update.text,
            )
          : 'Your message has been received. Our team will follow up shortly.';
      aiDraft = TelegramAiDraftReply(
        text: fallbackText,
        usedFallback: true,
        providerLabel: 'timeout-fallback',
      );
    }
    if (_telegramAiApprovalRequired && canNotifyAdmin) {
      final pending = _TelegramAiPendingDraft(
        inboundUpdateId: update.updateId,
        chatId: update.chatId,
        messageThreadId: update.messageThreadId,
        audience: 'client',
        clientId: target.clientId,
        siteId: siteId,
        sourceText: update.text.trim(),
        originalDraftText: aiDraft.text,
        draftText: aiDraft.text,
        providerLabel: aiDraft.providerLabel,
        usedLearnedApprovalStyle: aiDraft.usedLearnedApprovalStyle,
        createdAtUtc: DateTime.now().toUtc(),
      );
      _telegramAiPendingDrafts = <_TelegramAiPendingDraft>[
        pending,
        ..._telegramAiPendingDrafts.where(
          (entry) => entry.inboundUpdateId != pending.inboundUpdateId,
        ),
      ].take(100).toList(growable: false);
      _telegramAiLastHandledAtUtc = pending.createdAtUtc;
      _telegramAiLastHandledSummary = '${target.clientId}/$siteId • pending';
      await _appendTelegramConversationMessage(
        clientId: target.clientId,
        siteId: siteId,
        author: 'ONYX AI',
        body: 'Pending approval reply draft: ${aiDraft.text}',
        occurredAtUtc: pending.createdAtUtc,
        roomKey: 'Security Desk',
        viewerRole: ClientAppViewerRole.control.name,
        incidentStatusLabel: 'Pending Approval',
        messageSource: 'telegram',
        messageProvider: aiDraft.providerLabel,
      );
      await _sendTelegramMessageWithChunks(
        messageKeyPrefix: 'tg-admin-draft-${update.updateId}',
        chatId: adminChatId,
        messageThreadId: adminThreadId,
        responseText:
            'ONYX AI draft pending approval\n'
            'update_id=${pending.inboundUpdateId}\n'
            'scope=${pending.clientId}/${pending.siteId}\n'
            'chat=${pending.chatId}${pending.messageThreadId == null ? '' : '#${pending.messageThreadId}'}\n'
            'source=${_singleLine(pending.sourceText)}\n'
            'draft=${_singleLine(pending.draftText)}\n'
            'approve=/aiapprove ${pending.inboundUpdateId} • reject=/aireject ${pending.inboundUpdateId}',
        failureContext: 'Admin draft relay',
      );
      await _appendTelegramAiLedger(
        clientId: target.clientId,
        siteId: siteId,
        lane: 'client',
        action: 'draft_pending',
        inboundText: update.text,
        outboundText: aiDraft.text,
        providerLabel: aiDraft.providerLabel,
        update: update,
      );
      unawaited(_persistTelegramAdminRuntimeState());
      return true;
    }
    final delivered = await _sendTelegramMessageWithChunks(
      messageKeyPrefix: 'tg-client-ai-${update.updateId}',
      chatId: update.chatId,
      messageThreadId: update.messageThreadId,
      responseText: aiDraft.text,
      failureContext: 'Client AI response',
    );
    final nowUtc = DateTime.now().toUtc();
    _telegramAiLastHandledAtUtc = nowUtc;
    _telegramAiLastHandledSummary =
        '${target.clientId}/$siteId • ${delivered ? 'sent' : 'failed'}';
    await _appendTelegramConversationMessage(
      clientId: target.clientId,
      siteId: siteId,
      author: 'ONYX AI',
      body: aiDraft.text,
      occurredAtUtc: nowUtc,
      roomKey: delivered ? 'Residents' : 'Security Desk',
      viewerRole: delivered
          ? ClientAppViewerRole.client.name
          : ClientAppViewerRole.control.name,
      incidentStatusLabel: delivered ? 'Reply Sent' : 'Reply Failed',
      messageSource: 'telegram',
      messageProvider: aiDraft.providerLabel,
    );
    if (delivered) {
      await _appendCriticalTelegramClientReplyControlMirror(
        clientId: target.clientId,
        siteId: siteId,
        author: 'ONYX AI',
        body: aiDraft.text,
        occurredAtUtc: nowUtc,
        messageProvider: aiDraft.providerLabel,
      );
    }
    await _appendTelegramAiLedger(
      clientId: target.clientId,
      siteId: siteId,
      lane: 'client',
      action: delivered ? 'sent' : 'send_failed',
      inboundText: update.text,
      outboundText: aiDraft.text,
      providerLabel: aiDraft.providerLabel,
      update: update,
    );
    return true;
  }

  Future<bool> _handleTelegramClientTrustReportRequest({
    required TelegramBridgeInboundMessage update,
    required _TelegramInboundClientTarget target,
    required String siteId,
  }) async {
    if (!_isTelegramClientTrustReportRequest(update.text)) {
      return false;
    }
    final service = _clientTrustServiceOrNull;
    if (service == null) {
      return false;
    }
    final period = DateTimeRange(
      start: _telegramFlowNowUtc().subtract(const Duration(days: 30)),
      end: _telegramFlowNowUtc(),
    );
    final report = await service.getClientTrustReport(
      target.clientId,
      siteId,
      period,
    );
    final responseText = _formatClientTrustReportSummary(report);
    final nowUtc = _telegramFlowNowUtc();
    final delivered = await _sendTelegramMessageWithChunks(
      messageKeyPrefix: 'tg-client-trust-${update.updateId}',
      chatId: update.chatId,
      messageThreadId: update.messageThreadId,
      responseText: responseText,
      failureContext: 'Client trust report',
    );
    _telegramAiLastHandledAtUtc = nowUtc;
    _telegramAiLastHandledSummary =
        '${target.clientId}/$siteId • trust-report/${delivered ? 'sent' : 'failed'}';
    await _appendTelegramConversationMessage(
      clientId: target.clientId,
      siteId: siteId,
      author: 'ONYX AI',
      body: responseText,
      occurredAtUtc: nowUtc,
      roomKey: delivered ? 'Residents' : 'Security Desk',
      viewerRole: delivered
          ? ClientAppViewerRole.client.name
          : ClientAppViewerRole.control.name,
      incidentStatusLabel: delivered
          ? 'Trust Report Sent'
          : 'Trust Report Failed',
      messageSource: 'telegram',
      messageProvider: 'client_trust',
    );
    if (delivered) {
      await _appendCriticalTelegramClientReplyControlMirror(
        clientId: target.clientId,
        siteId: siteId,
        author: 'ONYX AI',
        body: responseText,
        occurredAtUtc: nowUtc,
        messageProvider: 'client_trust',
      );
    }
    _recordTelegramRecentPrompt(
      roomLabel: _deliverySiteLabelFor(
        clientId: target.clientId,
        siteId: siteId,
      ),
      scopeLabel: '${target.clientId} / $siteId',
      prompt: update.text,
      outcomeLabel: delivered ? 'trust report' : 'trust report failed',
      handledAtUtc: nowUtc,
    );
    await _appendTelegramAiLedger(
      clientId: target.clientId,
      siteId: siteId,
      lane: 'client',
      action: delivered ? 'trust_report_sent' : 'trust_report_failed',
      inboundText: update.text,
      outboundText: responseText,
      providerLabel: 'client_trust',
      update: update,
    );
    return true;
  }

  bool _isTelegramClientTrustReportRequest(String prompt) {
    final normalized = normalizeTelegramClientPromptSignalText(prompt);
    return normalized.contains('how am i doing') ||
        normalized.contains('how are we doing') ||
        normalized.contains('show my security report') ||
        normalized.contains('show security report') ||
        normalized.contains('security report') ||
        normalized.contains('trust report');
  }

  String _formatClientTrustReportSummary(OnyxClientTrustReport report) {
    final trendArrow = switch (report.saferScoreTrend) {
      'improving' => '↑ Improving',
      'declining' => '↓ Declining',
      _ => '→ Stable',
    };
    return [
      '🛡️ Your ONYX Security Report',
      'Period: ${report.periodLabel}',
      'Incidents handled: ${report.incidentsHandled}',
      'Avg response time: ${report.avgResponseSeconds.toStringAsFixed(1)}s',
      'False alarms reduced: ${report.falseAlarmsReduced.toStringAsFixed(0)}%',
      'Guard patrol compliance: ${report.guardPatrolCompliance.toStringAsFixed(0)}%',
      'System uptime: ${report.systemUptime.toStringAsFixed(1)}%',
      'Safety score: ${report.saferScore}/100 $trendArrow',
    ].join('\n');
  }

  Future<bool> _handleTelegramProactiveAlertCallback(
    TelegramBridgeInboundMessage update,
  ) async {
    final callbackId = (update.callbackQueryId ?? '').trim();
    final payload = update.text.trim();
    if (callbackId.isEmpty) {
      return false;
    }
    final callback = _parseTelegramProactiveAlertCallback(payload);
    if (callback == null) {
      return false;
    }
    if (callback.isMalformed) {
      await _answerTelegramCallbackSafe(
        callbackQueryId: callbackId,
        text: 'Alert action payload invalid.',
      );
      return true;
    }
    final nowUtc = DateTime.now().toUtc();
    if (callback.action == 'view') {
      await _handleTelegramViewAlertCallback(
        update: update,
        callback: callback,
        nowUtc: nowUtc,
      );
      return true;
    }
    final alert = callback.legacyTarget.trim().isNotEmpty
        ? await _latestActiveSiteAlertForCallbackTarget(
            callback.legacyTarget,
            siteId: callback.siteId,
          )
        : await _latestActiveSiteAlertForAlertId(
            callback.alertId,
            siteId: callback.siteId,
          );
    if (alert == null) {
      await _answerTelegramCallbackSafe(
        callbackQueryId: callbackId,
        text: 'Alert context expired.',
      );
      return true;
    }
    if (callback.action == 'dispatch') {
      await _handleTelegramDispatchAlertCallback(
        update: update,
        alert: alert,
        nowUtc: nowUtc,
      );
      return true;
    }
    if (callback.action == 'ack') {
      await _handleTelegramResolutionAlertCallback(
        update: update,
        alert: alert,
        nowUtc: nowUtc,
        falseAlarm: false,
      );
      return true;
    }
    if (callback.action == 'dismiss' || callback.action == 'false_alarm') {
      await _handleTelegramResolutionAlertCallback(
        update: update,
        alert: alert,
        nowUtc: nowUtc,
        falseAlarm: true,
      );
      return true;
    }
    final clientId = alert.clientId.trim().isEmpty
        ? _selectedClient
        : alert.clientId.trim();
    final siteId = alert.siteId.trim().isEmpty
        ? _selectedSite
        : alert.siteId.trim();
    final siteLabel = _deliverySiteLabelFor(clientId: clientId, siteId: siteId);
    final eventType = switch (callback.action) {
      'dispatch' => 'telegram_dispatch_requested',
      'ack' => 'telegram_acknowledged',
      'dismiss' => 'telegram_false_alarm',
      'false_alarm' => 'telegram_false_alarm',
      'armed_response' => 'telegram_armed_response',
      'keep_watching' => 'telegram_keep_watching',
      'all_good' => 'telegram_all_good',
      'i_see_them' => 'telegram_true_threat',
      'sound_warning' => 'telegram_sound_warning',
      'register_vehicle' => 'telegram_register_vehicle',
      'expected_vehicle' => 'telegram_expected_vehicle',
      _ => 'telegram_unknown_action',
    };
    await _recordTelegramAlertActionEvent(
      siteId: siteId,
      channelId: alert.channelId,
      zoneName: alert.zoneName,
      eventType: eventType,
      occurredAtUtc: nowUtc,
      rawPayload: <String, Object?>{
        'action': callback.action,
        'alert_id': alert.alertId,
        'site_id': siteId,
        'client_id': clientId,
        'operator_id': _telegramOutcomeOperatorId(update),
        'chat_id': update.chatId,
        'message_id': update.messageId,
      },
    );
    await _recordTelegramAlertOutcomeFeedback(
      alert: alert,
      action: callback.action,
      update: update,
    );
    await _answerTelegramCallbackSafe(
      callbackQueryId: callbackId,
      text: _telegramProactiveCallbackReply(
        action: callback.action,
        siteLabel: siteLabel,
      ),
    );
    return true;
  }

  Future<void> _handleTelegramViewAlertCallback({
    required TelegramBridgeInboundMessage update,
    required _TelegramProactiveAlertCallback callback,
    required DateTime nowUtc,
  }) async {
    final callbackId = (update.callbackQueryId ?? '').trim();
    final alert = callback.alertId.trim().isEmpty
        ? null
        : await _latestActiveSiteAlertForAlertId(
            callback.alertId,
            siteId: callback.siteId,
          );
    final siteId = callback.siteId.trim().isNotEmpty
        ? callback.siteId.trim()
        : (alert?.siteId.trim().isNotEmpty ?? false)
        ? alert!.siteId.trim()
        : _selectedSite.trim();
    final channelId = callback.channelId.trim().isNotEmpty
        ? callback.channelId.trim()
        : (alert?.channelId.trim().isNotEmpty ?? false)
        ? alert!.channelId.trim()
        : '0';
    final responseText =
        '📷 Camera $channelId — tap the RTSP link to view live: '
        '${_telegramCameraViewUrl(channelId)}';
    await _answerTelegramCallbackSafe(
      callbackQueryId: callbackId,
      text: responseText,
    );
    unawaited(
      _recordTelegramAlertActionEvent(
        siteId: siteId,
        channelId: channelId,
        zoneName: alert?.zoneName,
        eventType: 'telegram_view_camera',
        occurredAtUtc: nowUtc,
        rawPayload: <String, Object?>{
          'action': callback.action,
          'alert_id': callback.alertId.trim().isEmpty ? null : callback.alertId,
          'site_id': siteId,
          'channel_id': channelId,
          'operator_id': _telegramOutcomeOperatorId(update),
          'chat_id': update.chatId,
          'message_id': update.messageId,
        },
      ),
    );
    unawaited(
      _sendTelegramCameraViewReply(
        update: update,
        channelId: channelId,
        responseText: responseText,
      ),
    );
  }

  Future<void> _handleTelegramDispatchAlertCallback({
    required TelegramBridgeInboundMessage update,
    required _SiteAwarenessActiveAlertRecord alert,
    required DateTime nowUtc,
  }) async {
    final callbackId = (update.callbackQueryId ?? '').trim();
    final siteId = alert.siteId.trim().isEmpty ? _selectedSite : alert.siteId;
    try {
      await _insertTelegramDispatchRecord(alert: alert, nowUtc: nowUtc);
      await _recordTelegramAlertActionEvent(
        siteId: siteId,
        channelId: alert.channelId,
        zoneName: alert.zoneName,
        eventType: 'telegram_dispatch_requested',
        occurredAtUtc: nowUtc,
        rawPayload: <String, Object?>{
          'action': 'dispatch',
          'alert_id': alert.alertId,
          'site_id': siteId,
          'client_id': alert.clientId,
          'operator_id': _telegramOutcomeOperatorId(update),
          'chat_id': update.chatId,
          'message_id': update.messageId,
        },
      );
      await _recordTelegramAlertOutcomeFeedback(
        alert: alert,
        action: 'dispatch',
        update: update,
      );
      await _markSiteAwarenessAlertHandled(alert: alert, removeAlert: false);
      await _answerTelegramCallbackSafe(
        callbackQueryId: callbackId,
        text: '🚨 Dispatch logged for $siteId. Guard notified.',
      );
      await _appendTelegramAlertActionToOriginalMessage(
        update: update,
        actionLine:
            '🚨 Dispatch logged by operator — '
            '${_telegramCommandLocalTimeLabel(nowUtc)}',
        removeInlineKeyboard: true,
      );
    } catch (error, stackTrace) {
      developer.log(
        'Telegram dispatch callback persistence failed.',
        name: 'TelegramBridge',
        error: error,
        stackTrace: stackTrace,
      );
      await _answerTelegramCallbackSafe(
        callbackQueryId: callbackId,
        text: 'Dispatch could not be logged right now.',
      );
    }
  }

  Future<void> _handleTelegramResolutionAlertCallback({
    required TelegramBridgeInboundMessage update,
    required _SiteAwarenessActiveAlertRecord alert,
    required DateTime nowUtc,
    required bool falseAlarm,
  }) async {
    final callbackId = (update.callbackQueryId ?? '').trim();
    final action = falseAlarm ? 'dismiss' : 'ack';
    final eventType = falseAlarm
        ? 'telegram_false_alarm'
        : 'telegram_acknowledged';
    final successText = falseAlarm
        ? '🔕 Marked as false alarm.'
        : '✅ Acknowledged.';
    final failureText = falseAlarm
        ? 'False alarm could not be saved right now.'
        : 'Acknowledgement could not be saved right now.';
    try {
      await _updateTelegramEventRecord(
        alertId: alert.alertId,
        values: <String, Object?>{
          'status': falseAlarm ? 'false_alarm' : 'acknowledged',
          if (falseAlarm) 'resolved_at': nowUtc.toIso8601String(),
          if (!falseAlarm) 'acknowledged_at': nowUtc.toIso8601String(),
          if (!falseAlarm) 'acknowledged_by': 'telegram',
        },
      );
      await _recordTelegramAlertActionEvent(
        siteId: alert.siteId.trim().isEmpty ? _selectedSite : alert.siteId,
        channelId: alert.channelId,
        zoneName: alert.zoneName,
        eventType: eventType,
        occurredAtUtc: nowUtc,
        rawPayload: <String, Object?>{
          'action': action,
          'alert_id': alert.alertId,
          'site_id': alert.siteId,
          'client_id': alert.clientId,
          'operator_id': _telegramOutcomeOperatorId(update),
          'chat_id': update.chatId,
          'message_id': update.messageId,
        },
      );
      await _recordTelegramAlertOutcomeFeedback(
        alert: alert,
        action: falseAlarm ? 'dismiss' : 'ack',
        update: update,
      );
      await _markSiteAwarenessAlertHandled(
        alert: alert,
        removeAlert: falseAlarm,
      );
      await _answerTelegramCallbackSafe(
        callbackQueryId: callbackId,
        text: successText,
      );
      await _appendTelegramAlertActionToOriginalMessage(
        update: update,
        actionLine: falseAlarm
            ? '🔕 Marked as false alarm — ${_telegramCommandLocalTimeLabel(nowUtc)}'
            : '✅ Acknowledged by operator — ${_telegramCommandLocalTimeLabel(nowUtc)}',
        removeInlineKeyboard: true,
      );
    } catch (error, stackTrace) {
      developer.log(
        'Telegram alert resolution callback persistence failed.',
        name: 'TelegramBridge',
        error: error,
        stackTrace: stackTrace,
      );
      await _answerTelegramCallbackSafe(
        callbackQueryId: callbackId,
        text: failureText,
      );
    }
  }

  Future<void> _sendTelegramCameraViewReply({
    required TelegramBridgeInboundMessage update,
    required String channelId,
    required String responseText,
  }) async {
    final normalizedChannelId = channelId.trim();
    if (normalizedChannelId.isEmpty) {
      return;
    }
    final snapshotBytes = await _fetchProactiveAlertSnapshotBytes(
      normalizedChannelId,
    );
    final message = TelegramBridgeMessage(
      messageKey:
          'tg-view-camera-${update.updateId}-$normalizedChannelId-${DateTime.now().toUtc().millisecondsSinceEpoch}',
      chatId: update.chatId,
      messageThreadId: update.messageThreadId,
      replyToMessageId: update.messageId,
      text: snapshotBytes == null || snapshotBytes.isEmpty
          ? '📷 Camera $normalizedChannelId snapshot unavailable right now.\n$responseText'
          : responseText,
      photoBytes: snapshotBytes,
      photoFilename: snapshotBytes == null || snapshotBytes.isEmpty
          ? null
          : 'onyx-view-$normalizedChannelId.jpg',
      source: TelegramBridgeMessageSource.system,
      audience: TelegramBridgeMessageAudience.client,
    );
    final result = await _telegramBridge.sendMessages(messages: [message]);
    if (result.sentCount <= 0) {
      developer.log(
        'Telegram camera view follow-up failed for CH$normalizedChannelId.',
        name: 'TelegramBridge',
        error:
            result.failureReasonsByMessageKey[message.messageKey] ??
            'unknown failure',
      );
    }
  }

  Future<void> _answerTelegramCallbackSafe({
    required String callbackQueryId,
    required String text,
  }) async {
    if (callbackQueryId.trim().isEmpty) {
      return;
    }
    try {
      await _telegramBridge.answerCallbackQuery(
        callbackQueryId: callbackQueryId,
        text: text,
      );
    } catch (error, stackTrace) {
      developer.log(
        'Telegram answerCallbackQuery failed.',
        name: 'TelegramBridge',
        error: error,
        stackTrace: stackTrace,
      );
    }
  }

  Future<void> _insertTelegramDispatchRecord({
    required _SiteAwarenessActiveAlertRecord alert,
    required DateTime nowUtc,
  }) async {
    if (!widget.supabaseReady) {
      throw StateError('Supabase is not ready.');
    }
    await Supabase.instance.client.from('dispatches').insert(<String, Object?>{
      'site_id': alert.siteId.trim().isEmpty ? _selectedSite : alert.siteId,
      'event_id': alert.alertId,
      'triggered_by': 'telegram_button',
      'status': 'active',
      'created_at': nowUtc.toIso8601String(),
    });
  }

  Future<void> _updateTelegramEventRecord({
    required String alertId,
    required Map<String, Object?> values,
  }) async {
    if (!widget.supabaseReady) {
      throw StateError('Supabase is not ready.');
    }
    final client = Supabase.instance.client;
    var updated = false;
    Object? lastError;
    try {
      final byEventId = await client
          .from('events')
          .update(values)
          .eq('event_id', alertId.trim())
          .select('event_id');
      updated = byEventId.isNotEmpty;
    } catch (error) {
      lastError = error;
    }
    if (!updated) {
      try {
        final byId = await client
            .from('events')
            .update(values)
            .eq('id', alertId.trim())
            .select('id');
        updated = byId.isNotEmpty;
      } catch (error) {
        lastError = error;
      }
    }
    if (!updated) {
      throw lastError ??
          StateError('No matching event row found for $alertId.');
    }
  }

  Future<void> _markSiteAwarenessAlertHandled({
    required _SiteAwarenessActiveAlertRecord alert,
    required bool removeAlert,
  }) async {
    if (!widget.supabaseReady) {
      return;
    }
    try {
      final rows = await Supabase.instance.client
          .from('site_awareness_snapshots')
          .select('site_id,active_alerts')
          .eq(
            'site_id',
            alert.siteId.trim().isEmpty ? _selectedSite : alert.siteId,
          )
          .limit(1);
      if (rows.isEmpty) {
        return;
      }
      final row = Map<String, dynamic>.from(rows.first as Map);
      final rawAlerts = row['active_alerts'];
      if (rawAlerts is! List) {
        return;
      }
      final updatedAlerts = <Object?>[];
      for (final entry in rawAlerts) {
        if (entry is! Map) {
          updatedAlerts.add(entry);
          continue;
        }
        final alertMap = Map<String, Object?>.from(
          entry.cast<Object?, Object?>(),
        );
        final entryAlertId = (alertMap['alert_id'] ?? '').toString().trim();
        if (entryAlertId != alert.alertId.trim()) {
          updatedAlerts.add(alertMap);
          continue;
        }
        if (removeAlert) {
          continue;
        }
        updatedAlerts.add(<String, Object?>{
          ...alertMap,
          'is_acknowledged': true,
        });
      }
      await Supabase.instance.client
          .from('site_awareness_snapshots')
          .update(<String, Object?>{'active_alerts': updatedAlerts})
          .eq('site_id', row['site_id']);
    } catch (error, stackTrace) {
      developer.log(
        'Failed to update site awareness snapshot alert state.',
        name: 'TelegramBridge',
        error: error,
        stackTrace: stackTrace,
      );
    }
  }

  Future<void> _recordTelegramAlertOutcomeFeedback({
    required _SiteAwarenessActiveAlertRecord alert,
    required String action,
    required TelegramBridgeInboundMessage update,
  }) async {
    final outcome = _outcomeForTelegramAlertAction(action);
    if (outcome == null) {
      return;
    }
    final service = _outcomeFeedbackServiceOrNull;
    if (service == null) {
      return;
    }
    final clientId = alert.clientId.trim().isEmpty
        ? _selectedClient
        : alert.clientId.trim();
    final siteId = alert.siteId.trim().isEmpty
        ? _selectedSite
        : alert.siteId.trim();
    try {
      await service.recordOutcome(
        alert.alertId,
        outcome,
        _telegramOutcomeOperatorId(update),
        'Telegram quick action: $action',
        siteId: siteId,
        clientId: clientId,
        zoneId: (alert.zoneName ?? '').trim(),
        confidenceAtTime: alert.personConfidence,
        powerModeAtTime: alert.powerMode,
      );
    } catch (error, stackTrace) {
      developer.log(
        'ONYX outcome feedback persistence failed',
        name: 'OnyxOutcomeFeedback',
        error: error,
        stackTrace: stackTrace,
      );
    }
  }

  Future<void> _appendTelegramAlertActionToOriginalMessage({
    required TelegramBridgeInboundMessage update,
    required String actionLine,
    required bool removeInlineKeyboard,
  }) async {
    final messageId = update.messageId;
    final originalText = (update.messageText ?? '').trim();
    if (messageId == null || messageId <= 0 || originalText.isEmpty) {
      return;
    }
    final updatedText = _telegramAlertMessageWithActionLine(
      originalText: originalText,
      actionLine: actionLine,
    );
    final clearedMarkup = removeInlineKeyboard
        ? const <String, Object?>{
            'inline_keyboard': <List<Map<String, String>>>[],
          }
        : null;
    final edited = update.messageHasPhoto
        ? await _telegramBridge.editMessageCaption(
            chatId: update.chatId,
            messageId: messageId,
            caption: updatedText,
            replyMarkup: clearedMarkup,
          )
        : await _telegramBridge.editMessageText(
            chatId: update.chatId,
            messageId: messageId,
            text: updatedText,
            replyMarkup: clearedMarkup,
          );
    if (!edited) {
      developer.log(
        'Failed to edit Telegram alert message after callback action.',
        name: 'TelegramBridge',
        error:
            'chat=${update.chatId} message_id=$messageId has_photo=${update.messageHasPhoto}',
      );
    }
  }

  String _telegramAlertMessageWithActionLine({
    required String originalText,
    required String actionLine,
  }) {
    final normalizedOriginal = originalText.trimRight();
    final normalizedActionLine = actionLine.trim();
    if (normalizedOriginal.isEmpty || normalizedActionLine.isEmpty) {
      return normalizedOriginal;
    }
    final lines = normalizedOriginal
        .split('\n')
        .map((line) => line.trimRight())
        .toList(growable: false);
    if (lines.contains(normalizedActionLine)) {
      return normalizedOriginal;
    }
    return '$normalizedOriginal\n\n$normalizedActionLine';
  }

  String _telegramCameraViewUrl(String channelId) {
    final normalizedChannelId = channelId.trim().isEmpty
        ? '0'
        : channelId.trim();
    return 'http://192.168.0.67:11638/snapshot/$normalizedChannelId';
  }

  _TelegramProactiveAlertCallback? _parseTelegramProactiveAlertCallback(
    String payload,
  ) {
    final trimmed = payload.trim();
    if (trimmed.isEmpty) {
      return null;
    }
    if (trimmed.startsWith('oa|')) {
      final parts = trimmed
          .split('|')
          .map((part) => part.trim())
          .where((part) => part.isNotEmpty)
          .toList(growable: false);
      if (parts.length < 3) {
        return const _TelegramProactiveAlertCallback(
          action: '',
          malformed: true,
        );
      }
      return _TelegramProactiveAlertCallback(
        action: parts[1].toLowerCase(),
        legacyTarget: parts.sublist(2).join('|'),
      );
    }
    if (trimmed.startsWith('view:')) {
      final parts = trimmed.split(':');
      if (parts.length != 3) {
        return const _TelegramProactiveAlertCallback(
          action: '',
          malformed: true,
        );
      }
      return _TelegramProactiveAlertCallback(
        action: 'view',
        alertId: parts[1].trim(),
        channelId: parts[2].trim(),
        malformed: parts[1].trim().isEmpty || parts[2].trim().isEmpty,
      );
    }
    if (trimmed.startsWith('dispatch:')) {
      final parts = trimmed.split(':');
      if (parts.length != 3) {
        return const _TelegramProactiveAlertCallback(
          action: '',
          malformed: true,
        );
      }
      return _TelegramProactiveAlertCallback(
        action: 'dispatch',
        alertId: parts[1].trim(),
        siteId: parts[2].trim(),
        malformed: parts[1].trim().isEmpty || parts[2].trim().isEmpty,
      );
    }
    if (trimmed.startsWith('ack:')) {
      final alertId = trimmed.substring('ack:'.length).trim();
      return _TelegramProactiveAlertCallback(
        action: 'ack',
        alertId: alertId,
        malformed: alertId.isEmpty,
      );
    }
    if (trimmed.startsWith('dismiss:')) {
      final alertId = trimmed.substring('dismiss:'.length).trim();
      return _TelegramProactiveAlertCallback(
        action: 'dismiss',
        alertId: alertId,
        malformed: alertId.isEmpty,
      );
    }
    if (trimmed.startsWith('view_cam_')) {
      final raw = trimmed.substring('view_cam_'.length);
      final separator = raw.indexOf('_');
      if (separator <= 0 || separator >= raw.length - 1) {
        return const _TelegramProactiveAlertCallback(
          action: '',
          malformed: true,
        );
      }
      return _TelegramProactiveAlertCallback(
        action: 'view',
        channelId: raw.substring(0, separator),
        siteId: raw.substring(separator + 1),
      );
    }
    if (trimmed.startsWith('dispatch_')) {
      final raw = trimmed.substring('dispatch_'.length);
      final separator = raw.lastIndexOf('_');
      if (separator <= 0 || separator >= raw.length - 1) {
        return const _TelegramProactiveAlertCallback(
          action: '',
          malformed: true,
        );
      }
      return _TelegramProactiveAlertCallback(
        action: 'dispatch',
        siteId: raw.substring(0, separator),
        alertId: raw.substring(separator + 1),
      );
    }
    if (trimmed.startsWith('ack_')) {
      final alertId = trimmed.substring('ack_'.length).trim();
      return _TelegramProactiveAlertCallback(
        action: 'ack',
        alertId: alertId,
        malformed: alertId.isEmpty,
      );
    }
    if (trimmed.startsWith('dismiss_')) {
      final alertId = trimmed.substring('dismiss_'.length).trim();
      return _TelegramProactiveAlertCallback(
        action: 'dismiss',
        alertId: alertId,
        malformed: alertId.isEmpty,
      );
    }
    return null;
  }

  Future<_SiteAwarenessActiveAlertRecord?>
  _latestActiveSiteAlertForCallbackTarget(
    String target, {
    String siteId = '',
  }) async {
    final normalizedTarget = target.trim();
    if (normalizedTarget.isEmpty) {
      return null;
    }
    final normalizedSiteId = siteId.trim();
    final row = await _readLatestSiteAwarenessSnapshotRow(
      siteId: normalizedSiteId.isEmpty ? _selectedSite : normalizedSiteId,
    );
    if (row == null) {
      return _latestActiveSiteAlertForAlertId(
        normalizedTarget,
        siteId: normalizedSiteId,
      );
    }
    final alerts = _siteAwarenessActiveAlertsFromRow(row);
    for (final alert in alerts) {
      if (alert.alertId == normalizedTarget) {
        return alert;
      }
    }
    for (final alert in alerts) {
      if (alert.channelId.trim() == normalizedTarget) {
        return alert;
      }
    }
    return _latestActiveSiteAlertForAlertId(
      normalizedTarget,
      siteId: normalizedSiteId,
    );
  }

  Future<_SiteAwarenessActiveAlertRecord?> _latestActiveSiteAlertForAlertId(
    String alertId, {
    String siteId = '',
  }) async {
    final normalizedAlertId = alertId.trim();
    if (normalizedAlertId.isEmpty || !widget.supabaseReady) {
      return null;
    }
    try {
      final normalizedSiteId = siteId.trim();
      final rows = normalizedSiteId.isEmpty
          ? await Supabase.instance.client
                .from('site_awareness_snapshots')
                .select('site_id,client_id,snapshot_at,active_alerts')
                .order('snapshot_at', ascending: false)
                .limit(24)
          : await Supabase.instance.client
                .from('site_awareness_snapshots')
                .select('site_id,client_id,snapshot_at,active_alerts')
                .eq('site_id', normalizedSiteId)
                .order('snapshot_at', ascending: false)
                .limit(4);
      final latestRowsBySite = <String, Map<String, dynamic>>{};
      for (final rawRow in rows) {
        final row = Map<String, dynamic>.from(rawRow as Map);
        final rowSiteId = (row['site_id'] ?? '').toString().trim();
        if (rowSiteId.isEmpty || latestRowsBySite.containsKey(rowSiteId)) {
          continue;
        }
        latestRowsBySite[rowSiteId] = row;
      }
      for (final row in latestRowsBySite.values) {
        final alerts = _siteAwarenessActiveAlertsFromRow(row);
        for (final alert in alerts) {
          if (alert.alertId.trim() == normalizedAlertId) {
            return alert;
          }
        }
      }
    } catch (error, stackTrace) {
      developer.log(
        'Failed to resolve Telegram proactive alert callback context.',
        name: 'TelegramBridge',
        error: error,
        stackTrace: stackTrace,
      );
    }
    return null;
  }

  OnyxAlertOutcome? _outcomeForTelegramAlertAction(String action) {
    return switch (action.trim().toLowerCase()) {
      'dispatch' => OnyxAlertOutcome.armedResponse,
      'dismiss' => OnyxAlertOutcome.falseAlarm,
      'false_alarm' => OnyxAlertOutcome.falseAlarm,
      'armed_response' => OnyxAlertOutcome.armedResponse,
      'keep_watching' => OnyxAlertOutcome.unknown,
      'all_good' => OnyxAlertOutcome.falseAlarm,
      'i_see_them' => OnyxAlertOutcome.trueThreat,
      _ => null,
    };
  }

  String _telegramOutcomeOperatorId(TelegramBridgeInboundMessage update) {
    final userId = update.fromUserId?.toString().trim() ?? '';
    if (userId.isNotEmpty) {
      return 'tg:$userId';
    }
    final username = update.fromUsername?.trim() ?? '';
    if (username.isNotEmpty) {
      return '@$username';
    }
    return _operatorId.trim().isEmpty ? 'ONYX-OPERATOR' : _operatorId.trim();
  }

  String _telegramProactiveCallbackReply({
    required String action,
    required String siteLabel,
  }) {
    return switch (action.trim().toLowerCase()) {
      'dispatch' => 'Dispatch tagged for $siteLabel.',
      'ack' => 'Alert acknowledged for $siteLabel.',
      'dismiss' => 'False alarm tagged for $siteLabel.',
      'false_alarm' => 'False alarm tagged for $siteLabel.',
      'armed_response' => 'Armed response tagged for $siteLabel.',
      'keep_watching' => 'Keep watching noted for $siteLabel.',
      'all_good' => 'All good tagged for $siteLabel.',
      'i_see_them' => 'Threat confirmed for $siteLabel.',
      'sound_warning' => 'Sound warning noted for $siteLabel.',
      'register_vehicle' => 'Vehicle registration noted for $siteLabel.',
      'expected_vehicle' => 'Expected vehicle noted for $siteLabel.',
      _ => 'Action recorded for $siteLabel.',
    };
  }

  Future<String?> _weeklySignalAccuracySummaryOrNull({
    required String siteId,
    required String siteLabel,
  }) async {
    final service = _outcomeFeedbackServiceOrNull;
    if (service == null || siteId.trim().isEmpty) {
      return null;
    }
    try {
      final snapshot = await service.getSignalAccuracy(siteId);
      final falsePercent = (snapshot.falseAlarmRate * 100).toStringAsFixed(0);
      final truePercent = (snapshot.trueThreatRate * 100).toStringAsFixed(0);
      final topNoiseZone = snapshot.topFalsePositiveZones.isEmpty
          ? 'none'
          : snapshot.topFalsePositiveZones.first;
      final adjustedEntry =
          snapshot.zoneThresholds.entries
              .where((entry) => (entry.value - 0.55).abs() >= 0.001)
              .toList(growable: false)
            ..sort(
              (left, right) => (right.value - 0.55).abs().compareTo(
                (left.value - 0.55).abs(),
              ),
            );
      final adjustmentLabel = adjustedEntry.isEmpty
          ? 'none'
          : '${adjustedEntry.first.key} → ${adjustedEntry.first.value.toStringAsFixed(2)}';
      return [
        '📊 Signal Accuracy — $siteLabel',
        'False alarm rate: $falsePercent%',
        'True threat rate: $truePercent%',
        'Top noise zone: $topNoiseZone',
        'Threshold auto-adjusted: $adjustmentLabel',
      ].join('\n');
    } catch (error, stackTrace) {
      developer.log(
        'ONYX weekly signal accuracy summary failed',
        name: 'OnyxOutcomeFeedback',
        error: error,
        stackTrace: stackTrace,
      );
      return null;
    }
  }

  Future<bool> _handleTelegramOnyxOperationalCommand({
    required TelegramBridgeInboundMessage update,
    required _TelegramInboundClientTarget target,
    required String siteId,
  }) async {
    final recentThreadContextTexts =
        await _telegramOperationalRecentContextTexts(
          clientId: target.clientId,
          siteId: siteId,
          currentPrompt: update.text,
          currentAuthor: _telegramInboundAuthor(update),
          currentOccurredAtUtc: update.sentAtUtc,
        );
    if (shouldPreferTelegramAiOverOnyxCommand(
      prompt: update.text,
      recentContextTexts: recentThreadContextTexts,
    )) {
      return false;
    }
    final cameraHealthFactPacket = await _cameraHealthFactPacketForScope(
      clientId: target.clientId,
      siteId: siteId,
    );
    final response = _onyxTelegramOperationalCommandService.handle(
      request: OnyxTelegramCommandRequest(
        telegramUserId:
            update.fromUserId?.toString() ?? _telegramInboundAuthor(update),
        telegramGroupId: update.chatId,
        role: OnyxAuthorityRole.client,
        prompt: update.text,
        groupBinding: TelegramScopeBinding(
          telegramGroupId: update.chatId,
          allowedClientIds: {target.clientId},
          allowedSiteIds: {siteId},
        ),
        userAllowedClientIds: {target.clientId},
        userAllowedSiteIds: {siteId},
        requestedClientId: target.clientId,
        requestedSiteId: siteId,
        requestedClientLabel: target.clientId,
        requestedSiteLabel: _deliverySiteLabelFor(
          clientId: target.clientId,
          siteId: siteId,
        ),
        replyToText: update.replyToText,
        recentThreadContextTexts: recentThreadContextTexts,
      ),
      events: store.allEvents(),
      cameraHealthFactPacket: cameraHealthFactPacket,
    );
    if (!response.handled) {
      return false;
    }

    final renderedResponseText = response.allowed
        ? response.text
        : _telegramOperationalDeniedReply(
            role: OnyxAuthorityRole.client,
            intent: response.intent,
            baseText: response.text,
          );
    final nowUtc = DateTime.now().toUtc();
    final delivered = await _sendTelegramMessageWithChunks(
      messageKeyPrefix: 'tg-client-onyx-${update.updateId}',
      chatId: update.chatId,
      messageThreadId: update.messageThreadId,
      responseText: renderedResponseText,
      failureContext: 'Client ONYX operational command',
    );
    _telegramAiLastHandledAtUtc = nowUtc;
    _telegramAiLastHandledSummary =
        '${target.clientId}/$siteId • onyx-command/${response.allowed ? (delivered ? 'sent' : 'failed') : 'denied'}';
    await _appendTelegramConversationMessage(
      clientId: target.clientId,
      siteId: siteId,
      author: 'ONYX',
      body: renderedResponseText,
      occurredAtUtc: nowUtc,
      roomKey: delivered ? 'Residents' : 'Security Desk',
      viewerRole: delivered
          ? ClientAppViewerRole.client.name
          : ClientAppViewerRole.control.name,
      incidentStatusLabel: response.allowed ? 'ONYX Answer' : 'Access Denied',
      messageSource: 'telegram',
      messageProvider: 'onyx_command',
    );
    if (delivered && response.allowed) {
      await _appendCriticalTelegramClientReplyControlMirror(
        clientId: target.clientId,
        siteId: siteId,
        author: 'ONYX',
        body: renderedResponseText,
        occurredAtUtc: nowUtc,
        messageProvider: 'onyx_command',
      );
    }
    _recordTelegramRecentPrompt(
      roomLabel: _deliverySiteLabelFor(
        clientId: target.clientId,
        siteId: siteId,
      ),
      scopeLabel: '${target.clientId} / $siteId',
      prompt: update.text,
      outcomeLabel: response.allowed
          ? (delivered ? 'answered' : 'send failed')
          : 'denied',
      handledAtUtc: nowUtc,
    );
    await _appendTelegramAiLedger(
      clientId: target.clientId,
      siteId: siteId,
      lane: 'client',
      action: response.allowed
          ? (delivered ? 'onyx_command_answered' : 'onyx_command_send_failed')
          : 'onyx_command_denied',
      inboundText: update.text,
      outboundText: renderedResponseText,
      providerLabel: 'onyx-command',
      update: update,
    );
    return true;
  }

  Future<bool> _handleTelegramStructuredCommand({
    required TelegramBridgeInboundMessage update,
    required _TelegramInboundClientTarget target,
    required String siteId,
  }) async {
    final commandType = _telegramCommandRouter.classify(update.text);
    if (commandType == OnyxTelegramCommandType.unknown) {
      return false;
    }
    final responseText = await _telegramStructuredReplyForCommand(
      commandType: commandType,
      update: update,
      target: target,
      siteId: siteId,
    );
    final trimmedResponse = responseText.trim();
    if (trimmedResponse.isEmpty) {
      return false;
    }
    final providerLabel = 'command_router:${commandType.name}';
    final nowUtc = _telegramFlowNowUtc();
    final delivered = await _sendTelegramMessageWithChunks(
      messageKeyPrefix:
          'tg-client-router-${commandType.name}-${update.updateId}',
      chatId: update.chatId,
      messageThreadId: update.messageThreadId,
      responseText: trimmedResponse,
      failureContext: 'Client structured Telegram response',
    );
    if (delivered && commandType == OnyxTelegramCommandType.liveStatus) {
      await _maybeSendTelegramStatusVoiceMessage(
        chatId: update.chatId,
        messageThreadId: update.messageThreadId,
        clientId: target.clientId,
        siteId: siteId,
        endpointRole: target.endpointRole,
        fallbackText: trimmedResponse,
        sourceLabel: 'command_router',
      );
    }
    _telegramAiLastHandledAtUtc = nowUtc;
    _telegramAiLastHandledSummary =
        '${target.clientId}/$siteId • ${commandType.name}/${delivered ? 'sent' : 'failed'}';
    await _appendTelegramConversationMessage(
      clientId: target.clientId,
      siteId: siteId,
      author: 'ONYX',
      body: trimmedResponse,
      occurredAtUtc: nowUtc,
      roomKey: delivered ? 'Residents' : 'Security Desk',
      viewerRole: delivered
          ? ClientAppViewerRole.client.name
          : ClientAppViewerRole.control.name,
      incidentStatusLabel: delivered
          ? _telegramStructuredStatusLabel(commandType)
          : 'Structured Reply Failed',
      messageSource: 'telegram',
      messageProvider: providerLabel,
    );
    if (delivered) {
      final controlMirrorBody =
          commandType == OnyxTelegramCommandType.liveStatus
          ? await _telegramLiveStatusReply(
              clientId: target.clientId,
              siteId: siteId,
              audienceRole: ClientAppViewerRole.control.name,
              prompt: update.text,
            )
          : trimmedResponse;
      await _appendCriticalTelegramClientReplyControlMirror(
        clientId: target.clientId,
        siteId: siteId,
        author: 'ONYX',
        body: controlMirrorBody,
        occurredAtUtc: nowUtc,
        messageProvider: providerLabel,
      );
    }
    _recordTelegramRecentPrompt(
      roomLabel: _deliverySiteLabelFor(
        clientId: target.clientId,
        siteId: siteId,
      ),
      scopeLabel: '${target.clientId} / $siteId',
      prompt: update.text,
      outcomeLabel: delivered ? commandType.name : '${commandType.name} failed',
      handledAtUtc: nowUtc,
    );
    await _appendTelegramAiLedger(
      clientId: target.clientId,
      siteId: siteId,
      lane: 'client',
      action: delivered
          ? 'router_${commandType.name}_sent'
          : 'router_${commandType.name}_failed',
      inboundText: update.text,
      outboundText: trimmedResponse,
      providerLabel: providerLabel,
      update: update,
    );
    return true;
  }

