        _telegramFrOnboardingReply(update.text),
      ),
      OnyxTelegramCommandType.clientStatement => Future<String>.value(
        _telegramClientStatementAcknowledgement(update.text),
      ),
      OnyxTelegramCommandType.unknown => Future<String>.value(''),
    };
  }

  Future<String> _telegramVisitorRegistrationReply({
    required String siteId,
    required String prompt,
  }) async {
    if (_telegramVisitorDepartureRequested(prompt)) {
      try {
        await _deactivateOnDemandExpectedVisitors(siteId: siteId);
        return 'Visitor access removed.\nNormal monitoring resumed.';
      } catch (error, stackTrace) {
        developer.log(
          'Failed to remove expected visitor registration for $siteId.',
          name: 'OnyxTelegramVisitorRegistration',
          error: error,
          stackTrace: stackTrace,
        );
        return 'I could not remove visitor access just now, so the current visitor window is still active.';
      }
    }
    final confirmedResidents = await _recordManualVehiclePresenceConfirmation(
      siteId: siteId,
      prompt: prompt,
    );
    if (confirmedResidents.isNotEmpty) {
      final names = confirmedResidents
          .map(_vehiclePresenceOwnerLabel)
          .toList(growable: false);
      final joinedNames = names.length == 1
          ? names.first
          : '${names.take(names.length - 1).join(', ')} and ${names.last}';
      return 'Got it. I\'ve marked $joinedNames as on site.\n'
          'Vehicle presence has been confirmed by the resident.\n'
          'Let me know when they leave or if anything seems unusual.';
    }
    final registration = _telegramExpectedVisitorRegistrationForPrompt(prompt);
    if (registration == null) {
      return 'Noted. I can expect a cleaner, gardener, contractor, delivery, or visitor on site today if you want me to suppress normal daytime movement.';
    }
    try {
      await _insertTemporaryExpectedVisitor(
        siteId: siteId,
        registration: registration,
      );
      return 'Got it. Visitor access noted until '
          '${_telegramExpectedVisitorUntilLabel(registration.visitEnd)}.\n'
          "I won't alert for movement until then.\n"
          'Let me know when they leave.';
    } catch (error, stackTrace) {
      developer.log(
        'Failed to create expected visitor registration for $siteId.',
        name: 'OnyxTelegramVisitorRegistration',
        error: error,
        stackTrace: stackTrace,
      );
      return 'I could not save that visitor schedule just now, so normal monitoring remains active.';
    }
  }

  String _telegramFrOnboardingReply(String prompt) {
    final name = _telegramFrOnboardingName(prompt);
    final subject = name ?? 'someone';
    return 'To add $subject to ONYX recognition:\n'
        '1. Send me 3-5 clear photos of $subject\'s face\n'
        "2. I'll enroll them automatically\n"
        '3. ONYX will then recognise them on site\n\n'
        'Photos should be well-lit, face clearly visible, different angles preferred.';
  }

  String _telegramClientStatementAcknowledgement(String rawText) {
    final n = rawText.trim().toLowerCase();
    // Visitor / arrival announcement
    if (n.contains('visitor') ||
        n.contains('coming') ||
        n.contains('arriving') ||
        n.contains('dropping by')) {
      // Try to pull a time hint ("at 8pm", "tonight", "in an hour", etc.)
      final timeHint = _extractTimeHint(n);
      return timeHint != null
          ? 'Noted. I\'ll flag any unrecognised arrivals $timeHint. '
                'Let me know if you need anything specific.'
          : 'Noted. I\'ll flag any unrecognised arrivals. '
                'Let me know if you need anything specific.';
    }
    // Everyone / all residents home
    if (n.contains('everyone') ||
        n.contains('all home') ||
        n.contains('all residents') ||
        n.contains('everybody')) {
      return 'Understood — all residents accounted for. Monitoring continues.';
    }
    // Identity context — "is my dad", "are my kids", "that was my partner"
    if (n.contains(' is my ') ||
        n.contains(' are my ') ||
        n.contains(' is our ') ||
        n.contains(' are our ') ||
        n.contains('that was my') ||
        n.contains('that was our')) {
      return 'Got it, noted. Thanks for letting me know — '
          'I\'ll keep that in mind. Let me know if you need anything.';
    }
    // Generic informational statement
    return 'Noted. Thanks for the update — '
        'I\'ll keep that in mind. Let me know if you need anything specific.';
  }

  /// Extracts a brief time reference from a statement, e.g. "at 8pm" or "tonight".
  String? _extractTimeHint(String normalized) {
    final atPattern = RegExp(r'\bat\s+\d+(?::\d+)?\s*(?:am|pm)?');
    final match = atPattern.firstMatch(normalized);
    if (match != null) {
      return match.group(0)?.trim();
    }
    for (final hint in const <String>[
      'tonight',
      'this evening',
      'this afternoon',
      'this morning',
      'later today',
      'in an hour',
      'shortly',
    ]) {
      if (normalized.contains(hint)) return hint;
    }
    return null;
  }

  _TelegramExpectedVisitorRegistration?
  _telegramExpectedVisitorRegistrationForPrompt(String prompt) {
    final trimmed = prompt.trim();
    final normalized = trimmed.toLowerCase();
    if (normalized.isEmpty) {
      return null;
    }
    final nowLocal = _telegramFlowNowLocal();
    final targetDate = normalized.contains('tomorrow')
        ? DateTime(nowLocal.year, nowLocal.month, nowLocal.day + 1)
        : DateTime(nowLocal.year, nowLocal.month, nowLocal.day);
    final startDateTimeLocal = normalized.contains('tomorrow')
        ? DateTime(targetDate.year, targetDate.month, targetDate.day, 8)
        : nowLocal;
    final endDateTimeLocal = _telegramExpectedVisitorEndDateTimeLocal(
      prompt: trimmed,
      normalized: normalized,
      targetDateLocal: targetDate,
      startDateTimeLocal: startDateTimeLocal,
    );
    final visitorName = _telegramExpectedVisitorNameForPrompt(
      prompt: trimmed,
      normalized: normalized,
    );
    return _TelegramExpectedVisitorRegistration(
      visitorName: visitorName,
      visitorRole: 'visitor',
      visitType: 'on_demand',
      targetDateLocal: targetDate,
      visitStart: _telegramClockLabel(startDateTimeLocal),
      visitEnd: _telegramClockLabel(endDateTimeLocal),
      expiresAtUtc: endDateTimeLocal.toUtc(),
    );
  }

  bool _telegramVisitorDepartureRequested(String prompt) {
    final normalized = prompt.trim().toLowerCase();
    if (normalized.isEmpty) {
      return false;
    }
    return normalized.contains('leaving now') ||
        normalized.contains('cleaner leaving') ||
        normalized.contains('visitor gone') ||
        normalized.contains('just left') ||
        normalized.contains('gone now');
  }

  String _telegramExpectedVisitorNameForPrompt({
    required String prompt,
    required String normalized,
  }) {
    if (normalized.contains('cleaner')) {
      return 'Cleaner';
    }
    if (normalized.contains('gardener')) {
      return 'Gardener';
    }
    if (normalized.contains('contractor')) {
      return 'Contractor';
    }
    if (normalized.contains('delivery')) {
      return 'Delivery';
    }
    if (normalized.contains('visitor')) {
      return 'Visitor';
    }
    final patterns = <RegExp>[
      RegExp(
        r"^\s*([A-Za-z][A-Za-z'-]*(?:\s+[A-Za-z][A-Za-z'-]*)?)\s+is\s+here\b",
        caseSensitive: false,
      ),
      RegExp(
        r"^\s*([A-Za-z][A-Za-z'-]*(?:\s+[A-Za-z][A-Za-z'-]*)?)\s+just\s+arrived\b",
        caseSensitive: false,
      ),
      RegExp(
        r"^\s*([A-Za-z][A-Za-z'-]*(?:\s+[A-Za-z][A-Za-z'-]*)?)\s+came\s+in\b",
        caseSensitive: false,
      ),
      RegExp(
        r"letting in\s+([A-Za-z][A-Za-z'-]*(?:\s+[A-Za-z][A-Za-z'-]*)?)",
        caseSensitive: false,
      ),
      RegExp(
        r"opening for\s+([A-Za-z][A-Za-z'-]*(?:\s+[A-Za-z][A-Za-z'-]*)?)",
        caseSensitive: false,
      ),
    ];
    for (final pattern in patterns) {
      final match = pattern.firstMatch(prompt);
      if (match != null) {
        final candidate = (match.group(1) ?? '').trim();
        if (candidate.isNotEmpty) {
          return _telegramHumanizedPersonName(candidate);
        }
      }
    }
    return 'Visitor';
  }

  DateTime _telegramExpectedVisitorEndDateTimeLocal({
    required String prompt,
    required String normalized,
    required DateTime targetDateLocal,
    required DateTime startDateTimeLocal,
  }) {
    final durationMatch = RegExp(
      r'\bfor\s+(\d+)\s+hours?\b',
    ).firstMatch(normalized);
    if (durationMatch != null) {
      final hours = int.tryParse(durationMatch.group(1) ?? '');
      if (hours != null && hours > 0) {
        return startDateTimeLocal.add(Duration(hours: hours));
      }
    }
    if (normalized.contains('until lunchtime') ||
        normalized.contains('until lunch')) {
      return DateTime(
        targetDateLocal.year,
        targetDateLocal.month,
        targetDateLocal.day,
        13,
      );
    }
    final untilPattern = RegExp(
      r'until\s+(\d{1,2})(?::(\d{2}))?\s*(am|pm)?',
      caseSensitive: false,
    );
    final untilMatch = untilPattern.firstMatch(prompt);
    if (untilMatch != null) {
      var hour = int.tryParse(untilMatch.group(1) ?? '') ?? 17;
      final minute = int.tryParse(untilMatch.group(2) ?? '') ?? 0;
      final meridiem = (untilMatch.group(3) ?? '').toLowerCase();
      if (meridiem == 'pm' && hour < 12) {
        hour += 12;
      } else if (meridiem == 'am' && hour == 12) {
        hour = 0;
      }
      if (hour >= 0 && hour <= 23 && minute >= 0 && minute <= 59) {
        final parsed = DateTime(
          targetDateLocal.year,
          targetDateLocal.month,
          targetDateLocal.day,
          hour,
          minute,
        );
        if (!parsed.isBefore(startDateTimeLocal)) {
          return parsed;
        }
      }
    }
    final defaultEnd = DateTime(
      targetDateLocal.year,
      targetDateLocal.month,
      targetDateLocal.day,
      17,
    );
    if (!defaultEnd.isBefore(startDateTimeLocal)) {
      return defaultEnd;
    }
    return DateTime(
      targetDateLocal.year,
      targetDateLocal.month,
      targetDateLocal.day,
      23,
      59,
    );
  }

  String? _telegramFrOnboardingName(String prompt) {
    final trimmed = prompt.trim();
    if (trimmed.isEmpty) {
      return null;
    }
    final patterns = <RegExp>[
      RegExp(r'add\s+(.+?)\s+to\s+(?:the\s+)?system', caseSensitive: false),
      RegExp(
        r'register\s+(.+?)\s+as\s+(?:a\s+)?(?:resident|staff|guard|regular visitor)',
        caseSensitive: false,
      ),
      RegExp(r'enroll\s+(.+?)\s+in\s+(?:the\s+)?system', caseSensitive: false),
      RegExp(r'enrol\s+(.+?)\s+in\s+(?:the\s+)?system', caseSensitive: false),
    ];
    for (final pattern in patterns) {
      final match = pattern.firstMatch(trimmed);
      if (match != null) {
        final candidate = (match.group(1) ?? '').trim();
        if (candidate.isNotEmpty) {
          return _telegramHumanizedPersonName(candidate);
        }
      }
    }
    return null;
  }

  String _telegramHumanizedPersonName(String raw) {
    return raw
        .split(RegExp(r'\s+'))
        .where((part) => part.trim().isNotEmpty)
        .map(
          (part) =>
              '${part[0].toUpperCase()}${part.substring(1).toLowerCase()}',
        )
        .join(' ');
  }

  Future<String> _formatTelegramAiSiteAwarenessContext({
    required String clientId,
    required String siteId,
    required Map<String, dynamic> row,
  }) async {
    final base = _formatSiteAwarenessSnapshot(row);
    final frPresenceLine = await _telegramRecentFrPresenceLine(
      clientId: clientId,
      siteId: siteId,
      audienceRole: 'ai',
    );
    if (frPresenceLine == null || frPresenceLine.trim().isEmpty) {
      return base;
    }
    return '$base\n- Recent recognised people: $frPresenceLine';
  }

  Future<String?> _telegramRecentFrPresenceLine({
    required String clientId,
    required String siteId,
    required String audienceRole,
  }) async {
    final registry = await _frService.loadRegistry(siteId);
    if (registry.isEmpty) {
      return null;
    }
    final recentEvents = _recentFrEventsForScope(
      clientId: clientId,
      siteId: siteId,
    );
    if (recentEvents.isEmpty) {
      return null;
    }
    final normalizedAudience = audienceRole.trim().toLowerCase();
    final lines = <String>[];
    final seenMatchIds = <String>{};
    for (final event in recentEvents) {
      final faceMatchId = (event.faceMatchId ?? '').trim().toUpperCase();
      if (faceMatchId.isEmpty || !seenMatchIds.add(faceMatchId)) {
        continue;
      }
      final context = await _frService.resolveMatch(
        siteId: siteId,
        personId: faceMatchId,
        observedAtUtc: event.occurredAt.toUtc(),
        timezone: 'Africa/Johannesburg',
      );
      if (context == null) {
        continue;
      }
      final location = _frLocationLabelForEvent(event);
      if (normalizedAudience == ClientAppViewerRole.control.name) {
        lines.add(
          '${context.audienceLabel(OnyxFrAudience.controller)} detected near $location.',
        );
      } else if (normalizedAudience == 'ai') {
        lines.add(
          '${context.audienceLabel(OnyxFrAudience.ai)} (${context.person.role}) detected near $location.',
        );
      } else {
        lines.add(
          '${context.audienceLabel(OnyxFrAudience.client)} detected near $location.',
        );
      }
      if (lines.length >= 2) {
        break;
      }
    }
    if (lines.isEmpty) {
      return null;
    }
    return lines.join(' ');
  }

  Future<List<_TelegramFrPresenceStatus>> _telegramRecentFrPresenceStatuses({
    required String clientId,
    required String siteId,
  }) async {
    final recentEvents = _recentFrEventsForScope(
      clientId: clientId,
      siteId: siteId,
    );
    if (recentEvents.isEmpty) {
      return const <_TelegramFrPresenceStatus>[];
    }
    final statuses = <_TelegramFrPresenceStatus>[];
    final seenMatchIds = <String>{};
    for (final event in recentEvents) {
      final faceMatchId = (event.faceMatchId ?? '').trim().toUpperCase();
      if (faceMatchId.isEmpty || !seenMatchIds.add(faceMatchId)) {
        continue;
      }
      final context = await _frService.resolveMatch(
        siteId: siteId,
        personId: faceMatchId,
        observedAtUtc: event.occurredAt.toUtc(),
        timezone: 'Africa/Johannesburg',
      );
      if (context == null) {
        continue;
      }
      statuses.add(
        _TelegramFrPresenceStatus(
          displayName: context.audienceLabel(OnyxFrAudience.client),
          occurredAtUtc: event.occurredAt.toUtc(),
          locationLabel: _frLocationLabelForEvent(event),
        ),
      );
    }
    return List<_TelegramFrPresenceStatus>.unmodifiable(statuses);
  }

  Future<String?> _telegramCombinedPresenceReply({
    required String clientId,
    required String siteId,
    required String siteLabel,
    required String prompt,
    required DateTime nowUtc,
    required DateTime todayLocal,
  }) async {
    final registryRows = await _readSiteVehicleRegistryRows(siteId: siteId);
    if (registryRows.isEmpty) {
      return null;
    }
    final startOfDayUtc = DateTime(
      todayLocal.year,
      todayLocal.month,
      todayLocal.day,
    ).toUtc();
    final presenceRows = await _readSiteVehiclePresenceRows(
      siteId: siteId,
      sinceUtc: startOfDayUtc,
    );
    final statuses = _buildVehiclePresenceStatuses(
      registryRows: registryRows,
      presenceRows: presenceRows,
      nowUtc: nowUtc,
    );
    if (statuses.isEmpty) {
      return null;
    }
    final matchedStatus = _matchedVehiclePresenceStatusForPrompt(
      prompt,
      statuses,
    );
    final normalizedPrompt = prompt.trim().toLowerCase();
    final asksForCombinedPresence =
        normalizedPrompt.contains('who is home') ||
        normalizedPrompt.contains('whos home') ||
        normalizedPrompt.contains('who is on site');
    if (matchedStatus != null && !asksForCombinedPresence) {
      return [
        'Vehicle presence: $siteLabel',
        _telegramVehiclePresenceHomeLine(matchedStatus),
      ].join('\n');
    }
    final frStatuses = await _telegramRecentFrPresenceStatuses(
      clientId: clientId,
      siteId: siteId,
    );
    final onSiteLines = <String>[];
    final seenPeople = <String>{};
    for (final frStatus in frStatuses) {
      final key = _normalizedPresenceNameKey(frStatus.displayName);
      if (key.isEmpty || !seenPeople.add(key)) {
        continue;
      }
      onSiteLines.add(
        '${frStatus.displayName} (detected ${_vehiclePresenceLocalTimeLabel(frStatus.occurredAtUtc)})',
      );
    }
    for (final status in statuses.where((entry) => entry.isHome)) {
      final owner = _vehiclePresenceOwnerLabel(status.registry);
      final key = _normalizedPresenceNameKey(owner);
      if (key.isEmpty || !seenPeople.add(key)) {
        continue;
      }
      if (_vehiclePresenceWasResidentConfirmed(status.latestPresence)) {
        onSiteLines.add('$owner (resident confirmed)');
        continue;
      }
      final latest = status.latestPresence;
      if (latest != null) {
        onSiteLines.add(
          '$owner (vehicle on site since ${_vehiclePresenceLocalTimeLabel(latest.occurredAtUtc)})',
        );
      }
    }
    return [
      'On site: ${onSiteLines.isEmpty ? 'No one confirmed on site right now.' : onSiteLines.join(', ')}',
      'Vehicles:',
      ...statuses.map((status) {
        final owner = _vehiclePresenceOwnerLabel(status.registry);
        final vehicle = _vehiclePresenceVehicleLabel(status.registry);
        if (!status.seenToday || status.latestPresence == null) {
          return '- $owner — not detected today';
        }
        if (status.isHome) {
          if (_vehiclePresenceWasResidentConfirmed(status.latestPresence)) {
            return '- $owner — $vehicle on site (resident confirmed)';
          }
          if (status.latestPresence!.eventType == 'arrived') {
            return '- $owner — $vehicle — ${_vehiclePresenceArrivalLabel(status.latestPresence!)}';
          }
          return '- $owner — $vehicle on site (${_vehiclePresenceLastSeenLabel(status.latestPresence)})';
        }
        return '- $owner — out ($vehicle not seen since ${_vehiclePresenceLocalTimeLabel(status.latestPresence!.occurredAtUtc)})';
      }),
    ].join('\n');
  }

  List<IntelligenceReceived> _recentFrEventsForScope({
    required String clientId,
    required String siteId,
  }) {
    final cutoff = _telegramFlowNowUtc().subtract(const Duration(minutes: 30));
    final events =
        store
            .allEvents()
            .whereType<IntelligenceReceived>()
            .where(
              (event) =>
                  event.clientId.trim() == clientId.trim() &&
                  event.siteId.trim() == siteId.trim() &&
                  (event.faceMatchId ?? '').trim().isNotEmpty &&
                  !event.occurredAt.toUtc().isBefore(cutoff),
            )
            .toList(growable: false)
          ..sort((left, right) => right.occurredAt.compareTo(left.occurredAt));
    return events;
  }

  String _frLocationLabelForEvent(IntelligenceReceived event) {
    final zone = (event.zone ?? '').trim();
    if (zone.isNotEmpty) {
      return zone;
    }
    final cameraLabel = _monitoringCameraLabelForScope(
      clientId: event.clientId,
      siteId: event.siteId,
      cameraId: event.cameraId,
    );
    return cameraLabel.trim().isEmpty ? 'the site' : cameraLabel;
  }

  List<DispatchEvent> _telegramCommandScopedEvents({
    required String clientId,
    required String siteId,
  }) {
    final normalizedClientId = clientId.trim();
    final normalizedSiteId = siteId.trim();
    if (normalizedClientId.isEmpty || normalizedSiteId.isEmpty) {
      return const <DispatchEvent>[];
    }
    final scoped =
        store
            .allEvents()
            .where((event) {
              return _telegramCommandEventClientId(event) ==
                      normalizedClientId &&
                  _telegramCommandEventSiteId(event) == normalizedSiteId;
            })
            .toList(growable: false)
          ..sort(_compareDispatchEventsByOccurredAtThenSequence);
    return scoped;
  }

  String _telegramCommandEventClientId(DispatchEvent event) {
    return switch (event) {
      DecisionCreated value => value.clientId.trim(),
      ResponseArrived value => value.clientId.trim(),
      PartnerDispatchStatusDeclared value => value.clientId.trim(),
      GuardCheckedIn value => value.clientId.trim(),
      ExecutionCompleted value => value.clientId.trim(),
      ExecutionDenied value => value.clientId.trim(),
      IntelligenceReceived value => value.clientId.trim(),
      PatrolCompleted value => value.clientId.trim(),
      IncidentClosed value => value.clientId.trim(),
      ReportGenerated value => value.clientId.trim(),
      _ => '',
    };
  }

  String _telegramCommandEventSiteId(DispatchEvent event) {
    return switch (event) {
      DecisionCreated value => value.siteId.trim(),
      ResponseArrived value => value.siteId.trim(),
      PartnerDispatchStatusDeclared value => value.siteId.trim(),
      GuardCheckedIn value => value.siteId.trim(),
      ExecutionCompleted value => value.siteId.trim(),
      ExecutionDenied value => value.siteId.trim(),
      IntelligenceReceived value => value.siteId.trim(),
      PatrolCompleted value => value.siteId.trim(),
      IncidentClosed value => value.siteId.trim(),
      ReportGenerated value => value.siteId.trim(),
      _ => '',
    };
  }

  DateTime? _telegramCommandLatestScopedEventAtUtc({
    required String clientId,
    required String siteId,
  }) {
    final scoped = _telegramCommandScopedEvents(
      clientId: clientId,
      siteId: siteId,
    );
    if (scoped.isEmpty) {
      return null;
    }
    return scoped.last.occurredAt.toUtc();
  }

  String _telegramCommandLocalDateTimeLabel(DateTime? instantUtc) {
    if (instantUtc == null) {
      return 'n/a';
    }
    final local = instantUtc.toLocal();
    String two(int value) => value.toString().padLeft(2, '0');
    return '${local.year.toString().padLeft(4, '0')}-${two(local.month)}-${two(local.day)} ${two(local.hour)}:${two(local.minute)}';
  }

  String _telegramCommandLocalTimeLabel(DateTime? instantUtc) {
    if (instantUtc == null) {
      return 'n/a';
    }
    final local = instantUtc.toLocal();
    String two(int value) => value.toString().padLeft(2, '0');
    return '${two(local.hour)}:${two(local.minute)}';
  }

  String _telegramCommandCountLabel(int count, String singular) {
    final plural = singular == 'person' ? 'people' : '${singular}s';
    return '$count ${count == 1 ? singular : plural}';
  }

  String _telegramCommandPerimeterLabel(bool clear) =>
      clear ? 'clear' : 'alert active';

  String _telegramGateCameraOnlyPerimeterLine(
    TelegramAiSiteAwarenessSummary? summary,
  ) {
    if (summary == null) {
      return 'No fresh camera snapshot is available in the last 30 minutes.';
    }
    if (!summary.perimeterClear || summary.activeAlertCount > 0) {
      final alertCount = summary.activeAlertCount;
      return alertCount > 0
          ? 'Perimeter currently has $alertCount active ${alertCount == 1 ? 'alert' : 'alerts'}.'
          : 'Perimeter is currently in alert state.';
    }
    final totalMovement =
        summary.humanCount +
        summary.vehicleCount +
        summary.animalCount +
        summary.motionCount;
    if (totalMovement <= 0) {
      return 'Perimeter is currently clear with no movement detected.';
    }
    final parts = <String>[
      if (summary.humanCount > 0)
        _telegramCommandCountLabel(summary.humanCount, 'person'),
      if (summary.vehicleCount > 0)
        _telegramCommandCountLabel(summary.vehicleCount, 'vehicle'),
      if (summary.animalCount > 0)
        _telegramCommandCountLabel(summary.animalCount, 'animal'),
    ];
    if (parts.isEmpty && summary.motionCount > 0) {
      return 'Perimeter is currently clear with recent motion detected.';
    }
    return 'Perimeter is currently clear with ${parts.join(' • ')} detected.';
  }

  String _telegramCommandHeaderLabel(
    TelegramAiSiteAwarenessSummary summary,
    String siteLabel,
  ) {
    final isAllClear = summary.perimeterClear && summary.activeAlertCount <= 0;
    final emoji = isAllClear ? '🟢' : '🔴';
    final label = isAllClear ? 'All clear' : 'Alert active';
    return '$emoji $siteLabel — $label';
  }

  String? _telegramCommandHumanZoneActivityLine(
    List<_SiteAwarenessHumanZone> zones,
  ) {
    if (zones.isEmpty) {
      return null;
    }
    final perimeterZones = zones
        .where((zone) => zone.isPerimeter || zone.zoneType == 'perimeter')
        .toList(growable: false);
    if (perimeterZones.isNotEmpty) {
      final label = _telegramCommandHumanZoneLabels(
        perimeterZones,
        includeZoneType: false,
      );
      final cameraLabel = perimeterZones.length == 1
          ? 'perimeter camera'
          : 'perimeter cameras';
      return '⚠️ Movement at $label — $cameraLabel';
    }
    final indoorZones = zones
        .where((zone) => zone.isIndoor || zone.zoneType == 'indoor')
        .toList(growable: false);
    if (indoorZones.length == zones.length) {
      return 'Household activity detected — '
          '${_telegramCommandHumanZoneLabels(indoorZones)}';
    }
    return 'Movement detected at ${_telegramCommandHumanZoneLabels(zones)}';
  }

  String _telegramCommandHumanZoneLabels(
    List<_SiteAwarenessHumanZone> zones, {
    bool includeZoneType = true,
  }) {
    final labels = zones
        .take(2)
        .map((zone) {
          final base = zone.zoneName.trim();
          if (!includeZoneType) {
            return base;
          }
          return '$base (${zone.zoneTypeLabel})';
        })
        .toList(growable: false);
    if (zones.length > 2) {
      labels.add(
        'and ${zones.length - 2} more area${zones.length - 2 == 1 ? '' : 's'}',
      );
    }
    if (labels.length <= 1) {
      return labels.isEmpty ? 'the site' : labels.first;
    }
    if (labels.length == 2) {
      return '${labels.first} and ${labels.last}';
    }
    return '${labels.sublist(0, labels.length - 1).join(', ')}, and ${labels.last}';
  }

  String _telegramCommandRelativeAgeLabel(DateTime observedAtUtc) {
    final difference = _telegramFlowNowUtc().difference(observedAtUtc).abs();
    if (difference < const Duration(minutes: 1)) {
      return 'just now';
    }
    if (difference < const Duration(hours: 1)) {
      final minutes = difference.inMinutes;
      return '$minutes ${minutes == 1 ? 'minute' : 'minutes'} ago';
    }
    if (difference < const Duration(days: 1)) {
      final hours = difference.inHours;
      return '$hours ${hours == 1 ? 'hour' : 'hours'} ago';
    }
    final days = difference.inDays;
    return '$days ${days == 1 ? 'day' : 'days'} ago';
  }

  List<String> _telegramCommandKnownFaultLines(Map<String, dynamic> row) {
    final channels = row['channels'];
    final faultLines = <String>[];
    if (channels is Map) {
      final sortedKeys = channels.keys.toList(growable: false)
        ..sort((left, right) => left.toString().compareTo(right.toString()));
      for (final key in sortedKeys) {
        final keyLabel = key.toString().trim();
        if (!_siteAwarenessValidChannelLabel(keyLabel)) {
          continue;
        }
        final raw = channels[key];
        if (raw is! Map) {
          continue;
        }
        final isFault = raw['is_fault'] == true || raw['isFault'] == true;
        if (!isFault) {
          continue;
        }
        final status = _siteAwarenessHumanizedLabel(raw['status']);
        final statusLabel = switch (status) {
          'video loss' || 'offline' || 'fault' => 'Offline',
          'online' => 'Online',
          _ => _humanizeScopeLabel(status),
        };
        faultLines.add('Channel $keyLabel: $statusLabel (known fault)');
      }
    }
    if (faultLines.isNotEmpty) {
      return faultLines;
    }
    final knownFaults = row['known_faults'];
    if (knownFaults is! List) {
      return const <String>[];
    }
    return knownFaults
        .map((value) => value.toString().trim())
        .where(_siteAwarenessValidChannelLabel)
        .map((value) => 'Channel $value: Offline (known fault)')
        .toList(growable: false);
  }

  String _telegramCommandChannelSummary(Map<String, dynamic> row) {
    final knownFaults = row['known_faults'];
    final knownFaultLabels = knownFaults is List
        ? knownFaults
              .map((value) => value.toString().trim())
              .where(_siteAwarenessValidChannelLabel)
              .toList(growable: false)
        : const <String>[];
    final channels = row['channels'];
    if (channels is! Map || channels.isEmpty) {
      return knownFaultLabels.isEmpty
          ? 'all reporting channels healthy'
          : 'known fault on ${knownFaultLabels.map((value) => 'Channel $value').join(', ')}';
    }
    final sortedKeys = channels.keys.toList(growable: false)
      ..sort((left, right) => left.toString().compareTo(right.toString()));
    final parts = <String>[];
    for (final key in sortedKeys.take(4)) {
      final keyLabel = key.toString().trim();
      if (!_siteAwarenessValidChannelLabel(keyLabel)) {
        continue;
      }
      final raw = channels[key];
      if (raw is! Map) {
        continue;
      }
      final status = _siteAwarenessHumanizedLabel(raw['status']);
      final isFault = raw['is_fault'] == true || raw['isFault'] == true;
      parts.add('Channel $keyLabel ${isFault ? 'fault' : status}');
    }
    if (parts.isEmpty) {
      return knownFaultLabels.isEmpty
          ? 'all reporting channels healthy'
          : 'known fault on ${knownFaultLabels.map((value) => 'Channel $value').join(', ')}';
    }
    return parts.join(' • ');
  }

  ({DateTime startLocal, DateTime endLocal, String label})
  _telegramCommandIncidentWindowForPrompt(String prompt) {
    final normalized = prompt.toLowerCase();
    final nowLocal = _telegramFlowNowLocal();
    final startOfToday = DateTime(nowLocal.year, nowLocal.month, nowLocal.day);
    if (normalized.contains('last night')) {
      return (
        startLocal: startOfToday.subtract(const Duration(hours: 6)),
        endLocal: startOfToday.add(const Duration(hours: 6)),
        label: 'last night',
      );
    }
    if (normalized.contains('yesterday')) {
      return (
        startLocal: startOfToday.subtract(const Duration(days: 1)),
        endLocal: startOfToday,
        label: 'yesterday',
      );
    }
    if (normalized.contains('today')) {
      return (
        startLocal: startOfToday,
        endLocal: startOfToday.add(const Duration(days: 1)),
        label: 'today',
      );
    }
    return (
      startLocal: nowLocal.subtract(const Duration(hours: 24)),
      endLocal: nowLocal,
      label: 'the last 24 hours',
    );
  }

  Future<String> _telegramLiveStatusReply({
    required String clientId,
    required String siteId,
    String audienceRole = 'client',
    String prompt = '',
  }) async {
    final siteLabel = _deliverySiteLabelFor(clientId: clientId, siteId: siteId);
    final vehiclePresenceQuery = _telegramPromptLooksLikeVehiclePresence(
      prompt,
    );
    if (vehiclePresenceQuery) {
      final vehiclePresenceReply = await _telegramCombinedPresenceReply(
        clientId: clientId,
        siteId: siteId,
        siteLabel: siteLabel,
        prompt: prompt,
        nowUtc: _telegramFlowNowUtc(),
        todayLocal: _telegramFlowNowLocal(),
      );
      if (vehiclePresenceReply != null) {
        return vehiclePresenceReply;
      }
    }
    final siteProfile = await _siteProfileService.loadProfile(siteId);
    final activeExpectedVisitors = await _siteProfileService
        .loadActiveExpectedVisitors(
          siteId: siteId,
          timezone: siteProfile.timezone,
          atUtc: _telegramFlowNowUtc(),
        );
    final siteAwarenessRow = await _readLatestSiteAwarenessSnapshotRow(
      siteId: siteId,
    );
    final nowUtc = _telegramFlowNowUtc();
    final freshSiteAwareness =
        siteAwarenessRow != null &&
        _isSiteAwarenessSnapshotFresh(siteAwarenessRow, nowUtc);
    final siteAwarenessSummary = freshSiteAwareness
        ? _telegramAiSiteAwarenessSummaryFromRow(siteAwarenessRow)
        : null;
    Map<String, dynamic>? occupancyConfigRow;
    Map<String, dynamic>? occupancySessionRow;
    if (siteAwarenessSummary != null) {
      occupancyConfigRow = await _readSiteOccupancyConfigRow(siteId: siteId);
      if (occupancyConfigRow != null) {
        occupancySessionRow = await _readSiteOccupancySessionRow(
          siteId: siteId,
          nowLocal: _telegramFlowNowLocal(),
          resetHour: _siteOccupancyResetHour(occupancyConfigRow),
        );
      }
    }
    final incidentRows = await _readIncidentRowsForSite(siteId: siteId);
    final activeIncidents = incidentRows
        .where(_incidentRowIsActive)
        .toList(growable: false);
    final latestIncident = incidentRows.isEmpty ? null : incidentRows.first;
    final latestEventAtUtc =
        siteAwarenessSummary?.observedAtUtc ??
        _incidentRowOccurredAtUtc(latestIncident) ??
        _telegramCommandLatestScopedEventAtUtc(
          clientId: clientId,
          siteId: siteId,
        );

    final lines = <String>[];
    if (siteAwarenessSummary != null) {
      final freshSiteAwarenessRow = siteAwarenessRow!;
      final humanZones = _siteAwarenessHumanZones(freshSiteAwarenessRow);
      final humanZoneActivityLine = _telegramCommandHumanZoneActivityLine(
        humanZones,
      );
      final frPresenceLine = await _telegramRecentFrPresenceLine(
        clientId: clientId,
        siteId: siteId,
        audienceRole: audienceRole,
      );
      final hasPerimeterHumanMovement = humanZones.any(
        (zone) => zone.isPerimeter || zone.zoneType == 'perimeter',
      );
      lines.add(
        hasPerimeterHumanMovement &&
                siteAwarenessSummary.perimeterClear &&
                siteAwarenessSummary.activeAlertCount <= 0
            ? '🟠 $siteLabel — Perimeter movement'
            : _telegramCommandHeaderLabel(siteAwarenessSummary, siteLabel),
      );
      lines.add(
        'Perimeter: ${siteAwarenessSummary.perimeterClear ? 'Clear' : 'Alert active'}',
      );
      if (humanZoneActivityLine != null) {
        lines.add(humanZoneActivityLine);
      }
      if (frPresenceLine != null) {
        lines.add(frPresenceLine);
      }
      final expectedPeopleCount = _siteProfileExpectedPeopleCount(
        siteProfile,
        occupancyConfigRow,
      );
      final currentMovementCount = math.max(siteAwarenessSummary.humanCount, 0);
      lines.add(
        _siteProfileService.formatStatusMessage(
          profile: siteProfile,
          snapshot: SiteSnapshot(
            siteId: siteId,
            siteName: siteLabel,
            observedAtUtc: siteAwarenessSummary.observedAtUtc,
            perimeterClear: siteAwarenessSummary.perimeterClear,
            onSiteCount: currentMovementCount,
            expectedPeopleCount: expectedPeopleCount,
            vehicleCount: siteAwarenessSummary.vehicleCount,
            activeIncidents: activeIncidents.length,
            offlineChannels: _telegramCommandKnownFaultLines(
              freshSiteAwarenessRow,
            ),
            fresh: true,
            activeAlerts: siteAwarenessSummary.activeAlertCount,
          ),
        ),
      );
      if (siteProfile.industryType == 'residential' &&
          expectedPeopleCount > 0) {
        final lastMovementAtUtc =
            _siteOccupancyLastDetectionAtUtc(occupancySessionRow) ??
            (currentMovementCount > 0
                ? siteAwarenessSummary.observedAtUtc
                : null);
        if (currentMovementCount < expectedPeopleCount) {
          lines.add('Expected on site: $expectedPeopleCount residents');
        }
        if (lastMovementAtUtc != null) {
          lines.add(
            'Last movement: ${_telegramCommandLocalTimeLabel(lastMovementAtUtc)}',
          );
        }
      }
      final expectedVisitorLine = _telegramExpectedVisitorStatusLine(
        activeExpectedVisitors,
      );
      if (expectedVisitorLine != null) {
        lines.add(expectedVisitorLine);
      }
      if (siteAwarenessSummary.activeAlertCount > 0) {
        lines.add('Active alerts: ${siteAwarenessSummary.activeAlertCount}');
      }
      final vehicleSection = _telegramVehiclePresenceSummarySection(
        _buildVehiclePresenceStatuses(
          registryRows: await _readSiteVehicleRegistryRows(siteId: siteId),
          presenceRows: await _readSiteVehiclePresenceRows(
            siteId: siteId,
            sinceUtc: DateTime(
              _telegramFlowNowLocal().year,
              _telegramFlowNowLocal().month,
              _telegramFlowNowLocal().day,
            ).toUtc(),
          ),
          nowUtc: _telegramFlowNowUtc(),
        ),
      );
      if (vehicleSection.isNotEmpty) {
        lines.add(vehicleSection);
      }
      lines.add(
        'Last update: ${_telegramCommandRelativeAgeLabel(siteAwarenessSummary.observedAtUtc)}',
      );
      lines.addAll(_telegramCommandKnownFaultLines(freshSiteAwarenessRow));
    } else {
      lines.add('🟠 $siteLabel — Monitoring limited');
      lines.add(
        'Monitoring: No fresh site-awareness snapshot in the last 30 minutes',
      );
      if (latestEventAtUtc != null) {
        lines.add(
          'Last confirmed event: ${_telegramCommandLocalDateTimeLabel(latestEventAtUtc)}',
        );
      }
    }
    lines.add('Active incidents: ${activeIncidents.length}');
    if (latestIncident != null) {
      lines.add(
        'Latest operational incident: ${_incidentRowReference(latestIncident)} • ${_incidentRowStatusLabel(latestIncident)}',
      );
    }
    return lines.join('\n');
  }

  Future<void> _maybeSendTelegramStatusVoiceMessage({
    required String chatId,
    required int? messageThreadId,
    required String clientId,
    required String siteId,
    required String endpointRole,
    required String fallbackText,
    required String sourceLabel,
  }) async {
    final normalizedEndpointRole = _normalizeTelegramEndpointRole(endpointRole);
    if (!_telegramEndpointRoleAllowsVoice(normalizedEndpointRole)) {
      developer.log(
        '[ONYX] ElevenLabs: skipped voice synthesis endpoint_role=$normalizedEndpointRole',
        name: 'ElevenLabs',
      );
      return;
    }
    if (!_elevenLabsService.isConfigured || !_telegramBridge.isConfigured) {
      developer.log(
        '[ONYX] ElevenLabs: skipped voice synthesis '
        'elevenlabs_configured=${_elevenLabsService.isConfigured} '
        'telegram_configured=${_telegramBridge.isConfigured}',
        name: 'ElevenLabs',
      );
      return;
    }
    try {
      final script = await _buildTelegramStatusVoiceScript(
        clientId: clientId,
        siteId: siteId,
        endpointRole: normalizedEndpointRole,
        fallbackText: fallbackText,
      );
      if (script == null || script.trim().isEmpty) {
        developer.log(
          '[ONYX] ElevenLabs: skipped voice synthesis because script was empty',
          name: 'ElevenLabs',
        );
        return;
      }
      developer.log(
        '[ONYX] ElevenLabs: attempting voice synthesis, '
        'key_length=${_elevenLabsService.apiKeyLength}',
        name: 'ElevenLabs',
      );
      final audioBytes = await _elevenLabsService.synthesize(script);
      developer.log(
        '[ONYX] ElevenLabs: synthesis result = ${audioBytes?.length ?? 0} bytes',
        name: 'ElevenLabs',
      );
      if (audioBytes == null || audioBytes.isEmpty) {
        developer.log(
          '[ONYX] ElevenLabs: skipping Telegram voice upload because no audio was returned',
          name: 'ElevenLabs',
        );
        return;
      }
      developer.log(
        '[ONYX] ElevenLabs: sending voice message to chat=$chatId '
        'thread=${messageThreadId ?? 0} source=$sourceLabel',
        name: 'ElevenLabs',
      );
      await _telegramBridge.sendVoiceMessage(
        chatId,
        audioBytes,
        messageThreadId: messageThreadId,
      );
      developer.log(
        '[ONYX] ElevenLabs: sendVoiceMessage completed',
        name: 'ElevenLabs',
      );
    } catch (error, stackTrace) {
      developer.log(
        'Telegram status voice send failed for $sourceLabel',
        name: 'OnyxTelegramVoice',
        error: error,
        stackTrace: stackTrace,
      );
    }
  }

  Future<String?> _buildTelegramStatusVoiceScript({
    required String clientId,
    required String siteId,
    required String endpointRole,
    required String fallbackText,
  }) async {
    final siteLabel = _deliverySiteLabelFor(clientId: clientId, siteId: siteId);
    final nowUtc = _telegramFlowNowUtc();
    final siteProfile = await _siteProfileService.loadProfile(siteId);
    final siteAwarenessRow = await _readLatestSiteAwarenessSnapshotRow(
      siteId: siteId,
    );
    if (siteAwarenessRow != null &&
        _isSiteAwarenessSnapshotFresh(siteAwarenessRow, nowUtc)) {
      final siteAwarenessSummary = _telegramAiSiteAwarenessSummaryFromRow(
        siteAwarenessRow,
      )!;
      final activeExpectedVisitors = await _siteProfileService
          .loadActiveExpectedVisitors(
            siteId: siteId,
            timezone: siteProfile.timezone,
            atUtc: nowUtc,
          );
      final activeIncidentCount = (await _readIncidentRowsForSite(
        siteId: siteId,
      )).where(_incidentRowIsActive).length;
      final segments = <String>[
        _telegramEndpointRoleAllowsVoice(endpointRole)
            ? 'ONYX Control.'
            : 'ONYX Security.',
        '$siteLabel.',
        if (_telegramEndpointRoleAllowsVoice(endpointRole)) 'Status update.',
        siteAwarenessSummary.perimeterClear
            ? 'Perimeter clear.'
            : 'Perimeter alert active.',
      ];
      final humanCount = math.max(siteAwarenessSummary.humanCount, 0);
      if (humanCount > 0) {
        segments.add(
          humanCount == 1
              ? '1 person on site.'
              : '$humanCount persons on site.',
        );
      } else {
        segments.add('No persons detected on site.');
      }
      final onDemandVisitorLine = _telegramExpectedVisitorStatusLine(
        activeExpectedVisitors,
      );
      if (onDemandVisitorLine != null) {
        segments.add(onDemandVisitorLine);
      }
      if (activeIncidentCount <= 0) {
        segments.add('No active alerts.');
      } else {
        segments.add(
          activeIncidentCount == 1
              ? '1 active alert.'
              : '$activeIncidentCount active alerts.',
        );
      }
      segments.add('Camera coverage nominal.');
      for (final line in _telegramCommandKnownFaultLines(siteAwarenessRow)) {
        final spoken = line
            .replaceAll(':', '')
            .replaceAll('(', ', ')
            .replaceAll(')', '')
            .replaceAll('  ', ' ')
            .trim();
        if (spoken.isNotEmpty) {
          segments.add(spoken.endsWith('.') ? spoken : '$spoken.');
        }
      }
      if (_telegramEndpointRoleAllowsVoice(endpointRole)) {
        segments.add('End of update.');
      } else {
        segments.add('Monitoring continues.');
      }
      return _normalizeTelegramStatusVoiceScript(segments.join(' '));
    }
    return _normalizeTelegramStatusVoiceScript(fallbackText);
  }

  String? _normalizeTelegramStatusVoiceScript(String value) {
    final normalized = value
        .replaceAll('\n', ' ')
        .replaceAll(RegExp(r'[•*_]'), ' ')
        .replaceAll(RegExp(r'\s+'), ' ')
        .trim();
    if (normalized.isEmpty) {
      return null;
    }
    if (normalized.length <= 500) {
      return normalized;
    }
    return normalized.substring(0, 500).trimRight();
  }

  Future<String> _telegramIncidentReply({
    required String clientId,
    required String siteId,
    required String prompt,
  }) async {
    final siteLabel = _deliverySiteLabelFor(clientId: clientId, siteId: siteId);
    final incidentRows = await _readIncidentRowsForSite(siteId: siteId);
    final window = _telegramCommandIncidentWindowForPrompt(prompt);
    final filtered = incidentRows
        .where((row) {
          final occurredAtUtc = _incidentRowOccurredAtUtc(row);
          if (occurredAtUtc == null) {
            return false;
          }
          final occurredAtLocal = occurredAtUtc.toLocal();
          return !occurredAtLocal.isBefore(window.startLocal) &&
              occurredAtLocal.isBefore(window.endLocal);
        })
        .toList(growable: false);
    if (filtered.isEmpty) {
      if (window.label == 'today') {
        return 'No incidents recorded today at $siteLabel.';
      }
      return 'Incident summary: $siteLabel\n• No incidents recorded for ${window.label}.';
    }
    final lines = <String>[
      'Incident summary: $siteLabel',
      '• Window: ${window.label}',
    ];
    for (final row in filtered.take(4)) {
      final parts = <String>[
        _incidentRowReference(row),
        'opened ${_telegramCommandLocalTimeLabel(_incidentRowOccurredAtUtc(row))}',
      ];
      final dispatchAtUtc = _incidentRowDispatchAtUtc(row);
      if (dispatchAtUtc != null) {
        parts.add('dispatch ${_telegramCommandLocalTimeLabel(dispatchAtUtc)}');
      }
      final arrivedAtUtc = _incidentRowArrivalAtUtc(row);
      if (arrivedAtUtc != null) {
        parts.add('arrived ${_telegramCommandLocalTimeLabel(arrivedAtUtc)}');
      }
      final resolvedAtUtc = _incidentRowResolutionAtUtc(row);
      if (resolvedAtUtc != null) {
        parts.add(
          'outcome ${_incidentRowStatusLabel(row)} at ${_telegramCommandLocalTimeLabel(resolvedAtUtc)}',
        );
      } else {
        parts.add('status ${_incidentRowStatusLabel(row)}');
      }
      lines.add('• ${parts.join(' • ')}');
    }
    return lines.join('\n');
  }

  Future<String> _telegramDispatchReply({
    required String clientId,
    required String siteId,
    required String prompt,
  }) async {
    final siteLabel = _deliverySiteLabelFor(clientId: clientId, siteId: siteId);
    var incidentRows = await _readIncidentRowsForSite(siteId: siteId);
    if (prompt.toLowerCase().contains('today')) {
      final todayStartLocal = DateTime(
        _telegramFlowNowLocal().year,
        _telegramFlowNowLocal().month,
        _telegramFlowNowLocal().day,
      );
      final tomorrowStartLocal = todayStartLocal.add(const Duration(days: 1));
      incidentRows = incidentRows
          .where((row) {
            final occurredAtUtc = _incidentRowOccurredAtUtc(row);
            if (occurredAtUtc == null) {
              return false;
            }
            final local = occurredAtUtc.toLocal();
            return !local.isBefore(todayStartLocal) &&
                local.isBefore(tomorrowStartLocal);
          })
          .toList(growable: false);
    }
    final dispatchedRows = incidentRows
        .where(
          (row) =>
              _incidentRowDispatchAtUtc(row) != null ||
              _incidentRowArrivalAtUtc(row) != null ||
              _incidentRowIsActive(row),
        )
        .toList(growable: false);
    if (dispatchedRows.isEmpty) {
      return 'Dispatch summary: $siteLabel\n• No dispatch records are attached to this site yet.';
    }
    final lines = <String>['Dispatch summary: $siteLabel'];
    for (final row in dispatchedRows.take(4)) {
      final parts = <String>[
        _incidentRowReference(row),
        'dispatched ${_telegramCommandLocalTimeLabel(_incidentRowDispatchAtUtc(row) ?? _incidentRowOccurredAtUtc(row))}',
        'status ${_incidentRowStatusLabel(row)}',
      ];
      final arrivedAtUtc = _incidentRowArrivalAtUtc(row);
      if (arrivedAtUtc != null) {
        parts.add('arrived ${_telegramCommandLocalTimeLabel(arrivedAtUtc)}');
      }
      lines.add('• ${parts.join(' • ')}');
    }
    return lines.join('\n');
  }

  Future<String> _telegramGateAccessReply({
    required String clientId,
    required String siteId,
  }) async {
    final siteLabel = _deliverySiteLabelFor(clientId: clientId, siteId: siteId);
    final occupancyConfigRow = await _readSiteOccupancyConfigRow(
      siteId: siteId,
    );
    final siteAwarenessRow = await _readLatestSiteAwarenessSnapshotRow(
      siteId: siteId,
    );
    final siteAwarenessSummary =
        siteAwarenessRow != null &&
            _isSiteAwarenessSnapshotFresh(
              siteAwarenessRow,
              _telegramFlowNowUtc(),
            )
        ? _telegramAiSiteAwarenessSummaryFromRow(siteAwarenessRow)
        : null;
    if (occupancyConfigRow == null ||
        !_siteOccupancyHasGateSensors(occupancyConfigRow)) {
      return [
        'No gate sensors are configured at $siteLabel.',
        'ONYX monitors via cameras only.',
        _telegramGateCameraOnlyPerimeterLine(siteAwarenessSummary),
      ].join('\n');
    }
    return [
      'Gate sensors are configured at $siteLabel, but direct gate-state reporting is not available in this chat yet.',
      _telegramGateCameraOnlyPerimeterLine(siteAwarenessSummary),
    ].join('\n');
  }

  Future<String> _telegramGuardReply({
    required String clientId,
    required String siteId,
  }) async {
    final occupancyConfigRow = await _readSiteOccupancyConfigRow(
      siteId: siteId,
    );
    if (occupancyConfigRow != null &&
        !_siteOccupancyHasGuard(occupancyConfigRow)) {
      return 'No guard is assigned to this site.\nONYX is monitoring via cameras only.';
    }
    final siteLabel = _deliverySiteLabelFor(clientId: clientId, siteId: siteId);
    final assignments = await _readPatrolAssignmentsForSite(siteId: siteId);
    if (assignments.isEmpty) {
      return 'No active guard assignment is configured at $siteLabel yet.';
    }
    final checkpoints = await _readPatrolCheckpointsForSite(
      siteId: siteId,
      routeIds: assignments
          .map((assignment) => assignment.routeId.trim())
          .where((value) => value.isNotEmpty)
          .toSet()
          .toList(growable: false),
    );
    final scans = await _readPatrolScansForSite(siteId: siteId);
    final outcome = const OnyxPatrolMonitorService().evaluate(
      siteId: siteId,
      assignments: assignments,
      checkpoints: checkpoints,
      scans: scans,
      nowLocal: _telegramFlowNowLocal(),
    );
    if (outcome.complianceSnapshots.isEmpty) {
      return 'Guard status: $siteLabel\n• No patrol telemetry has been recorded yet.';
    }
    final snapshot =
        outcome.complianceSnapshots.where((entry) => entry.onDuty).isNotEmpty
        ? outcome.complianceSnapshots.firstWhere((entry) => entry.onDuty)
        : outcome.complianceSnapshots.first;
    final shiftLabel =
        '${_telegramCommandLocalTimeLabel(snapshot.windowStartLocal)} - ${_telegramCommandLocalTimeLabel(snapshot.windowEndLocal)}';
    final lastScanLine = snapshot.lastCheckpointName == null
        ? 'none logged yet'
        : '${snapshot.lastCheckpointName} at ${_telegramCommandLocalDateTimeLabel(snapshot.lastScanAtUtc)}';
    final complianceLabel = snapshot.expectedPatrols <= 0
        ? 'awaiting first patrol window'
        : '${snapshot.completedPatrols} of ${snapshot.expectedPatrols} expected (${snapshot.compliancePercent.toStringAsFixed(0)}%)';
    return [
      'Guard status: $siteLabel',
      '• Guard on duty: ${snapshot.guardName} (${snapshot.guardId})${snapshot.onDuty ? '' : ' — off shift'}',
      '• Shift: $shiftLabel',
      '• Last checkpoint: $lastScanLine',
      '• Patrol compliance: $complianceLabel',
      if (snapshot.missedCheckpoints.isNotEmpty)
        '• Outstanding checkpoints: ${snapshot.missedCheckpoints.take(3).join(', ')}',
    ].join('\n');
  }

  Future<String> _telegramReportReply({
    required String clientId,
    required String siteId,
    required String prompt,
  }) async {
    final normalizedPrompt = prompt.toLowerCase();
    final siteLabel = _deliverySiteLabelFor(clientId: clientId, siteId: siteId);
    final occupancyConfigRow = await _readSiteOccupancyConfigRow(
      siteId: siteId,
    );
    if (!normalizedPrompt.contains('weekly') &&
        !normalizedPrompt.contains('monthly')) {
      if (occupancyConfigRow != null &&
          !_siteOccupancyHasGuard(occupancyConfigRow)) {
        return _telegramCameraOnlyResidenceReportReply(
          clientId: clientId,
          siteId: siteId,
          siteLabel: siteLabel,
          occupancyConfigRow: occupancyConfigRow,
        );
      }
      return _telegramGuardPatrolReportReply(
        clientId: clientId,
        siteId: siteId,
        siteLabel: siteLabel,
        occupancyConfigRow: occupancyConfigRow,
      );
    }
    final history = _siteActivityHistoryPointsForScope(
      clientId: clientId,
      siteId: siteId,
    );
    final windowDays = normalizedPrompt.contains('monthly') ? 30 : 7;
    final selected = history.take(windowDays).toList(growable: false);
    if (selected.isEmpty) {
      return '${normalizedPrompt.contains('monthly') ? 'Monthly' : 'Weekly'} summary: $siteLabel\n• No intelligence projection history is available yet.';
    }
    var totalSignals = 0;
    var totalPeople = 0;
    var totalVehicles = 0;
    var totalUnknown = 0;
    var totalFlagged = 0;
    var totalLongPresence = 0;
    for (final point in selected) {
      totalSignals += point.snapshot.totalSignals;
      totalPeople += point.snapshot.personSignals;
      totalVehicles += point.snapshot.vehicleSignals;
      totalUnknown +=
          point.snapshot.unknownPersonSignals +
          point.snapshot.unknownVehicleSignals;
      totalFlagged += point.snapshot.flaggedIdentitySignals;
      totalLongPresence += point.snapshot.longPresenceSignals;
    }
    final trend = _siteActivityTrendSnapshotFor(selected.first.snapshot);
    return [
      '${normalizedPrompt.contains('monthly') ? 'Monthly' : 'Weekly'} summary: $siteLabel',
      '• Days covered: ${selected.length}',
      '• Total signals: $totalSignals',
      '• Movement mix: ${_telegramCommandCountLabel(totalPeople, 'person')} • ${_telegramCommandCountLabel(totalVehicles, 'vehicle')}',
      '• Unknown / flagged: $totalUnknown unknown • $totalFlagged flagged',
      '• Long presence markers: $totalLongPresence',
      if (trend != null) '• Trend: ${trend.label} — ${trend.summary}',
    ].join('\n');
  }

  Future<String> _telegramCameraOnlyResidenceReportReply({
    required String clientId,
    required String siteId,
    required String siteLabel,
    required Map<String, dynamic> occupancyConfigRow,
  }) async {
    final siteProfile = await _siteProfileService.loadProfile(siteId);
    final activeExpectedVisitors = await _siteProfileService
        .loadActiveExpectedVisitors(
          siteId: siteId,
          timezone: siteProfile.timezone,
          atUtc: _telegramFlowNowUtc(),
        );
    final siteAwarenessRow = await _readLatestSiteAwarenessSnapshotRow(
      siteId: siteId,
    );
    final nowUtc = _telegramFlowNowUtc();
    final freshSiteAwareness =
        siteAwarenessRow != null &&
        _isSiteAwarenessSnapshotFresh(siteAwarenessRow, nowUtc);
    final siteAwarenessSummary = freshSiteAwareness
        ? _telegramAiSiteAwarenessSummaryFromRow(siteAwarenessRow)
        : null;
    final occupancySessionRow = await _readSiteOccupancySessionRow(
      siteId: siteId,
      nowLocal: _telegramFlowNowLocal(),
      resetHour: _siteOccupancyResetHour(occupancyConfigRow),
    );
    final expectedOccupancy = _siteOccupancyExpectedOccupancy(
      occupancyConfigRow,
    );
    final detectedToday = _siteOccupancyDisplayedDetectedCount(
      sessionRow: occupancySessionRow,
      currentHumanCount: siteAwarenessSummary?.humanCount ?? 0,
    );
    final localNow = _telegramFlowNowLocal();
    final startOfTodayLocal = DateTime(
      localNow.year,
      localNow.month,
      localNow.day,
    );
    final endOfTodayLocal = startOfTodayLocal.add(const Duration(days: 1));
    final incidentsToday = (await _readIncidentRowsForSite(siteId: siteId))
        .where((row) {
          final occurredAtUtc = _incidentRowOccurredAtUtc(row);
          if (occurredAtUtc == null) {
            return false;
          }
          final occurredAtLocal = occurredAtUtc.toLocal();
          return !occurredAtLocal.isBefore(startOfTodayLocal) &&
              occurredAtLocal.isBefore(endOfTodayLocal);
        })
        .length;
    final lines = <String>[
      'Report: $siteLabel',
      if (siteAwarenessSummary != null) ...<String>[
        '• Camera monitoring: active',
        '• ${_siteProfileService.formatStatusMessage(
          profile: siteProfile,
          snapshot: SiteSnapshot(siteId: siteId, siteName: siteLabel, observedAtUtc: siteAwarenessSummary.observedAtUtc, perimeterClear: siteAwarenessSummary.perimeterClear, onSiteCount: math.max(siteAwarenessSummary.humanCount, 0), expectedPeopleCount: _siteProfileExpectedPeopleCount(siteProfile, occupancyConfigRow), vehicleCount: siteAwarenessSummary.vehicleCount, activeIncidents: incidentsToday, offlineChannels: _telegramCommandKnownFaultLines(siteAwarenessRow ?? const <String, dynamic>{}), fresh: true, activeAlerts: siteAwarenessSummary.activeAlertCount),
        )}',
      ] else ...<String>['• Camera monitoring: limited'],
      if (expectedOccupancy > 0 && siteProfile.industryType == 'residential')
        '• Occupancy: Movement detected from up to $detectedToday ${detectedToday == 1 ? 'person' : 'people'} today (identity unconfirmed)',
      if (_telegramExpectedVisitorStatusLine(activeExpectedVisitors)
          case final visitorLine?)
        '• $visitorLine',
      '• Incidents today: $incidentsToday',
      '• Alert summary: ${siteAwarenessSummary == null || siteAwarenessSummary.activeAlertCount <= 0 ? 'none' : '${siteAwarenessSummary.activeAlertCount} active'}',
      if (siteAwarenessSummary != null)
        '• Last update: ${_telegramCommandRelativeAgeLabel(siteAwarenessSummary.observedAtUtc)}',
      ..._telegramCommandKnownFaultLines(
        siteAwarenessRow ?? const <String, dynamic>{},
      ).map((line) => '• $line'),
    ];
    return lines.join('\n');
  }

  Future<String> _telegramGuardPatrolReportReply({
    required String clientId,
    required String siteId,
    required String siteLabel,
    required Map<String, dynamic>? occupancyConfigRow,
  }) async {
    final cameraReport = await _telegramCameraOnlyResidenceReportReply(
      clientId: clientId,
      siteId: siteId,
      siteLabel: siteLabel,
      occupancyConfigRow:
          occupancyConfigRow ??
          const <String, dynamic>{
            'expected_occupancy': 0,
            'occupancy_label': 'people',
            'site_type': '',
            'reset_hour': 3,
          },
    );
    final assignments = await _readPatrolAssignmentsForSite(siteId: siteId);
    if (assignments.isEmpty) {
      return '$cameraReport\n• Guard patrol report: no active guard assignment configured.';
    }
    final checkpoints = await _readPatrolCheckpointsForSite(
      siteId: siteId,
      routeIds: assignments
          .map((assignment) => assignment.routeId.trim())
          .where((value) => value.isNotEmpty)
          .toSet()
          .toList(growable: false),
    );
    final scans = await _readPatrolScansForSite(siteId: siteId);
    final outcome = const OnyxPatrolMonitorService().evaluate(
      siteId: siteId,
      assignments: assignments,
      checkpoints: checkpoints,
      scans: scans,
      nowLocal: _telegramFlowNowLocal(),
    );
    if (outcome.complianceSnapshots.isEmpty) {
      return '$cameraReport\n• Guard patrol report: no patrol scans recorded today.';
    }
    final snapshot =
        outcome.complianceSnapshots.where((entry) => entry.onDuty).isNotEmpty
        ? outcome.complianceSnapshots.firstWhere((entry) => entry.onDuty)
        : outcome.complianceSnapshots.first;
    final shiftLabel =
        '${_telegramCommandLocalTimeLabel(snapshot.windowStartLocal)} - ${_telegramCommandLocalTimeLabel(snapshot.windowEndLocal)}';
    final lines = <String>[
      cameraReport,
      '• Guard Patrol Report — ${snapshot.complianceDateValue}',
      '• Guard: ${snapshot.guardName} (${snapshot.guardId})',
      '• Shift: $shiftLabel',
      '• Patrols completed: ${snapshot.completedPatrols} of ${snapshot.expectedPatrols} expected',
      '• Compliance: ${snapshot.compliancePercent.toStringAsFixed(0)}%',
      '• Missed checkpoints: ${snapshot.missedCheckpoints.isEmpty ? 'none' : snapshot.missedCheckpoints.join(', ')}',
      '• Last scan: ${snapshot.lastCheckpointName == null ? 'none logged yet' : '${snapshot.lastCheckpointName} at ${_telegramCommandLocalTimeLabel(snapshot.lastScanAtUtc)}'}',
    ];
    return lines.join('\n');
  }

