    DvrScopeConfig? scope, {
    Iterable<IntelligenceReceived> recentIntelligence =
        const <IntelligenceReceived>[],
  }) async {
    final override = widget.localHikvisionDvrVisualProbeServiceOverride;
    if (override != null && scope != null) {
