      'site_builder_opened' =>
        auditVerified
            ? 'Signed site builder handoff verified.'
            : 'Add the next site fast',
      'site_map_opened' =>
        auditVerified
            ? 'Signed site map handoff verified.'
            : 'Open the site map',
      'site_settings_opened' =>
        auditVerified
            ? 'Signed site settings handoff verified.'
            : name.isEmpty
