            : 'Edit $name',
      'site_guard_roster_opened' =>
        auditVerified
            ? 'Signed guard roster handoff verified.'
            : name.isEmpty
            ? 'Open the guard roster'
            : 'Assign guards for $name',
      _ =>
        auditVerified
            ? 'Signed Sites handoff verified.'
            : 'Open the Sites desk',
