  int _fallbackTelegramTargetCountForScope(String clientId, String siteId) {
    if (!_telegramBridge.isConfigured) {
      return 0;
    }
    final fallbackTarget = _telegramBridgeResolver.telegramFallbackTarget(
      clientId: clientId,
      siteId: siteId,
    );
    return fallbackTarget == null ? 0 : 1;
  }

  void _ensureClientCommsDeliveryReadiness(String clientId, String siteId) {
    final normalizedClientId = clientId.trim();
    final normalizedSiteId = siteId.trim();
    if (normalizedClientId.isEmpty || normalizedSiteId.isEmpty) {
      return;
    }
    final key = _clientCommsScopeKey(normalizedClientId, normalizedSiteId);
    if (_clientCommsDeliveryReadinessByScope.containsKey(key) ||
        _clientCommsDeliveryReadinessLoading.contains(key)) {
      return;
    }
    unawaited(
      _refreshClientCommsDeliveryReadiness(
        clientId: normalizedClientId,
        siteId: normalizedSiteId,
      ),
    );
  }

  Future<void> _refreshClientCommsDeliveryReadiness({
    required String clientId,
    required String siteId,
  }) async {
    final key = _clientCommsScopeKey(clientId, siteId);
    // Mark the scope as loading synchronously so callers relying on the
    // `_clientCommsDeliveryReadinessLoading` set see the flip immediately.
    // The visual rebuild is deferred to the next frame to avoid triggering
    // a setState during build when this refresh is kicked off from a
    // router-driven page builder (see onyx_router.dart — each GoRoute
    // wraps its body in a Builder, which makes synchronous setState calls
    // from within the body's build fail the "setState during build" guard
    // that was tolerated under the old MaterialApp(home:) tree).
    _clientCommsDeliveryReadinessLoading = {
      ..._clientCommsDeliveryReadinessLoading,
      key,
    };
    if (mounted) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (mounted) setState(() {});
      });
    }

    var telegramTargetCount = _fallbackTelegramTargetCountForScope(
      clientId,
      siteId,
    );
    var telegramEndpointMappingAmbiguous = false;
    var phoneContactCount = 0;
    try {
      final targetRecords = selectTelegramRecordsForLaneAndScope(
        records: await _readManagedTelegramEndpointRecordsForScope(
          clientId: clientId,
          siteId: siteId,
        ),
        partnerTargets: false,
        isPartnerLabel: _isPartnerEndpointLabel,
      );
      final phones = await _resolveActiveContactPhones(
        clientId: clientId,
        siteId: siteId,
      );
      telegramEndpointMappingAmbiguous = hasAmbiguousTelegramEndpointMappings(
        entries: targetRecords,
        chatIdOf: (record) => record.chatId,
        threadIdOf: (record) => record.threadId,
      );
      final uniqueTargetCount = countUniqueTelegramEndpointMappings(
        entries: targetRecords,
        chatIdOf: (record) => record.chatId,
        threadIdOf: (record) => record.threadId,
      );
      if (uniqueTargetCount > 0) {
        telegramTargetCount = uniqueTargetCount;
      }
      phoneContactCount = phones.length;
    } catch (_) {
      // Keep env/runtime fallback state when the directory lookup is down.
    }

    final readiness = _clientCommsDeliveryPolicy.evaluate(
      telegramBridgeConfigured: _telegramBridge.isConfigured,
      telegramTargetCount: telegramTargetCount,
      telegramHealthLabel: _telegramBridgeHealthLabel,
      telegramFallbackActive: _telegramBridgeFallbackToInApp,
      telegramEndpointMappingAmbiguous: telegramEndpointMappingAmbiguous,
      smsProviderConfigured: _smsFallbackProviderConfigured,
      phoneContactCount: phoneContactCount,
      voipProviderConfigured: _voipProviderConfigured,
    );

    if (!mounted) {
      _clientCommsDeliveryReadinessByScope = {
        ..._clientCommsDeliveryReadinessByScope,
        key: readiness,
      };
      _clientCommsDeliveryReadinessLoading = {
        ..._clientCommsDeliveryReadinessLoading,
      }..remove(key);
      return;
    }
    setState(() {
      _clientCommsDeliveryReadinessByScope = {
        ..._clientCommsDeliveryReadinessByScope,
        key: readiness,
      };
      _clientCommsDeliveryReadinessLoading = {
        ..._clientCommsDeliveryReadinessLoading,
      }..remove(key);
    });
  }

  ClientCommsDeliveryReadiness _clientCommsDeliveryReadinessForScope({
    required String clientId,
    required String siteId,
  }) {
    final normalizedClientId = clientId.trim();
    final normalizedSiteId = siteId.trim();
    if (normalizedClientId.isEmpty || normalizedSiteId.isEmpty) {
      return const ClientCommsDeliveryReadiness();
    }
    _ensureClientCommsDeliveryReadiness(normalizedClientId, normalizedSiteId);
    return _clientCommsDeliveryReadinessByScope[_clientCommsScopeKey(
          normalizedClientId,
          normalizedSiteId,
        )] ??
        _clientCommsDeliveryPolicy.evaluate(
          telegramBridgeConfigured: _telegramBridge.isConfigured,
          telegramTargetCount: _fallbackTelegramTargetCountForScope(
            normalizedClientId,
            normalizedSiteId,
          ),
          telegramHealthLabel: _telegramBridgeHealthLabel,
          telegramFallbackActive: _telegramBridgeFallbackToInApp,
          telegramEndpointMappingAmbiguous: false,
          smsProviderConfigured: _smsFallbackProviderConfigured,
          phoneContactCount: 0,
          voipProviderConfigured: _voipProviderConfigured,
        );
  }

  List<TelegramAiPendingDraftView> _telegramAiPendingDraftViews() {
    return _telegramAiPendingDrafts
        .map((draft) {
          final learnedRewriteEntries =
              _telegramAiApprovedRewriteEntriesForScope(
                draft.clientId,
                draft.siteId,
              );
          final learnedRewriteExamples = learnedRewriteEntries
              .map((entry) => entry.text)
              .toList(growable: false);
          final strongestLearnedRewrite = learnedRewriteEntries.isEmpty
              ? null
              : learnedRewriteEntries.first;
          final learnedRewritePreviews = learnedRewriteEntries
              .take(3)
              .map(
                (entry) => TelegramAiLearnedStylePreviewView(
                  text: entry.text,
                  operatorTag: entry.operatorTag,
                  approvalCount: entry.approvalCount,
                  lastApprovedAtUtc: entry.lastApprovedAtUtc,
                  lastUsedAtUtc: entry.lastUsedAtUtc,
                ),
              )
              .toList(growable: false);
          return TelegramAiPendingDraftView(
            updateId: draft.inboundUpdateId,
            audience: draft.audience,
            clientId: draft.clientId,
            siteId: draft.siteId,
            matchesSelectedScope:
                draft.clientId.trim() == _selectedClient.trim() &&
                draft.siteId.trim() == _selectedSite.trim(),
            chatId: draft.chatId,
            messageThreadId: draft.messageThreadId,
            sourceText: draft.sourceText,
            draftText: draft.draftText,
            providerLabel: draft.providerLabel,
            clientProfileOverrideSignal:
                _telegramAiClientProfileOverrideForScope(
                  draft.clientId,
                  draft.siteId,
                ) ??
                '',
            learnedRewriteCount: learnedRewriteExamples.length,
            learnedRewriteExample: learnedRewriteExamples.isEmpty
                ? ''
                : learnedRewriteExamples.first,
            learnedRewriteTag: strongestLearnedRewrite?.operatorTag ?? '',
            learnedRewriteApprovalCount:
                strongestLearnedRewrite?.approvalCount ?? 0,
            learnedRewriteLastApprovedAtUtc:
                strongestLearnedRewrite?.lastApprovedAtUtc,
            learnedRewriteLastUsedAtUtc: strongestLearnedRewrite?.lastUsedAtUtc,
            learnedRewritePreviews: learnedRewritePreviews,
            usesLearnedApprovalStyle: draft.usedLearnedApprovalStyle,
            createdAtUtc: draft.createdAtUtc,
          );
        })
        .toList(growable: false);
  }

  bool _isOnyxClientConversationMessage(ClientAppMessage message) {
    final author = message.author.trim().toLowerCase();
    if (author.contains('onyx')) {
      return true;
    }
    final provider = message.messageProvider.trim().toLowerCase();
    return provider.startsWith('onyx') || provider == 'ai_policy';
  }

  ClientAppMessage? _latestClientLaneReplyForMessages(
    List<ClientAppMessage> messages,
  ) {
    return messages
        .where(
          (message) =>
              message.body.trim().isNotEmpty &&
              (_isOnyxClientConversationMessage(message) ||
                  message.viewerRole.trim().toLowerCase() ==
                      ClientAppViewerRole.control.name),
        )
        .fold<ClientAppMessage?>(
          null,
          (latest, message) =>
              latest == null || message.occurredAt.isAfter(latest.occurredAt)
              ? message
              : latest,
        );
  }

  List<ClientAppMessage> _mergeConversationMessageIntoScopedCache(
    List<ClientAppMessage> existingMessages,
    ClientAppMessage message,
  ) {
    final nextMessages = <ClientAppMessage>[
      message,
      ...existingMessages.where(
        (candidate) =>
            candidate.author != message.author ||
            candidate.body != message.body ||
            !candidate.occurredAt.isAtSameMomentAs(message.occurredAt) ||
            candidate.roomKey != message.roomKey ||
            candidate.viewerRole != message.viewerRole ||
            candidate.incidentStatusLabel != message.incidentStatusLabel ||
            candidate.messageSource != message.messageSource ||
            candidate.messageProvider != message.messageProvider,
      ),
    ]..sort((left, right) => right.occurredAt.compareTo(left.occurredAt));
    return nextMessages;
  }

  ClientsLiveFollowUpNotice? _latestLiveFollowUpNoticeForScope(
    String clientId,
    String siteId,
  ) {
    final normalizedClientId = clientId.trim();
    final normalizedSiteId = siteId.trim();
    if (normalizedClientId.isEmpty || normalizedSiteId.isEmpty) {
      return null;
    }
    final messages =
        normalizedClientId == _selectedClient &&
            normalizedSiteId == _selectedSite
        ? _clientAppMessages
        : (_clientConversationMessagesByScope[_clientCommsScopeKey(
                normalizedClientId,
                normalizedSiteId,
              )] ??
              const <ClientAppMessage>[]);
    final latest = messages
        .where(
          (message) =>
              message.body.trim().isNotEmpty &&
              message.incidentStatusLabel.trim().toLowerCase() ==
                  'client follow-up sent',
        )
        .fold<ClientAppMessage?>(
          null,
          (current, message) =>
              current == null || message.occurredAt.isAfter(current.occurredAt)
              ? message
              : current,
        );
    if (latest == null) {
      return null;
    }
    final resolvedByControlReply = messages.any((message) {
      if (!message.occurredAt.isAfter(latest.occurredAt)) {
        return false;
      }
      if (!_isOnyxClientConversationMessage(message)) {
        return false;
      }
      final label = message.incidentStatusLabel.trim().toLowerCase();
      return label == 'control reply sent' ||
          label == 'approved reply sent' ||
          label == 'reply sent';
    });
    if (resolvedByControlReply) {
      return null;
    }
    final latestClientAsk = messages
        .where(
          (message) =>
              message.body.trim().isNotEmpty &&
              !_isOnyxClientConversationMessage(message) &&
              message.viewerRole.trim().toLowerCase() !=
                  ClientAppViewerRole.control.name &&
              !message.occurredAt.isAfter(latest.occurredAt),
        )
        .fold<ClientAppMessage?>(
          null,
          (current, message) =>
              current == null || message.occurredAt.isAfter(current.occurredAt)
              ? message
              : current,
        );
    final siteReference = _monitoringSiteProfileFor(
      clientId: normalizedClientId,
      siteId: normalizedSiteId,
    ).siteName;
    final suggestedReplyDraft =
        _truthGroundedReplyDraftForCriticalTelegramFollowUp(
          siteReference: siteReference,
          latestClientAsk: latestClientAsk?.body ?? '',
          recentMessages: messages,
        ) ??
        _suggestedReplyDraftForCriticalTelegramFollowUp(
          siteReference: siteReference,
          followUpBody: latest.body,
          latestClientAsk: latestClientAsk?.body ?? '',
        );
    return ClientsLiveFollowUpNotice(
      id: 'live-follow-up-${latest.occurredAt.microsecondsSinceEpoch}',
      author: latest.author,
      body: latest.body,
      room: latest.roomKey.trim().isEmpty
          ? latest.viewerRole.trim().toLowerCase() ==
                    ClientAppViewerRole.control.name
                ? 'Security Desk'
                : 'Residents'
          : latest.roomKey.trim(),
      occurredAtUtc: latest.occurredAt.toUtc(),
      urgent: true,
      suggestedReplyDraft: suggestedReplyDraft,
    );
  }

  Future<String> _draftClientsLiveFollowUpReplyForScope(
    ClientsLiveFollowUpNotice notice,
    String clientId,
    String siteId,
  ) async {
    final normalizedClientId = clientId.trim();
    final normalizedSiteId = siteId.trim();
    if (normalizedClientId.isEmpty || normalizedSiteId.isEmpty) {
      return notice.suggestedReplyDraft.trim();
    }
    final siteReference = _monitoringSiteProfileFor(
      clientId: normalizedClientId,
      siteId: normalizedSiteId,
    ).siteName;
    final recentMessages = await _readConversationMessagesForScope(
      clientId: normalizedClientId,
      siteId: normalizedSiteId,
      limit: 10,
    );
    final latestClientAsk =
        recentMessages
            .where(
              (message) =>
                  message.body.trim().isNotEmpty &&
                  !_isOnyxClientConversationMessage(message) &&
                  message.viewerRole.trim().toLowerCase() !=
                      ClientAppViewerRole.control.name &&
                  !message.occurredAt.isAfter(notice.occurredAtUtc),
            )
            .fold<ClientAppMessage?>(
              null,
              (current, message) =>
                  current == null ||
                      message.occurredAt.isAfter(current.occurredAt)
                  ? message
                  : current,
            )
            ?.body
            .trim() ??
        '';
    final truthGroundedDraft =
        _truthGroundedReplyDraftForCriticalTelegramFollowUp(
          siteReference: siteReference,
          latestClientAsk: latestClientAsk,
          recentMessages: recentMessages,
        );
    final fallbackDraft = notice.suggestedReplyDraft.trim().isNotEmpty
        ? truthGroundedDraft ?? notice.suggestedReplyDraft.trim()
        : _suggestedReplyDraftForCriticalTelegramFollowUp(
            siteReference: siteReference,
            followUpBody: notice.body,
            latestClientAsk: latestClientAsk,
          );
    if (!_telegramAiAssistantEnabled) {
      return fallbackDraft;
    }
    final aiContext = await _telegramAiClientDraftingContextForScope(
      clientId: normalizedClientId,
      siteId: normalizedSiteId,
      messageText: latestClientAsk.isNotEmpty ? latestClientAsk : notice.body,
      limit: 10,
    );
    TelegramAiDraftReply aiDraft;
    try {
      aiDraft = await _telegramAiAssistant
          .draftReply(
            audience: TelegramAiAudience.client,
            messageText: latestClientAsk.isNotEmpty
                ? latestClientAsk
                : 'Client requested a follow-up update for $siteReference.',
            clientId: normalizedClientId,
            siteId: normalizedSiteId,
            deliveryMode: TelegramAiDeliveryMode.approvalDraft,
            clientProfileSignals: aiContext.clientProfileSignals,
            preferredReplyExamples: aiContext.preferredReplyExamples,
            preferredReplyStyleTags: aiContext.preferredReplyStyleTags,
            learnedReplyExamples: aiContext.learnedReplyExamples,
            learnedReplyStyleTags: aiContext.learnedReplyStyleTags,
            recentConversationTurns: <String>[
              'Latest client follow-up already sent: ${_singleLine(notice.body, maxLength: 160)}',
              ...aiContext.recentConversationTurns,
            ],
            cameraHealthFactPacket: aiContext.cameraHealthFactPacket,
          )
          .timeout(const Duration(seconds: 5));
    } on TimeoutException {
      return fallbackDraft;
    }
    final aiDraftText = aiDraft.text.trim();
    if (aiDraftText.isEmpty) {
      return fallbackDraft;
    }
    if (truthGroundedDraft != null &&
        _looksGenericCriticalFollowUpReply(aiDraftText)) {
      return truthGroundedDraft;
    }
    return aiDraftText;
  }

  String? _truthGroundedReplyDraftForCriticalTelegramFollowUp({
    required String siteReference,
    required String latestClientAsk,
    required List<ClientAppMessage> recentMessages,
  }) {
    final normalizedAsk = normalizeTelegramClientPromptSignalText(
      latestClientAsk,
    );
    if (normalizedAsk.isEmpty) {
      return null;
    }
    final asksIfEverythingIsOkay = _asksIfEverythingIsOkayForCriticalFollowUp(
      normalizedAsk,
    );
    if (!asksIfEverythingIsOkay) {
      return null;
    }
    final joined = recentMessages
        .map((message) {
          final status = message.incidentStatusLabel.trim().toLowerCase();
          final provider = message.messageProvider.trim().toLowerCase();
          final body = message.body.trim().toLowerCase();
          return '$status\n$provider\n$body';
        })
        .where((value) => value.trim().isNotEmpty)
        .join('\n');
    if (joined.isEmpty) {
      return null;
    }
    final telemetrySummaryVisible =
        joined.contains('site activity summary') ||
        joined.contains('site telemetry') ||
        joined.contains('latest site activity');
    if (!telemetrySummaryVisible) {
      return null;
    }
    final latestResponseArrival =
        joined.contains('field response unit arrived on site') ||
        joined.contains(
          'latest field signal: a field response unit arrived on site',
        ) ||
        joined.contains('latest field signal: response arrival') ||
        joined.contains('response arrival');
    final noOpenIncident =
        joined.contains('not sitting as an open incident now') ||
        joined.contains('open follow-ups: 0') ||
        joined.contains('no client-facing action has been required');
    final remoteMonitoringOffline =
        joined.contains('temporarily without remote monitoring') ||
        joined.contains('remote monitoring is offline') ||
        joined.contains('remote watch is temporarily unavailable') ||
        joined.contains('monitoring path is offline');
    final telemetryLead = latestResponseArrival
        ? 'The latest ONYX telemetry shows a response unit arrival at $siteReference'
        : 'The latest ONYX telemetry shows recent field activity at $siteReference';
    final openIncidentDetail = noOpenIncident
        ? ' and nothing is currently sitting as an open incident'
        : '';
    final visualQualifier = remoteMonitoringOffline
        ? 'but remote monitoring is offline, so I cannot confirm visually from here right now.'
        : 'but I do not have live visual confirmation right now.';
    return '$telemetryLead$openIncidentDetail, $visualQualifier If you want, I can ask control for a manual follow-up.';
  }

  bool _looksGenericCriticalFollowUpReply(String text) {
    final normalized = text.trim().toLowerCase();
    if (normalized.isEmpty) {
      return true;
    }
    return normalized.contains('we are checking') &&
        (normalized.contains('next confirmed step') ||
            normalized.contains('next on-site step') ||
            normalized.contains('will update you here'));
  }

  String _suggestedReplyDraftForCriticalTelegramFollowUp({
    required String siteReference,
    required String followUpBody,
    required String latestClientAsk,
  }) {
    final normalizedSiteReference = siteReference.trim().isEmpty
        ? 'the site'
        : siteReference.trim();
    final normalizedBody = followUpBody.trim().toLowerCase();
    final normalizedAsk = normalizeTelegramClientPromptSignalText(
      latestClientAsk,
    );
    final asksIfEverythingIsOkay = _asksIfEverythingIsOkayForCriticalFollowUp(
      normalizedAsk,
    );
    final mentionsAccess =
        normalizedBody.contains('access') ||
        normalizedBody.contains('gate') ||
        normalizedAsk.contains('gate') ||
        normalizedAsk.contains('entrance');
    final onSiteAlready =
        normalizedBody.contains('already on site') ||
        normalizedBody.contains('on site');
    if (onSiteAlready && asksIfEverythingIsOkay) {
      return 'Security is already on site at $normalizedSiteReference and control is following up now. I will confirm here as soon as the team verifies whether everything is okay.';
    }
    if (mentionsAccess) {
      return 'Control is following up specifically on access at $normalizedSiteReference now. I will confirm here as soon as the next verified update comes in.';
    }
    if (asksIfEverythingIsOkay) {
      return 'Control is following up at $normalizedSiteReference now. I will confirm here as soon as we have a verified update on whether everything is okay.';
    }
    return 'Control is following up at $normalizedSiteReference now. I will confirm here as soon as the next verified update comes in.';
  }

  bool _asksIfEverythingIsOkayForCriticalFollowUp(String normalizedAsk) {
    if (normalizedAsk.trim().isEmpty) {
      return false;
    }
    return asksForTelegramClientBroadStatusCheck(normalizedAsk) ||
        normalizedAsk.contains('all okay') ||
        normalizedAsk.contains('is it okay') ||
        normalizedAsk.contains('you sure') ||
        normalizedAsk.contains('are you sure') ||
        normalizedAsk.contains('safe');
  }

  Future<String?> _draftClientComposerAiReplyForScope({
    required String clientId,
    required String siteId,
    required String room,
    required String currentDraftText,
  }) async {
    final normalizedClientId = clientId.trim();
    final normalizedSiteId = siteId.trim();
    final normalizedRoom = room.trim();
    final normalizedDraftText = currentDraftText.trim();
    if (normalizedClientId.isEmpty || normalizedSiteId.isEmpty) {
      return normalizedDraftText.isEmpty ? null : normalizedDraftText;
    }
    final recentMessages = await _readConversationMessagesForScope(
      clientId: normalizedClientId,
      siteId: normalizedSiteId,
      limit: 12,
    );
    final roomMessages = recentMessages
        .where(
          (message) =>
              normalizedRoom.isEmpty ||
              message.roomKey.trim().toLowerCase() ==
                  normalizedRoom.toLowerCase(),
        )
        .toList(growable: false);
    final latestClientAsk =
        roomMessages
            .where(
              (message) =>
                  message.body.trim().isNotEmpty &&
                  !_isOnyxClientConversationMessage(message) &&
                  message.viewerRole.trim().toLowerCase() !=
                      ClientAppViewerRole.control.name,
            )
            .fold<ClientAppMessage?>(
              null,
              (current, message) =>
                  current == null ||
                      message.occurredAt.isAfter(current.occurredAt)
                  ? message
                  : current,
            )
            ?.body
            .trim() ??
        '';
    if (latestClientAsk.isEmpty && normalizedDraftText.isEmpty) {
      return null;
    }
    if (!_telegramAiAssistantEnabled) {
      return normalizedDraftText.isEmpty
          ? latestClientAsk
          : normalizedDraftText;
    }
    final aiContext = await _telegramAiClientDraftingContextForScope(
      clientId: normalizedClientId,
      siteId: normalizedSiteId,
      messageText: normalizedDraftText.isNotEmpty
          ? normalizedDraftText
          : latestClientAsk,
      limit: 12,
    );
    final prompt = latestClientAsk.isNotEmpty
        ? normalizedDraftText.isNotEmpty
              ? 'Client asked: ${_singleLine(latestClientAsk, maxLength: 160)}\n'
                    'Current operator draft: ${_singleLine(normalizedDraftText, maxLength: 220)}\n'
                    'Refine the operator draft into a calm, send-ready client reply. Preserve the confirmed facts and intended action from the draft unless the recent lane context clearly contradicts them. Do not switch to a different issue or offer a new action unless the client asked for it.'
              : latestClientAsk
        : 'Please refine this operator draft into a calm, send-ready client reply. Preserve the confirmed facts and intended action from the draft unless the recent lane context clearly contradicts them: ${_singleLine(normalizedDraftText, maxLength: 220)}';
    TelegramAiDraftReply aiDraft;
    try {
      aiDraft = await _telegramAiAssistant
          .draftReply(
            audience: TelegramAiAudience.client,
            messageText: prompt,
            clientId: normalizedClientId,
            siteId: normalizedSiteId,
            deliveryMode: TelegramAiDeliveryMode.approvalDraft,
            clientProfileSignals: aiContext.clientProfileSignals,
            preferredReplyExamples: aiContext.preferredReplyExamples,
            preferredReplyStyleTags: aiContext.preferredReplyStyleTags,
            learnedReplyExamples: aiContext.learnedReplyExamples,
            learnedReplyStyleTags: aiContext.learnedReplyStyleTags,
            recentConversationTurns: <String>[
              if (normalizedRoom.isNotEmpty)
                'Active reply lane: $normalizedRoom',
              if (normalizedDraftText.isNotEmpty)
                'Current operator draft: ${_singleLine(normalizedDraftText, maxLength: 160)}',
              ...aiContext.recentConversationTurns,
            ],
            cameraHealthFactPacket: aiContext.cameraHealthFactPacket,
          )
          .timeout(const Duration(seconds: 5));
    } on TimeoutException {
      return normalizedDraftText.isEmpty
          ? latestClientAsk
          : normalizedDraftText;
    }
    final assistedText = aiDraft.text.trim();
    if (assistedText.isNotEmpty) {
      return assistedText;
    }
    return normalizedDraftText.isEmpty ? latestClientAsk : normalizedDraftText;
  }

  ({String label, String? detail, bool fallbackActive})
  _telegramBridgeHealthForPushSyncState(
    ClientPushSyncState state, {
    required bool bridgeConfigured,
  }) {
    ClientPushSyncAttempt? latestTelegramAttempt;
    for (final attempt in state.history) {
      if (attempt.status.startsWith('telegram-')) {
        latestTelegramAttempt = attempt;
        break;
      }
    }
    if (latestTelegramAttempt == null) {
      return (
        label: bridgeConfigured ? 'configured' : 'disabled',
        detail: bridgeConfigured
            ? 'Bridge token configured. Awaiting delivery attempts.'
            : 'Telegram bridge disabled or missing bot token.',
        fallbackActive: false,
      );
    }
    switch (latestTelegramAttempt.status) {
      case 'telegram-ok':
        return (
          label: 'ok',
          detail: 'Last Telegram delivery succeeded.',
          fallbackActive: false,
        );
      case 'telegram-blocked':
        return (
          label: 'blocked',
          detail: latestTelegramAttempt.failureReason,
          fallbackActive: true,
        );
      case 'telegram-skipped':
        return (
          label: 'no-target',
          detail: latestTelegramAttempt.failureReason,
          fallbackActive: true,
        );
      case 'telegram-failed':
        return (
          label: 'degraded',
          detail: latestTelegramAttempt.failureReason,
          fallbackActive: false,
        );
      default:
        return (
          label: bridgeConfigured ? 'configured' : 'disabled',
          detail: bridgeConfigured
              ? 'Bridge token configured. Awaiting delivery attempts.'
              : 'Telegram bridge disabled or missing bot token.',
          fallbackActive: false,
        );
    }
  }

  List<LiveControlInboxClientAsk> _unresolvedClientAsksForScope({
    required String clientId,
    required String siteId,
    required List<ClientAppMessage> messages,
    required bool matchesSelectedScope,
    int limit = 1,
  }) {
    final normalizedClientId = clientId.trim();
    final normalizedSiteId = siteId.trim();
    if (normalizedClientId.isEmpty || normalizedSiteId.isEmpty) {
      return const <LiveControlInboxClientAsk>[];
    }
    if (_telegramAiPendingDrafts.any(
      (draft) =>
          draft.audience.trim().toLowerCase() == 'client' &&
          draft.clientId.trim() == normalizedClientId &&
          draft.siteId.trim() == normalizedSiteId,
    )) {
      return const <LiveControlInboxClientAsk>[];
    }
    final clientMessages =
        messages
            .where(
              (message) =>
                  message.body.trim().isNotEmpty &&
                  message.viewerRole.trim().toLowerCase() ==
                      ClientAppViewerRole.client.name &&
                  !_isOnyxClientConversationMessage(message),
            )
            .toList(growable: false)
          ..sort((a, b) => b.occurredAt.compareTo(a.occurredAt));
    if (clientMessages.isEmpty) {
      return const <LiveControlInboxClientAsk>[];
    }
    final latestLaneReplyAtUtc = _latestClientLaneReplyForMessages(
      messages,
    )?.occurredAt;
    final latestPendingDraftAtUtc = _telegramAiPendingDrafts
        .where(
          (draft) =>
              draft.audience.trim().toLowerCase() == 'client' &&
              draft.clientId.trim() == normalizedClientId &&
              draft.siteId.trim() == normalizedSiteId,
        )
        .map((draft) => draft.createdAtUtc)
        .fold<DateTime?>(
          null,
          (latest, occurredAt) => latest == null || occurredAt.isAfter(latest)
              ? occurredAt
              : latest,
        );
    final latestHandledAtUtc = [latestLaneReplyAtUtc, latestPendingDraftAtUtc]
        .whereType<DateTime>()
        .fold<DateTime?>(
          null,
          (latest, occurredAt) => latest == null || occurredAt.isAfter(latest)
              ? occurredAt
              : latest,
        );
    return clientMessages
        .where(
          (message) =>
              latestHandledAtUtc == null ||
              message.occurredAt.isAfter(latestHandledAtUtc),
        )
        .take(limit)
        .map(
          (message) => LiveControlInboxClientAsk(
            clientId: normalizedClientId,
            siteId: normalizedSiteId,
            author: message.author.trim(),
            body: _singleLine(message.body, maxLength: 220),
            messageProvider: message.messageProvider.trim(),
            occurredAtUtc: message.occurredAt,
            matchesSelectedScope: matchesSelectedScope,
          ),
        )
        .toList(growable: false);
  }

  List<ClientCommsAuditView> _clientCommsAuditViews() {
    final scopeKeys = <String>{
      _clientCommsScopeKey(_selectedClient, _selectedSite),
      ..._latestSmsFallbackUpdateByScope.keys,
      ..._latestVoipStageUpdateByScope.keys,
      ..._clientCommsDeliveryReadinessByScope.keys,
      ..._clientConversationMessagesByScope.keys,
      ..._clientPushQueueByScope.keys,
      ..._clientPushSyncStateByScope.keys,
      ..._telegramAiClientProfileOverrideByScope.keys,
      ..._telegramAiApprovedRewriteExamplesByScope.keys,
      ..._telegramAiPendingDrafts
          .where(
            (draft) =>
                draft.audience.trim().toLowerCase() == 'client' &&
                draft.clientId.trim().isNotEmpty &&
                draft.siteId.trim().isNotEmpty,
          )
          .map((draft) => _clientCommsScopeKey(draft.clientId, draft.siteId)),
    };
    final views = <ClientCommsAuditView>[];
    for (final scopeKey in scopeKeys) {
      final parts = scopeKey.split('|');
      if (parts.length != 2) {
        continue;
      }
      final clientId = parts.first.trim();
      final siteId = parts.last.trim();
      if (clientId.isEmpty || siteId.isEmpty) {
        continue;
      }
      _ensureClientCommsDeliveryReadiness(clientId, siteId);
      final deliveryReadiness = _clientCommsDeliveryReadinessForScope(
        clientId: clientId,
        siteId: siteId,
      );
      final latestSmsFallbackUpdate = _latestSmsFallbackUpdateForScope(
        clientId,
        siteId,
      );
      final latestVoipStageUpdate = _latestVoipStageUpdateForScope(
        clientId,
        siteId,
      );
      final scopedStateKey = _clientCommsScopeKey(clientId, siteId);
      final selectedScope =
          clientId == _selectedClient.trim() && siteId == _selectedSite.trim();
      final scopedPendingDrafts = _telegramAiPendingDrafts
          .where(
            (draft) =>
                draft.audience.trim().toLowerCase() == 'client' &&
                draft.clientId.trim() == clientId &&
                draft.siteId.trim() == siteId,
          )
          .toList(growable: false);
      final pendingApprovalCount = scopedPendingDrafts.length;
      final pendingLearnedStyleDraftCount = scopedPendingDrafts
          .where((draft) => draft.usedLearnedApprovalStyle)
          .length;
      final learnedApprovalStyleEntries =
          _telegramAiApprovedRewriteEntriesForScope(clientId, siteId);
      final learnedApprovalStyleExamples = learnedApprovalStyleEntries
          .map((entry) => entry.text)
          .toList(growable: false);
      final strongestLearnedApprovalStyle = learnedApprovalStyleEntries.isEmpty
          ? null
          : learnedApprovalStyleEntries.first;
      final learnedApprovalStylePreviews = learnedApprovalStyleEntries
          .take(3)
          .map(
            (entry) => TelegramAiLearnedStylePreviewView(
              text: entry.text,
              operatorTag: entry.operatorTag,
              approvalCount: entry.approvalCount,
              lastApprovedAtUtc: entry.lastApprovedAtUtc,
              lastUsedAtUtc: entry.lastUsedAtUtc,
            ),
          )
          .toList(growable: false);
      final scopeMessages = selectedScope
          ? _clientAppMessages
          : _clientConversationMessagesByScope[scopedStateKey] ??
                const <ClientAppMessage>[];
      final scopedPushQueue = selectedScope
          ? _clientAppPushQueue
          : (_clientPushQueueByScope[scopedStateKey] ??
                const <ClientAppPushDeliveryItem>[]);
      final scopedPushSyncState = selectedScope
          ? ClientPushSyncState(
              statusLabel: _clientAppPushSyncStatusLabel,
              lastSyncedAtUtc: _clientAppPushLastSyncedAtUtc,
              failureReason: _clientAppPushSyncFailureReason,
              retryCount: _clientAppPushSyncRetryCount,
              history: _clientAppPushSyncHistory,
              telegramDeliveredMessageKeys:
                  _clientAppTelegramDeliveredMessageKeys,
              backendProbeStatusLabel: _clientAppBackendProbeStatusLabel,
              backendProbeLastRunAtUtc: _clientAppBackendProbeLastRunAtUtc,
              backendProbeFailureReason: _clientAppBackendProbeFailureReason,
              backendProbeHistory: _clientAppBackendProbeHistory,
            )
          : (_clientPushSyncStateByScope[scopedStateKey] ??
                const ClientPushSyncState.idle());
      final recentDeliveryHistoryLines = _clientCommsHistorySummaryLines(
        scopedPushSyncState.history,
      );
      final unresolvedClientAsks = _unresolvedClientAsksForScope(
        clientId: clientId,
        siteId: siteId,
        messages: scopeMessages,
        matchesSelectedScope: selectedScope,
      );
      final latestLaneReply = _latestClientLaneReplyForMessages(scopeMessages);
      final profileOverrideSignal =
          _telegramAiClientProfileOverrideForScope(clientId, siteId) ?? '';
      final scopedTelegramHealth = selectedScope
          ? (
              label: _telegramBridgeHealthLabel,
              detail: (_telegramBridgeHealthDetail ?? '').trim().isEmpty
                  ? null
                  : _telegramBridgeHealthDetail!.trim(),
              fallbackActive: _telegramBridgeFallbackToInApp,
            )
          : _telegramBridgeHealthForPushSyncState(
              scopedPushSyncState,
              bridgeConfigured: _telegramBridge.isConfigured,
            );
      if (latestSmsFallbackUpdate == null &&
          latestVoipStageUpdate == null &&
          pendingApprovalCount <= 0 &&
          unresolvedClientAsks.isEmpty &&
          learnedApprovalStyleExamples.isEmpty &&
          latestLaneReply == null &&
          scopedPushQueue.isEmpty &&
          scopedPushSyncState.statusLabel.trim().toLowerCase() == 'idle' &&
          (scopedPushSyncState.failureReason ?? '').trim().isEmpty &&
          profileOverrideSignal.trim().isEmpty) {
        continue;
      }
      views.add(
        ClientCommsAuditView(
          clientId: clientId,
          siteId: siteId,
          matchesSelectedScope: selectedScope,
          pendingApprovalCount: pendingApprovalCount,
          awaitingResponseCount: unresolvedClientAsks.length,
          pendingLearnedStyleDraftCount: pendingLearnedStyleDraftCount,
          learnedApprovalStyleCount: learnedApprovalStyleExamples.length,
          learnedApprovalStyleExample: learnedApprovalStyleExamples.isEmpty
              ? ''
              : learnedApprovalStyleExamples.first,
          learnedApprovalStyleTag:
              strongestLearnedApprovalStyle?.operatorTag ?? '',
          learnedApprovalStyleApprovalCount:
              strongestLearnedApprovalStyle?.approvalCount ?? 0,
          learnedApprovalStyleLastApprovedAtUtc:
              strongestLearnedApprovalStyle?.lastApprovedAtUtc,
          learnedApprovalStyleLastUsedAtUtc:
              strongestLearnedApprovalStyle?.lastUsedAtUtc,
          learnedApprovalStylePreviews: learnedApprovalStylePreviews,
          latestClientAskBody: unresolvedClientAsks.isEmpty
              ? ''
              : unresolvedClientAsks.first.body,
          latestClientAskAtUtc: unresolvedClientAsks.isEmpty
              ? null
              : unresolvedClientAsks.first.occurredAtUtc,
          latestLaneReplyBody: latestLaneReply == null
              ? ''
              : _singleLine(latestLaneReply.body, maxLength: 220),
          latestLaneReplyAtUtc: latestLaneReply?.occurredAt,
          queuedPushCount: scopedPushQueue
              .where((item) => item.status == ClientPushDeliveryStatus.queued)
              .length,
          pushSyncStatusLabel: scopedPushSyncState.statusLabel,
          pushSyncFailureReason:
              (scopedPushSyncState.failureReason ?? '').trim().isEmpty
              ? null
              : scopedPushSyncState.failureReason!.trim(),
          clientProfileOverrideSignal: profileOverrideSignal,
          telegramHealthLabel: scopedTelegramHealth.label,
          smsFallbackLabel: deliveryReadiness.smsFallbackLabel,
          voiceReadinessLabel: deliveryReadiness.voiceReadinessLabel,
          deliveryReadinessDetail: deliveryReadiness.detail,
          latestSmsFallbackStatus: latestSmsFallbackUpdate?.status,
          latestSmsFallbackAtUtc: latestSmsFallbackUpdate?.occurredAtUtc,
          latestVoipStageStatus: latestVoipStageUpdate?.status,
          latestVoipStageAtUtc: latestVoipStageUpdate?.occurredAtUtc,
          recentDeliveryHistoryLines: recentDeliveryHistoryLines,
        ),
      );
    }
    views.sort((a, b) {
      final aMoment =
          a.latestLaneReplyAtUtc ??
          a.latestClientAskAtUtc ??
          a.latestVoipStageAtUtc ??
          a.latestSmsFallbackAtUtc ??
          DateTime.fromMillisecondsSinceEpoch(0, isUtc: true);
      final bMoment =
          b.latestLaneReplyAtUtc ??
          b.latestClientAskAtUtc ??
          b.latestVoipStageAtUtc ??
          b.latestSmsFallbackAtUtc ??
          DateTime.fromMillisecondsSinceEpoch(0, isUtc: true);
      return bMoment.compareTo(aMoment);
    });
    return views.take(6).toList(growable: false);
  }

  LiveClientCommsSnapshot? _liveClientCommsSnapshot({
    String? clientId,
    String? siteId,
  }) {
    final requestedClientId = clientId;
    final requestedSiteId = siteId;
    final resolvedClientId = (requestedClientId ?? '').trim().isNotEmpty
        ? requestedClientId!.trim()
        : _selectedClient.trim();
    final resolvedSiteId = (requestedSiteId ?? '').trim().isNotEmpty
        ? requestedSiteId!.trim()
        : _selectedSite.trim();
    if (resolvedClientId.isEmpty || resolvedSiteId.isEmpty) {
      return null;
    }
    final deliveryReadiness = _clientCommsDeliveryReadinessForScope(
      clientId: resolvedClientId,
      siteId: resolvedSiteId,
    );
    final latestSmsFallbackUpdate = _latestSmsFallbackUpdateForScope(
      resolvedClientId,
      resolvedSiteId,
    );
    final latestVoipStageUpdate = _latestVoipStageUpdateForScope(
      resolvedClientId,
      resolvedSiteId,
    );
    final scopeKey = _clientCommsScopeKey(resolvedClientId, resolvedSiteId);
    final selectedScope =
        resolvedClientId == _selectedClient.trim() &&
        resolvedSiteId == _selectedSite.trim();

    final scopedMessagesSource = selectedScope
        ? _clientAppMessages
        : _clientConversationMessagesByScope[scopeKey] ??
              const <ClientAppMessage>[];
    final scopedMessages =
        scopedMessagesSource
            .where((message) => message.body.trim().isNotEmpty)
            .toList(growable: false)
          ..sort((a, b) => b.occurredAt.compareTo(a.occurredAt));
    final scopedPendingDrafts =
        _telegramAiPendingDrafts
            .where(
              (draft) =>
                  draft.audience.trim().toLowerCase() == 'client' &&
                  draft.clientId.trim() == resolvedClientId &&
                  draft.siteId.trim() == resolvedSiteId,
            )
            .toList(growable: false)
          ..sort((a, b) => b.createdAtUtc.compareTo(a.createdAtUtc));
    final scopedPushQueue =
        (selectedScope
                ? _clientAppPushQueue
                : (_clientPushQueueByScope[scopeKey] ??
                      const <ClientAppPushDeliveryItem>[]))
            .toList(growable: false)
          ..sort((a, b) => b.occurredAt.compareTo(a.occurredAt));
    final scopedPushSyncState = selectedScope
        ? ClientPushSyncState(
            statusLabel: _clientAppPushSyncStatusLabel,
            lastSyncedAtUtc: _clientAppPushLastSyncedAtUtc,
            failureReason: _clientAppPushSyncFailureReason,
            retryCount: _clientAppPushSyncRetryCount,
            history: _clientAppPushSyncHistory,
            telegramDeliveredMessageKeys:
                _clientAppTelegramDeliveredMessageKeys,
            backendProbeStatusLabel: _clientAppBackendProbeStatusLabel,
            backendProbeLastRunAtUtc: _clientAppBackendProbeLastRunAtUtc,
            backendProbeFailureReason: _clientAppBackendProbeFailureReason,
            backendProbeHistory: _clientAppBackendProbeHistory,
          )
        : (_clientPushSyncStateByScope[scopeKey] ??
              const ClientPushSyncState.idle());
    final recentDeliveryHistoryLines = _clientCommsHistorySummaryLines(
      scopedPushSyncState.history,
    );
    final scopedTelegramHealth = selectedScope
        ? (
            label: _telegramBridgeHealthLabel,
            detail: (_telegramBridgeHealthDetail ?? '').trim().isEmpty
                ? null
                : _telegramBridgeHealthDetail!.trim(),
            fallbackActive: _telegramBridgeFallbackToInApp,
          )
        : _telegramBridgeHealthForPushSyncState(
            scopedPushSyncState,
            bridgeConfigured: _telegramBridge.isConfigured,
          );

    final latestClientMessage = scopedMessages
        .cast<ClientAppMessage?>()
        .firstWhere(
          (message) =>
              message != null &&
              message.viewerRole.trim().toLowerCase() ==
                  ClientAppViewerRole.client.name &&
              !_isOnyxClientConversationMessage(message),
          orElse: () => null,
        );
    final latestOnyxReply = _latestClientLaneReplyForMessages(scopedMessages);
    final latestPendingDraft = scopedPendingDrafts.isEmpty
        ? null
        : scopedPendingDrafts.first;
    final learnedApprovalStyleExamples =
        _telegramAiApprovedRewriteExamplesForScope(
          resolvedClientId,
          resolvedSiteId,
        );
    final clientVoiceProfileLabel = _telegramAiClientProfileDisplayLabel(
      _telegramAiClientProfileOverrideForScope(
        resolvedClientId,
        resolvedSiteId,
      ),
    );

    return LiveClientCommsSnapshot(
      clientId: resolvedClientId,
      siteId: resolvedSiteId,
      clientVoiceProfileLabel: clientVoiceProfileLabel,
      learnedApprovalStyleCount: learnedApprovalStyleExamples.length,
      learnedApprovalStyleExample: learnedApprovalStyleExamples.isEmpty
          ? ''
          : learnedApprovalStyleExamples.first,
      pendingLearnedStyleDraftCount: scopedPendingDrafts
          .where((draft) => draft.usedLearnedApprovalStyle)
          .length,
      totalMessages: scopedMessages.length,
      clientInboundCount: scopedMessages
          .where(
            (message) =>
                message.viewerRole.trim().toLowerCase() ==
                    ClientAppViewerRole.client.name &&
                !_isOnyxClientConversationMessage(message),
          )
          .length,
      pendingApprovalCount: scopedPendingDrafts.length,
      queuedPushCount: scopedPushQueue
          .where((item) => item.status == ClientPushDeliveryStatus.queued)
          .length,
      telegramHealthLabel: scopedTelegramHealth.label,
      telegramHealthDetail: scopedTelegramHealth.detail,
      telegramFallbackActive: scopedTelegramHealth.fallbackActive,
      pushSyncStatusLabel: scopedPushSyncState.statusLabel,
      pushSyncFailureReason:
          (scopedPushSyncState.failureReason ?? '').trim().isEmpty
          ? null
          : scopedPushSyncState.failureReason!.trim(),
      smsFallbackLabel: deliveryReadiness.smsFallbackLabel,
      smsFallbackReady: deliveryReadiness.smsFallbackReady,
      smsFallbackEligibleNow: deliveryReadiness.smsFallbackEligibleNow,
      voiceReadinessLabel: deliveryReadiness.voiceReadinessLabel,
      deliveryReadinessDetail: deliveryReadiness.detail,
      latestSmsFallbackStatus: latestSmsFallbackUpdate?.status,
      latestSmsFallbackAtUtc: latestSmsFallbackUpdate?.occurredAtUtc,
      latestVoipStageStatus: latestVoipStageUpdate?.status,
      latestVoipStageAtUtc: latestVoipStageUpdate?.occurredAtUtc,
      recentDeliveryHistoryLines: recentDeliveryHistoryLines,
      latestClientMessage: latestClientMessage == null
          ? null
          : _singleLine(latestClientMessage.body, maxLength: 180),
      latestClientMessageAtUtc: latestClientMessage?.occurredAt,
      latestOnyxReply: latestOnyxReply == null
          ? null
          : _singleLine(latestOnyxReply.body, maxLength: 180),
      latestOnyxReplyAtUtc: latestOnyxReply?.occurredAt,
      latestPendingDraft: latestPendingDraft == null
          ? null
          : _singleLine(latestPendingDraft.draftText, maxLength: 180),
      latestPendingDraftAtUtc: latestPendingDraft?.createdAtUtc,
    );
  }

  List<String> _clientCommsHistorySummaryLines(
    List<ClientPushSyncAttempt> history, {
    int limit = 3,
  }) {
    if (history.isEmpty) {
      return const <String>[];
    }
    return history
        .take(limit)
        .map((attempt) {
          final occurredAt = attempt.occurredAt.toUtc();
          final hh = occurredAt.hour.toString().padLeft(2, '0');
          final mm = occurredAt.minute.toString().padLeft(2, '0');
          final status = _humanizedClientCommsHistoryStatus(attempt.status);
          final reason = (attempt.failureReason ?? '').trim();
          final prefix = '$hh:$mm UTC • $status • queue:${attempt.queueSize}';
          if (reason.isEmpty) {
            return prefix;
          }
          return '$prefix • ${ClientDeliveryMessageFormatter.humanizeScopedCommsSummary(reason)}';
        })
        .toList(growable: false);
  }

  String _humanizedClientCommsHistoryStatus(String raw) {
    final normalized = raw.trim().toLowerCase();
    return switch (normalized) {
      '' => 'standing by',
      'idle' => 'standing by',
      'ok' => 'synced',
      'failed' => 'needs review',
      'syncing' => 'sync in flight',
      'degraded' => 'delivery under watch',
      'sms-fallback-ok' => 'sms fallback sent',
      'telegram-blocked' => 'telegram blocked',
      'telegram-failed' => 'telegram failed',
      'voip-staged' => 'voip staged',
      'voip-failed' => 'voip needs review',
      _ => raw,
    };
  }

  LiveControlInboxSnapshot _liveControlInboxSnapshot({
    String? clientId,
    String? siteId,
  }) {
    final requestedClientId = clientId;
    final requestedSiteId = siteId;
    final resolvedClientId = (requestedClientId ?? '').trim().isNotEmpty
        ? requestedClientId!.trim()
        : _selectedClient.trim();
    final resolvedSiteId = (requestedSiteId ?? '').trim().isNotEmpty
        ? requestedSiteId!.trim()
        : _selectedSite.trim();
    final pendingDrafts =
        _telegramAiPendingDrafts
            .where((draft) => draft.audience.trim().toLowerCase() == 'client')
            .toList(growable: false)
          ..sort((a, b) => b.createdAtUtc.compareTo(a.createdAtUtc));
    final selectedScopeClientVoiceProfileLabel =
        _telegramAiClientProfileDisplayLabel(
          _telegramAiClientProfileOverrideForScope(
            resolvedClientId,
            resolvedSiteId,
          ),
        );
    final inboxDrafts = pendingDrafts
        .take(6)
        .map(
          (draft) => LiveControlInboxDraft(
            updateId: draft.inboundUpdateId,
            clientId: draft.clientId,
            siteId: draft.siteId,
            sourceText: _singleLine(draft.sourceText, maxLength: 220),
            draftText: _singleLine(draft.draftText, maxLength: 220),
            providerLabel: draft.providerLabel.trim(),
            usesLearnedApprovalStyle: draft.usedLearnedApprovalStyle,
            createdAtUtc: draft.createdAtUtc,
            clientVoiceProfileLabel: _telegramAiClientProfileDisplayLabel(
              _telegramAiClientProfileOverrideForScope(
                draft.clientId,
                draft.siteId,
              ),
            ),
            matchesSelectedScope:
                draft.clientId.trim() == resolvedClientId &&
                draft.siteId.trim() == resolvedSiteId,
          ),
        )
        .toList(growable: false);
    final selectedScopeLiveClientAsks = _unresolvedClientAsksForScope(
      clientId: resolvedClientId,
      siteId: resolvedSiteId,
      messages: _clientAppMessages,
      matchesSelectedScope: true,
      limit: 2,
    );
    final crossScopeLiveClientAsks =
        _clientConversationMessagesByScope.entries
            .where((entry) => entry.key.trim().isNotEmpty)
            .expand((entry) {
              final parts = entry.key.split('|');
              if (parts.length != 2) {
                return const <LiveControlInboxClientAsk>[];
              }
              final clientId = parts.first.trim();
              final siteId = parts.last.trim();
              if (clientId.isEmpty ||
                  siteId.isEmpty ||
                  (clientId == resolvedClientId && siteId == resolvedSiteId)) {
                return const <LiveControlInboxClientAsk>[];
              }
              return _unresolvedClientAsksForScope(
                clientId: clientId,
                siteId: siteId,
                messages: entry.value,
                matchesSelectedScope: false,
              );
            })
            .toList(growable: false)
          ..sort((a, b) => b.occurredAtUtc.compareTo(a.occurredAtUtc));
    final liveClientAsks = <LiveControlInboxClientAsk>[
      ...selectedScopeLiveClientAsks,
      ...crossScopeLiveClientAsks,
    ]..sort((a, b) => b.occurredAtUtc.compareTo(a.occurredAtUtc));

    return LiveControlInboxSnapshot(
      selectedClientId: resolvedClientId,
      selectedSiteId: resolvedSiteId,
      selectedScopeClientVoiceProfileLabel:
          selectedScopeClientVoiceProfileLabel,
      pendingApprovalCount: pendingDrafts.length,
      selectedScopePendingCount: pendingDrafts
          .where(
            (draft) =>
                draft.clientId.trim() == resolvedClientId &&
                draft.siteId.trim() == resolvedSiteId,
          )
          .length,
      awaitingResponseCount: liveClientAsks.length,
      telegramHealthLabel: _telegramBridgeHealthLabel,
      telegramHealthDetail: (_telegramBridgeHealthDetail ?? '').trim().isEmpty
          ? null
          : _telegramBridgeHealthDetail!.trim(),
      telegramFallbackActive: _telegramBridgeFallbackToInApp,
      pendingDrafts: inboxDrafts,
      liveClientAsks: liveClientAsks,
    );
  }

