}

class _SiteAwarenessActiveAlertRecord {
  final String siteId;
  final String clientId;
  final String alertId;
  final String channelId;
  final String eventType;
  final DateTime detectedAt;
  final bool isAcknowledged;
  final String message;
  final String? zoneName;
  final String? zoneType;
  final bool isLoitering;
  final bool isSequence;
  final String? alertSource;
  final String? alertKind;
  final String? subjectLabel;
  final String? timeContext;
  final Map<String, Object?>? alertReason;
  final Map<String, Object?>? latency;
  final double? personConfidence;
  final String? powerMode;

  const _SiteAwarenessActiveAlertRecord({
    required this.siteId,
    required this.clientId,
    required this.alertId,
    required this.channelId,
    required this.eventType,
    required this.detectedAt,
    required this.isAcknowledged,
    required this.message,
    this.zoneName,
    this.zoneType,
    this.isLoitering = false,
    this.isSequence = false,
    this.alertSource,
    this.alertKind,
    this.subjectLabel,
    this.timeContext,
    this.alertReason,
    this.latency,
    this.personConfidence,
    this.powerMode,
  });

  String get deliveryCameraKey {
    final normalizedChannelId = channelId.trim();
    if (normalizedChannelId.isNotEmpty) {
      return normalizedChannelId;
    }
    final normalizedZoneName = (zoneName ?? '').trim().toLowerCase();
    if (normalizedZoneName.isNotEmpty) {
      return normalizedZoneName;
    }
    return 'unknown-camera';
  }

  String get deliveryMessageTypeKey {
    return <String>[
      (alertSource ?? '').trim().toLowerCase(),
      eventType.trim().toLowerCase(),
      isLoitering ? 'loiter' : 'standard',
      isSequence ? 'sequence' : 'single',
      _normalizeSiteAwarenessAlertMessageType(message),
    ].where((part) => part.isNotEmpty).join('|');
  }

  String get deliveryDeduplicationKey {
    return '$deliveryCameraKey|$deliveryMessageTypeKey';
  }
}

String _normalizeSiteAwarenessAlertMessageType(String message) {
  final normalizedLines = message
      .trim()
      .toLowerCase()
      .split('\n')
      .map(
        (line) => line
            .trim()
            .replaceAll(RegExp(r'\s+[—-]\s+\d{1,2}:\d{2}\b'), '')
            .replaceAll(RegExp(r'\s+'), ' '),
      )
      .where((line) => line.isNotEmpty)
      .toList(growable: false);
  if (normalizedLines.isEmpty) {
    return 'alert';
  }
  return normalizedLines.join('|');
}

List<_SiteAwarenessActiveAlertRecord> _siteAwarenessActiveAlertsFromRow(
  Map<String, dynamic> row,
) {
  final rawAlerts = row['active_alerts'];
  if (rawAlerts is! List) {
    return const <_SiteAwarenessActiveAlertRecord>[];
  }
  final alerts = <_SiteAwarenessActiveAlertRecord>[];
  for (final entry in rawAlerts) {
    final alert = _siteAwarenessAsObjectMap(entry);
    if (alert == null) {
      continue;
    }
    final siteId = _siteAwarenessSummaryString(row['site_id']) ?? '';
    final clientId = _siteAwarenessSummaryString(row['client_id']) ?? '';
    final alertId = _siteAwarenessSummaryString(alert['alert_id']) ?? '';
    final channelId = _siteAwarenessSummaryString(alert['channel_id']) ?? '';
    final detectedAt = _siteAwarenessSummaryDate(alert['detected_at']);
    if (alertId.isEmpty || detectedAt == null) {
      continue;
    }
    alerts.add(
      _SiteAwarenessActiveAlertRecord(
        siteId: siteId,
        clientId: clientId,
        alertId: alertId,
        channelId: channelId,
        eventType:
            _siteAwarenessSummaryString(alert['event_type']) ?? 'unknown',
        detectedAt: detectedAt,
        isAcknowledged:
            _siteAwarenessSummaryBool(
              alert['is_acknowledged'] ?? alert['isAcknowledged'],
            ) ??
            false,
        message: _siteAwarenessSummaryString(alert['message']) ?? '',
        zoneName: _siteAwarenessSummaryString(
          alert['zone_name'] ?? alert['zoneName'],
        ),
        zoneType: _siteAwarenessSummaryString(
          alert['zone_type'] ?? alert['zoneType'],
        ),
        isLoitering:
            _siteAwarenessSummaryBool(
              alert['is_loitering'] ?? alert['isLoitering'],
            ) ??
            false,
        isSequence:
            _siteAwarenessSummaryBool(
              alert['is_sequence'] ?? alert['isSequence'],
            ) ??
            false,
        alertSource: _siteAwarenessSummaryString(
          alert['alert_source'] ?? alert['alertSource'],
        ),
        alertKind: _siteAwarenessSummaryString(
          alert['alert_kind'] ?? alert['alertKind'],
        ),
        subjectLabel: _siteAwarenessSummaryString(
          alert['subject_label'] ?? alert['subjectLabel'],
        ),
        timeContext: _siteAwarenessSummaryString(
          alert['time_context'] ?? alert['timeContext'],
        ),
        alertReason: _siteAwarenessAsObjectMap(
          alert['alert_reason'] ?? alert['alertReason'],
        ),
        latency: _siteAwarenessAsObjectMap(alert['latency']),
        personConfidence: _siteAwarenessSummaryDouble(
          alert['person_confidence'] ?? alert['personConfidence'],
        ),
        powerMode: _siteAwarenessSummaryString(
          alert['power_mode'] ?? alert['powerMode'],
        ),
      ),
    );
  }
  alerts.sort((left, right) => right.detectedAt.compareTo(left.detectedAt));
  return List<_SiteAwarenessActiveAlertRecord>.unmodifiable(alerts);
}

class _SiteAwarenessHumanZone {
  final String channelId;
  final String zoneName;
  final String zoneType;
  final bool isPerimeter;
  final bool isIndoor;
  final DateTime? lastDetectedAtUtc;

  const _SiteAwarenessHumanZone({
    required this.channelId,
    required this.zoneName,
    required this.zoneType,
    required this.isPerimeter,
    required this.isIndoor,
    required this.lastDetectedAtUtc,
  });

  String get zoneTypeLabel {
    if (isPerimeter || zoneType == 'perimeter') {
      return 'perimeter';
    }
    if (isIndoor || zoneType == 'indoor') {
      return 'indoor';
    }
    final normalized = zoneType
        .trim()
        .replaceAll('_', '-')
        .replaceAll(RegExp(r'\s+'), ' ');
    return normalized.isEmpty ? 'camera zone' : normalized;
  }
}

enum _TelegramProactiveAlertKind {
  perimeterBreach,
  unknownVehicleAtGate,
  loitering,
  generalMovement,
}

class _TelegramProactiveAlertPresentation {
  final String markdownText;
  final String plainText;
  final Map<String, Object?>? replyMarkup;
  final List<int>? photoBytes;
  final String? photoFilename;
  final _TelegramProactiveAlertKind alertKind;

  const _TelegramProactiveAlertPresentation({
    required this.markdownText,
    required this.plainText,
    required this.replyMarkup,
    required this.photoBytes,
    required this.photoFilename,
    required this.alertKind,
  });
}

List<_SiteAwarenessHumanZone> _siteAwarenessHumanZones(
  Map<String, dynamic> row,
) {
  final detections = _siteAwarenessAsObjectMap(row['detections']);
  final rawZones = detections?['human_zones'] ?? detections?['humanZones'];
  if (rawZones is! List) {
    return const <_SiteAwarenessHumanZone>[];
  }
  final zones = <_SiteAwarenessHumanZone>[];
  for (final entry in rawZones) {
    final zone = _siteAwarenessAsObjectMap(entry);
    if (zone == null) {
      continue;
    }
    final channelId =
        _siteAwarenessSummaryString(zone['channel_id'] ?? zone['channelId']) ??
        '';
    final zoneName =
        _siteAwarenessSummaryString(zone['zone_name'] ?? zone['zoneName']) ??
        '';
    if (zoneName.isEmpty) {
      continue;
    }
    zones.add(
      _SiteAwarenessHumanZone(
        channelId: channelId,
        zoneName: zoneName,
        zoneType:
            _siteAwarenessSummaryString(
              zone['zone_type'] ?? zone['zoneType'],
            ) ??
            'camera zone',
        isPerimeter:
            _siteAwarenessSummaryBool(
              zone['is_perimeter'] ?? zone['isPerimeter'],
            ) ??
            false,
        isIndoor:
            _siteAwarenessSummaryBool(zone['is_indoor'] ?? zone['isIndoor']) ??
            false,
        lastDetectedAtUtc: _siteAwarenessSummaryDate(
          zone['last_detected_at'] ?? zone['lastDetectedAt'],
        ),
      ),
    );
  }
  zones.sort((left, right) {
    final rightStamp = right.lastDetectedAtUtc;
    final leftStamp = left.lastDetectedAtUtc;
    if (rightStamp != null && leftStamp != null) {
      final compare = rightStamp.compareTo(leftStamp);
      if (compare != 0) {
        return compare;
      }
    } else if (rightStamp != null) {
      return 1;
    } else if (leftStamp != null) {
      return -1;
    }
    return left.channelId.compareTo(right.channelId);
  });
  return List<_SiteAwarenessHumanZone>.unmodifiable(zones);
}

Map<String, Object?>? _siteAwarenessAsObjectMap(Object? value) {
  if (value is! Map) {
    return null;
  }
  return value.map(
    (key, entryValue) => MapEntry(key.toString(), entryValue as Object?),
  );
}

DateTime? _siteAwarenessSummaryDate(Object? value) {
  if (value is! String || value.trim().isEmpty) {
    return null;
  }
  return DateTime.tryParse(value)?.toUtc();
}

int? _siteAwarenessSummaryInt(Object? value) {
  if (value is int) {
    return value;
  }
  if (value is num) {
    return value.toInt();
  }
  if (value is String) {
    return int.tryParse(value);
  }
  return null;
}

String? _siteAwarenessSummaryString(Object? value) {
  if (value is! String) {
    return null;
  }
  final trimmed = value.trim();
  return trimmed.isEmpty ? null : trimmed;
}

bool _siteAwarenessValidChannelLabel(String value) {
  final parsed = int.tryParse(value.trim());
  return parsed != null && parsed > 0;
}

