Future<void> _insertTemporaryExpectedVisitor({
  required String siteId,
  required _TelegramExpectedVisitorRegistration registration,
}) async {
  final targetDateLocal = registration.targetDateLocal;
  await Supabase.instance.client.from('site_expected_visitors').insert(<
    String,
    Object?
  >{
    'site_id': siteId.trim(),
    'visitor_name': registration.visitorName,
    'visitor_role': registration.visitorRole,
    'visit_type': registration.visitType,
    'visit_days': registration.visitType == 'on_demand'
        ? const <String>[]
        : <String>[_telegramVisitorWeekdayLabel(targetDateLocal)],
    'visit_start': registration.visitStart,
    'visit_end': registration.visitEnd,
    'visit_date':
        '${targetDateLocal.year.toString().padLeft(4, '0')}-${targetDateLocal.month.toString().padLeft(2, '0')}-${targetDateLocal.day.toString().padLeft(2, '0')}',
    'expires_at': registration.expiresAtUtc.toIso8601String(),
    'is_active': true,
    'notes':
        'Telegram visitor registration created ${DateTime.now().toUtc().toIso8601String()}',
  });
}

Future<void> _deactivateOnDemandExpectedVisitors({
  required String siteId,
}) async {
  final nowLocal = DateTime.now().toLocal();
  final visitDate =
      '${nowLocal.year.toString().padLeft(4, '0')}-${nowLocal.month.toString().padLeft(2, '0')}-${nowLocal.day.toString().padLeft(2, '0')}';
  await Supabase.instance.client
      .from('site_expected_visitors')
      .update(<String, Object?>{'is_active': false})
      .eq('site_id', siteId.trim())
      .eq('visit_type', 'on_demand')
      .eq('visit_date', visitDate)
      .eq('is_active', true);
}

Future<void> _deactivateExpiredOnDemandExpectedVisitors({
  required String siteId,
}) async {
  await Supabase.instance.client
      .from('site_expected_visitors')
      .update(<String, Object?>{'is_active': false})
      .eq('site_id', siteId.trim())
      .eq('visit_type', 'on_demand')
      .eq('is_active', true)
      .lte('expires_at', DateTime.now().toUtc().toIso8601String());
}

Future<Map<String, dynamic>?> _readSiteOccupancySessionRow({
  required String siteId,
  required DateTime nowLocal,
  int resetHour = 3,
}) async {
  if (siteId.trim().isEmpty) {
    return null;
  }
  try {
    final sessionDate = _siteOccupancySessionDateValue(
      nowLocal,
      resetHour: resetHour,
    );
    final rows = await Supabase.instance.client
        .from('site_occupancy_sessions')
        .select(
          'site_id,session_date,peak_detected,last_detection_at,channels_with_detections,updated_at',
        )
        .eq('site_id', siteId.trim())
        .eq('session_date', sessionDate)
        .limit(1);
    if (rows.isEmpty) {
      return null;
    }
    return Map<String, dynamic>.from(rows.first as Map);
  } catch (_) {
    return null;
  }
}

Future<List<Map<String, dynamic>>> _readIncidentRowsForSite({
  required String siteId,
  int limit = 50,
}) async {
  if (siteId.trim().isEmpty) {
    return const <Map<String, dynamic>>[];
  }
  try {
    final rows = await Supabase.instance.client
        .from('incidents')
        .select(
          'id,event_uid,status,incident_type,created_at,occurred_at,signal_received_at,dispatch_time,arrival_time,resolution_time,controller_notes,field_report',
        )
        .eq('site_id', siteId.trim())
        .order('created_at', ascending: false)
        .limit(limit);
    final normalized =
        rows
            .map((row) => Map<String, dynamic>.from(row as Map))
            .toList(growable: false)
          ..sort((left, right) {
            final rightAt = _incidentRowOccurredAtUtc(right);
            final leftAt = _incidentRowOccurredAtUtc(left);
            if (rightAt == null && leftAt == null) {
              return 0;
            }
            if (rightAt == null) {
              return -1;
            }
            if (leftAt == null) {
              return 1;
            }
            return rightAt.compareTo(leftAt);
          });
    return normalized;
  } catch (_) {
    return const <Map<String, dynamic>>[];
  }
}

String _siteOccupancySessionDateValue(
  DateTime observedAtLocal, {
  int resetHour = 3,
}) {
  final normalizedResetHour = resetHour.clamp(0, 23);
  final dayStart = DateTime(
    observedAtLocal.year,
    observedAtLocal.month,
    observedAtLocal.day,
    normalizedResetHour,
  );
  final sessionLocalDate = observedAtLocal.isBefore(dayStart)
      ? dayStart.subtract(const Duration(days: 1))
      : dayStart;
  String two(int value) => value.toString().padLeft(2, '0');
  return '${sessionLocalDate.year.toString().padLeft(4, '0')}-${two(sessionLocalDate.month)}-${two(sessionLocalDate.day)}';
}

int _siteOccupancyExpectedOccupancy(Map<String, dynamic>? row) =>
    _siteAwarenessSummaryInt(row?['expected_occupancy']) ?? 0;

int _siteOccupancyResetHour(Map<String, dynamic>? row) =>
    _siteAwarenessSummaryInt(row?['reset_hour']) ?? 3;

bool _siteOccupancyHasGuard(Map<String, dynamic>? row) =>
    _siteAwarenessSummaryBool(row?['has_guard']) ?? false;

bool _siteOccupancyHasGateSensors(Map<String, dynamic>? row) =>
    _siteAwarenessSummaryBool(row?['has_gate_sensors']) ?? false;

int _siteOccupancyPeakDetected(Map<String, dynamic>? row) =>
    _siteAwarenessSummaryInt(row?['peak_detected']) ?? 0;

int _siteOccupancyDisplayedDetectedCount({
  required Map<String, dynamic>? sessionRow,
  required int currentHumanCount,
}) {
  final occupancyPeak = _siteOccupancyPeakDetected(sessionRow);
  return math.max(currentHumanCount, occupancyPeak);
}

String? _telegramExpectedVisitorStatusLine(List<SiteExpectedVisitor> visitors) {
  final onDemandVisitors = visitors
      .where((visitor) => visitor.visitType.trim().toLowerCase() == 'on_demand')
      .toList(growable: false);
  if (onDemandVisitors.isEmpty) {
    return null;
  }
  final primary = onDemandVisitors.first;
  final untilLabel = _telegramExpectedVisitorUntilLabel(primary.visitEnd);
  if (onDemandVisitors.length == 1) {
    final displayName = primary.displayName.trim();
    if (displayName.isNotEmpty &&
        displayName.toLowerCase() != 'visitor' &&
        displayName.toLowerCase() != 'delivery') {
      return '1 unregistered visitor on site ($displayName) until $untilLabel.';
    }
    return '1 unregistered visitor on site until $untilLabel.';
  }
  return '${onDemandVisitors.length} unregistered visitors on site until $untilLabel.';
}

String _telegramExpectedVisitorUntilLabel(String? rawTime) {
  if (rawTime == null || rawTime.trim().isEmpty) {
    return 'end of day';
  }
  final match = RegExp(r'^(\d{1,2}):(\d{2})').firstMatch(rawTime.trim());
  if (match == null) {
    return rawTime.trim();
  }
  final hour = int.tryParse(match.group(1)!);
  final minute = int.tryParse(match.group(2)!);
  if (hour == null || minute == null) {
    return rawTime.trim();
  }
  return '${hour.toString().padLeft(2, '0')}:${minute.toString().padLeft(2, '0')}';
}

class _SiteVehicleRegistryRecord {
  final String siteId;
  final String plateNumber;
  final String vehicleDescription;
  final String ownerName;
  final String ownerRole;

  const _SiteVehicleRegistryRecord({
    required this.siteId,
    required this.plateNumber,
    required this.vehicleDescription,
    required this.ownerName,
    required this.ownerRole,
  });

  factory _SiteVehicleRegistryRecord.fromRow(Map<String, dynamic> row) {
    return _SiteVehicleRegistryRecord(
      siteId: (row['site_id'] as String? ?? '').trim(),
      plateNumber: _normalizedVehiclePlate(row['plate_number']),
      vehicleDescription: (row['vehicle_description'] as String? ?? '').trim(),
      ownerName: (row['owner_name'] as String? ?? '').trim(),
      ownerRole: (row['owner_role'] as String? ?? '').trim(),
    );
  }
}

class _SiteVehiclePresenceRecord {
  final String id;
  final String siteId;
  final String plateNumber;
  final String ownerName;
  final String eventType;
  final int? channelId;
  final String? zoneName;
  final DateTime occurredAtUtc;

  const _SiteVehiclePresenceRecord({
    required this.id,
    required this.siteId,
    required this.plateNumber,
    required this.ownerName,
    required this.eventType,
    required this.channelId,
    required this.zoneName,
    required this.occurredAtUtc,
  });

  factory _SiteVehiclePresenceRecord.fromRow(Map<String, dynamic> row) {
    return _SiteVehiclePresenceRecord(
      id: (row['id'] as String? ?? '').trim(),
      siteId: (row['site_id'] as String? ?? '').trim(),
      plateNumber: _normalizedVehiclePlate(row['plate_number']),
      ownerName: (row['owner_name'] as String? ?? '').trim(),
      eventType: (row['event_type'] as String? ?? '').trim().toLowerCase(),
      channelId: _siteAwarenessSummaryInt(row['channel_id']),
      zoneName: (row['zone_name'] as String?)?.trim(),
      occurredAtUtc:
          _siteAwarenessSummaryDate(row['occurred_at']) ??
          DateTime.now().toUtc(),
