Future<List<Map<String, dynamic>>> _readSiteVehicleRegistryRows({
  required String siteId,
}) async {
  if (siteId.trim().isEmpty) {
    return const <Map<String, dynamic>>[];
  }
  try {
    final rows = await Supabase.instance.client
        .from('site_vehicle_registry')
        .select(
          'site_id,plate_number,vehicle_description,owner_name,owner_role,is_active,visit_type',
        )
        .eq('site_id', siteId.trim())
        .eq('is_active', true)
        .order('owner_name', ascending: true);
    return rows
        .map((row) => Map<String, dynamic>.from(row as Map))
        .toList(growable: false);
  } catch (_) {
    return const <Map<String, dynamic>>[];
  }
}

Future<List<Map<String, dynamic>>> _readSiteVehiclePresenceRows({
  required String siteId,
  DateTime? sinceUtc,
  int limit = 200,
}) async {
  if (siteId.trim().isEmpty) {
    return const <Map<String, dynamic>>[];
  }
  try {
    final base = Supabase.instance.client
        .from('site_vehicle_presence')
        .select(
          'id,site_id,plate_number,owner_name,event_type,channel_id,zone_name,occurred_at',
        )
        .eq('site_id', siteId.trim());
    final rows = await (sinceUtc == null
        ? base.order('occurred_at', ascending: false).limit(limit)
        : base
              .gte('occurred_at', sinceUtc.toUtc().toIso8601String())
              .order('occurred_at', ascending: false)
              .limit(limit));
    return rows
        .map((row) => Map<String, dynamic>.from(row as Map))
        .toList(growable: false);
  } on PostgrestException catch (error) {
    if (_isMissingSupabaseRelationError(error, 'site_vehicle_presence')) {
      developer.log(
        'Falling back to vehicle_visits because site_vehicle_presence is unavailable in Supabase REST.',
        name: 'OnyxVehiclePresence',
        error: error,
      );
      return _readVehiclePresenceRowsFromVehicleVisits(
        siteId: siteId,
        sinceUtc: sinceUtc,
        limit: limit,
      );
    }
    return const <Map<String, dynamic>>[];
  } catch (_) {
    return const <Map<String, dynamic>>[];
  }
}

bool _isMissingSupabaseRelationError(
  PostgrestException error,
  String relationName,
) {
  final relation = relationName.trim().toLowerCase();
  if (relation.isEmpty) {
    return false;
  }
  final code = error.code.toString().trim().toLowerCase();
  final details = (error.details ?? '').toString().trim().toLowerCase();
  final hint = (error.hint ?? '').toString().trim().toLowerCase();
  final message = error.message.toString().trim().toLowerCase();
  final combined = '$message $details $hint';
  if (!combined.contains(relation)) {
    return false;
  }
  return code == 'pgrst205' ||
      combined.contains('schema cache') ||
      combined.contains('could not find the table') ||
      combined.contains('relation') && combined.contains('does not exist');
}

Future<List<Map<String, dynamic>>> _readVehiclePresenceRowsFromVehicleVisits({
  required String siteId,
  DateTime? sinceUtc,
  int limit = 200,
}) async {
  final registryRows = await _readSiteVehicleRegistryRows(siteId: siteId);
  final registryByPlate = <String, _SiteVehicleRegistryRecord>{};
  for (final row in registryRows) {
    final record = _SiteVehicleRegistryRecord.fromRow(row);
    if (record.plateNumber.isEmpty) {
      continue;
    }
    registryByPlate[record.plateNumber] = record;
  }
  try {
    final rows = await Supabase.instance.client
        .from('vehicle_visits')
        .select(
          'id,site_id,plate_number,started_at_utc,last_seen_at_utc,completed_at_utc,visit_status,zone_labels',
        )
        .eq('site_id', siteId.trim())
        .order('last_seen_at_utc', ascending: false)
        .limit(limit);
    final synthesized = <Map<String, dynamic>>[];
    for (final rawRow in rows) {
      final row = Map<String, dynamic>.from(rawRow as Map);
      final visitId = (row['id'] ?? '').toString().trim();
      final normalizedPlate = _normalizedVehiclePlate(row['plate_number']);
      final startedAtUtc = _siteAwarenessSummaryDate(row['started_at_utc']);
      final lastSeenAtUtc = _siteAwarenessSummaryDate(row['last_seen_at_utc']);
      final completedAtUtc = _siteAwarenessSummaryDate(row['completed_at_utc']);
      final visitStatus = (row['visit_status'] ?? '')
          .toString()
          .trim()
          .toLowerCase();
      final zoneLabels = row['zone_labels'];
      final zoneName = zoneLabels is List
          ? zoneLabels
                .map((value) => value.toString().trim())
                .firstWhere((value) => value.isNotEmpty, orElse: () => '')
          : '';
      final registry = registryByPlate[normalizedPlate];
      final ownerName = registry?.ownerName ?? '';
      void addSyntheticEvent({
        required String suffix,
        required String eventType,
        required DateTime occurredAtUtc,
      }) {
        final normalizedOccurredAtUtc = occurredAtUtc.toUtc();
        if (sinceUtc != null &&
            normalizedOccurredAtUtc.isBefore(sinceUtc.toUtc())) {
          return;
        }
        synthesized.add(<String, dynamic>{
          'id': visitId.isEmpty
              ? '$normalizedPlate:$suffix'
              : '$visitId:$suffix',
          'site_id': siteId.trim(),
          'plate_number': normalizedPlate,
          'owner_name': ownerName,
          'event_type': eventType,
          'channel_id': null,
          'zone_name': zoneName.isEmpty ? null : zoneName,
          'occurred_at': normalizedOccurredAtUtc.toIso8601String(),
        });
      }

      if (startedAtUtc != null) {
        addSyntheticEvent(
          suffix: 'arrived',
          eventType: 'arrived',
          occurredAtUtc: startedAtUtc,
        );
      }
      if (visitStatus != 'completed' && lastSeenAtUtc != null) {
        addSyntheticEvent(
          suffix: 'on_site',
          eventType: 'on_site',
          occurredAtUtc: lastSeenAtUtc,
        );
      }
      if (completedAtUtc != null) {
        addSyntheticEvent(
          suffix: 'departed',
          eventType: 'departed',
          occurredAtUtc: completedAtUtc,
        );
      }
    }
    synthesized.sort((left, right) {
      final rightAt = _siteAwarenessSummaryDate(right['occurred_at']);
      final leftAt = _siteAwarenessSummaryDate(left['occurred_at']);
      if (rightAt == null && leftAt == null) {
        return 0;
      }
      if (rightAt == null) {
        return -1;
      }
      if (leftAt == null) {
        return 1;
      }
      return rightAt.compareTo(leftAt);
    });
    return synthesized.take(limit).toList(growable: false);
  } catch (_) {
    return const <Map<String, dynamic>>[];
  }
}

List<_SiteVehiclePresenceStatus> _buildVehiclePresenceStatuses({
  required List<Map<String, dynamic>> registryRows,
  required List<Map<String, dynamic>> presenceRows,
  required DateTime nowUtc,
  Duration homeThreshold = const Duration(hours: 2),
}) {
  final registry = registryRows
      .map(_SiteVehicleRegistryRecord.fromRow)
      .where((entry) => entry.plateNumber.isNotEmpty)
      .toList(growable: false);
  final presenceByPlate = <String, List<_SiteVehiclePresenceRecord>>{};
  for (final row in presenceRows) {
    final record = _SiteVehiclePresenceRecord.fromRow(row);
    if (record.plateNumber.isEmpty) {
      continue;
    }
    presenceByPlate
        .putIfAbsent(record.plateNumber, () => <_SiteVehiclePresenceRecord>[])
        .add(record);
  }
  final statuses = <_SiteVehiclePresenceStatus>[];
  for (final entry in registry) {
    final records = List<_SiteVehiclePresenceRecord>.from(
      presenceByPlate[entry.plateNumber] ??
          const <_SiteVehiclePresenceRecord>[],
    );
    records.sort(
      (left, right) => right.occurredAtUtc.compareTo(left.occurredAtUtc),
    );
    final latest = records.isEmpty ? null : records.first;
    final seenToday = latest != null;
    final isHome =
        latest != null &&
        nowUtc.difference(latest.occurredAtUtc) <= homeThreshold &&
        latest.eventType != 'departed';
    statuses.add(
      _SiteVehiclePresenceStatus(
        registry: entry,
        latestPresence: latest,
        seenToday: seenToday,
        isHome: isHome,
      ),
    );
  }
  return List<_SiteVehiclePresenceStatus>.unmodifiable(statuses);
}

String _normalizedPresenceNameKey(String value) {
  return value
      .trim()
      .toLowerCase()
      .replaceAll(RegExp(r'[^a-z0-9]+'), ' ')
      .replaceAll(RegExp(r'\s+'), ' ')
      .trim();
}

bool _vehiclePresenceWasResidentConfirmed(
  _SiteVehiclePresenceRecord? presence,
) {
  final zone = presence?.zoneName?.trim().toLowerCase() ?? '';
  return presence != null &&
      presence.eventType == 'on_site' &&
      zone == 'resident confirmed';
}

bool _promptContainsOwnerName(String prompt, String ownerName) {
  final normalizedPrompt = ' ${_normalizedPresenceNameKey(prompt)} ';
  final normalizedOwner = _normalizedPresenceNameKey(ownerName);
  if (normalizedOwner.isEmpty) {
    return false;
  }
  if (normalizedPrompt.contains(' $normalizedOwner ')) {
    return true;
  }
  for (final token in normalizedOwner.split(' ')) {
    if (token.length < 3) {
      continue;
    }
    if (normalizedPrompt.contains(' $token ')) {
      return true;
    }
  }
  return false;
}

List<_SiteVehicleRegistryRecord> _matchedVehicleRegistryOwnersForPrompt({
  required String prompt,
  required List<_SiteVehicleRegistryRecord> registry,
}) {
  final matches = <_SiteVehicleRegistryRecord>[];
  final seenPlates = <String>{};
  for (final entry in registry) {
    if (entry.ownerName.trim().isEmpty) {
      continue;
    }
    if (!_promptContainsOwnerName(prompt, entry.ownerName)) {
      continue;
    }
    if (!seenPlates.add(entry.plateNumber)) {
      continue;
    }
    matches.add(entry);
  }
  return List<_SiteVehicleRegistryRecord>.unmodifiable(matches);
}

Future<List<_SiteVehicleRegistryRecord>>
_recordManualVehiclePresenceConfirmation({
  required String siteId,
  required String prompt,
}) async {
  final registryRows = await _readSiteVehicleRegistryRows(siteId: siteId);
  if (registryRows.isEmpty) {
    return const <_SiteVehicleRegistryRecord>[];
  }
  final registry = registryRows
      .map(_SiteVehicleRegistryRecord.fromRow)
      .where((entry) => entry.plateNumber.isNotEmpty)
      .toList(growable: false);
  final matches = _matchedVehicleRegistryOwnersForPrompt(
    prompt: prompt,
    registry: registry,
  );
  if (matches.isEmpty) {
    return const <_SiteVehicleRegistryRecord>[];
  }
  final nowUtc = DateTime.now().toUtc();
  final recentRows = await _readSiteVehiclePresenceRows(
    siteId: siteId,
    sinceUtc: nowUtc.subtract(const Duration(hours: 6)),
    limit: 400,
  );
  final latestByPlate = <String, _SiteVehiclePresenceRecord>{};
  for (final row in recentRows) {
    final record = _SiteVehiclePresenceRecord.fromRow(row);
    if (record.plateNumber.isEmpty) {
      continue;
    }
    latestByPlate.putIfAbsent(record.plateNumber, () => record);
  }
  for (final entry in matches) {
    final latest = latestByPlate[entry.plateNumber];
    final shouldInsert =
        latest == null ||
        nowUtc.difference(latest.occurredAtUtc) > const Duration(minutes: 15) ||
        !_vehiclePresenceWasResidentConfirmed(latest);
    if (!shouldInsert) {
      continue;
    }
    await Supabase.instance.client
        .from('site_vehicle_presence')
        .insert(<String, Object?>{
          'site_id': siteId.trim(),
          'plate_number': entry.plateNumber,
          'owner_name': entry.ownerName,
          'event_type': 'on_site',
          'channel_id': null,
          'zone_name': 'resident confirmed',
          'occurred_at': nowUtc.toIso8601String(),
        });
  }
  return matches;
}

bool _telegramPromptLooksLikeVehiclePresence(String prompt) {
  final normalized = prompt.trim().toLowerCase();
  if (normalized.isEmpty) {
    return false;
  }
  return normalized.contains('whos home') ||
      normalized.contains('who is home') ||
      normalized.contains('who is on site') ||
      normalized.contains('which cars are home') ||
      normalized.contains('which car is home') ||
      normalized.contains('did ') && normalized.contains(' arrive') ||
      normalized.startsWith('is ') && normalized.endsWith(' home');
}

String _vehiclePresenceOwnerLabel(_SiteVehicleRegistryRecord registry) {
  final owner = registry.ownerName.trim();
  return owner.isEmpty ? registry.plateNumber : owner;
}

String _vehiclePresenceVehicleLabel(_SiteVehicleRegistryRecord registry) {
  final description = registry.vehicleDescription.trim();
  return description.isEmpty ? registry.plateNumber : description;
}

String _vehiclePresenceLastSeenLabel(_SiteVehiclePresenceRecord? presence) {
  if (presence == null) {
    return 'not detected today';
  }
  final zoneName = presence.zoneName?.trim();
  final zoneLabel = zoneName == null || zoneName.isEmpty
      ? 'unknown zone'
      : zoneName;
  return '$zoneLabel ${_vehiclePresenceLocalTimeLabel(presence.occurredAtUtc)}';
}

String _vehiclePresenceArrivalLabel(_SiteVehiclePresenceRecord presence) {
  final zoneName = presence.zoneName?.trim();
  final zoneLabel = zoneName == null || zoneName.isEmpty ? 'site' : zoneName;
  return 'arrived ${_vehiclePresenceLocalTimeLabel(presence.occurredAtUtc)} ($zoneLabel)';
}

String _telegramVehiclePresenceSummarySection(
  List<_SiteVehiclePresenceStatus> statuses,
) {
  if (statuses.isEmpty) {
    return '';
  }
  final lines = <String>['🚗 Vehicles on site:'];
  for (final status in statuses) {
    final vehicle = _vehiclePresenceVehicleLabel(status.registry);
    final owner = _vehiclePresenceOwnerLabel(status.registry);
    if (!status.seenToday || status.latestPresence == null) {
      lines.add('- $owner — $vehicle (not detected today)');
      continue;
    }
    if (status.latestPresence!.eventType == 'arrived' && status.isHome) {
      lines.add(
        '- $owner — $vehicle — ${_vehiclePresenceArrivalLabel(status.latestPresence!)}',
      );
      continue;
    }
    if (_vehiclePresenceWasResidentConfirmed(status.latestPresence) &&
        status.isHome) {
      lines.add('- $owner — $vehicle (on site, confirmed by resident)');
      continue;
    }
    lines.add(
      '- $owner — $vehicle (last seen: ${_vehiclePresenceLastSeenLabel(status.latestPresence)})',
    );
  }
  return lines.join('\n');
}

String _telegramVehiclePresenceHomeLine(_SiteVehiclePresenceStatus status) {
  final owner = _vehiclePresenceOwnerLabel(status.registry);
  final vehicle = _vehiclePresenceVehicleLabel(status.registry);
  final latest = status.latestPresence;
  if (latest == null) {
    return '$owner — out ($vehicle not detected today)';
  }
  final zoneName = latest.zoneName?.trim();
  final zoneLabel = zoneName == null || zoneName.isEmpty ? 'site' : zoneName;
  final timeLabel = _vehiclePresenceLocalTimeLabel(latest.occurredAtUtc);
  if (status.isHome) {
    if (_vehiclePresenceWasResidentConfirmed(latest)) {
      return '$owner — home ($vehicle confirmed by resident)';
    }
    if (latest.eventType == 'arrived') {
      return '$owner — home ($vehicle ${_vehiclePresenceArrivalLabel(latest)})';
    }
    return '$owner — home ($vehicle in $zoneLabel since $timeLabel)';
  }
  return '$owner — out ($vehicle not seen since $timeLabel)';
}

_SiteVehiclePresenceStatus? _matchedVehiclePresenceStatusForPrompt(
  String prompt,
  List<_SiteVehiclePresenceStatus> statuses,
) {
  final normalized = prompt.trim().toLowerCase();
  for (final status in statuses) {
    final owner = status.registry.ownerName.trim().toLowerCase();
    if (owner.isNotEmpty && normalized.contains(owner)) {
      return status;
    }
    for (final token in owner.split(RegExp(r'\s+'))) {
      if (token.length >= 3 && normalized.contains(token)) {
        return status;
      }
    }
  }
  return null;
}

String _normalizedVehiclePlate(Object? value) {
  final raw = value?.toString().trim().toUpperCase() ?? '';
  if (raw.isEmpty) {
    return '';
  }
  return raw.replaceAll(RegExp(r'[^A-Z0-9]'), '');
}

String _vehiclePresenceLocalTimeLabel(DateTime? instantUtc) {
  if (instantUtc == null) {
    return 'n/a';
  }
  final local = instantUtc.toLocal();
  String two(int value) => value.toString().padLeft(2, '0');
  return '${two(local.hour)}:${two(local.minute)}';
}

String _telegramVisitorWeekdayLabel(DateTime dateLocal) {
  return switch (dateLocal.weekday) {
    DateTime.monday => 'monday',
    DateTime.tuesday => 'tuesday',
    DateTime.wednesday => 'wednesday',
    DateTime.thursday => 'thursday',
    DateTime.friday => 'friday',
    DateTime.saturday => 'saturday',
    DateTime.sunday => 'sunday',
    _ => 'unknown',
  };
}

String _telegramClockLabel(DateTime dateTimeLocal) {
  return '${dateTimeLocal.hour.toString().padLeft(2, '0')}:${dateTimeLocal.minute.toString().padLeft(2, '0')}';
}

class _TelegramExpectedVisitorRegistration {
  final String visitorName;
  final String visitorRole;
  final String visitType;
  final DateTime targetDateLocal;
  final String visitStart;
  final String visitEnd;
  final DateTime expiresAtUtc;

  const _TelegramExpectedVisitorRegistration({
    required this.visitorName,
    required this.visitorRole,
    required this.visitType,
    required this.targetDateLocal,
    required this.visitStart,
    required this.visitEnd,
    required this.expiresAtUtc,
  });
}

int _siteProfileExpectedPeopleCount(
  SiteIntelligenceProfile profile,
  Map<String, dynamic>? occupancyConfigRow,
) {
  final profileCount = profile.expectedPeopleCount;
  if (profileCount > 0) {
    return profileCount;
  }
  return _siteOccupancyExpectedOccupancy(occupancyConfigRow);
}

DateTime? _siteOccupancyLastDetectionAtUtc(Map<String, dynamic>? row) =>
    _siteAwarenessSummaryDate(row?['last_detection_at']);

DateTime? _incidentRowOccurredAtUtc(Map<String, dynamic>? row) =>
    _siteAwarenessSummaryDate(
      row?['signal_received_at'] ?? row?['occurred_at'] ?? row?['created_at'],
    );

DateTime? _incidentRowDispatchAtUtc(Map<String, dynamic>? row) =>
    _siteAwarenessSummaryDate(row?['dispatch_time']);

DateTime? _incidentRowArrivalAtUtc(Map<String, dynamic>? row) =>
    _siteAwarenessSummaryDate(row?['arrival_time']);

DateTime? _incidentRowResolutionAtUtc(Map<String, dynamic>? row) =>
    _siteAwarenessSummaryDate(row?['resolution_time']);

String _incidentRowReference(Map<String, dynamic>? row) {
  final eventUid = _siteAwarenessSummaryString(row?['event_uid']);
  if (eventUid != null && eventUid.isNotEmpty) {
    return eventUid;
  }
  final id = _siteAwarenessSummaryString(row?['id']) ?? 'incident';
  if (id.length <= 8) {
    return id;
  }
  return id.substring(0, 8);
}

String _incidentRowStatusLabel(Map<String, dynamic>? row) {
  final status = (_siteAwarenessSummaryString(row?['status']) ?? 'open')
      .trim()
      .toLowerCase();
  if (status.isEmpty) {
    return 'open';
  }
  return _siteAwarenessHumanizedLabel(status);
}

bool _incidentRowIsActive(Map<String, dynamic>? row) {
  final status = (_siteAwarenessSummaryString(row?['status']) ?? 'open')
      .trim()
      .toLowerCase();
  switch (status) {
    case 'closed':
    case 'resolved':
    case 'all_clear':
    case 'all clear':
    case 'cancelled':
    case 'canceled':
      return false;
    default:
      return true;
  }
}

Future<List<OnyxGuardPatrolAssignment>> _readPatrolAssignmentsForSite({
  required String siteId,
}) async {
  if (siteId.trim().isEmpty) {
    return const <OnyxGuardPatrolAssignment>[];
  }
  try {
    final rows = await Supabase.instance.client
        .from('guard_assignments')
        .select(
          'id,site_id,guard_id,guard_name,route_id,shift_start,shift_end,patrol_interval_minutes,is_active',
        )
        .eq('site_id', siteId.trim())
        .eq('is_active', true);
    return rows
        .map(
          (row) => OnyxGuardPatrolAssignment.fromRow(
            Map<String, dynamic>.from(row as Map),
          ),
        )
        .toList(growable: false);
  } catch (_) {
    return const <OnyxGuardPatrolAssignment>[];
  }
}

Future<List<OnyxPatrolCheckpoint>> _readPatrolCheckpointsForSite({
  required String siteId,
  List<String> routeIds = const <String>[],
}) async {
  if (siteId.trim().isEmpty) {
    return const <OnyxPatrolCheckpoint>[];
  }
  try {
    final builder = Supabase.instance.client
        .from('patrol_checkpoints')
        .select(
          'id,route_id,site_id,checkpoint_name,checkpoint_code,sequence_order,is_active',
        )
        .eq('site_id', siteId.trim())
        .eq('is_active', true);
    final normalizedRouteIds = routeIds
        .map((value) => value.trim())
        .where((value) => value.isNotEmpty)
        .toList(growable: false);
    final rows = normalizedRouteIds.isEmpty
        ? await builder.order('sequence_order', ascending: true)
        : await builder
              .inFilter('route_id', normalizedRouteIds)
              .order('sequence_order', ascending: true);
    return rows
        .map(
          (row) => OnyxPatrolCheckpoint.fromRow(
            Map<String, dynamic>.from(row as Map),
          ),
        )
        .toList(growable: false);
  } catch (_) {
    return const <OnyxPatrolCheckpoint>[];
  }
}

Future<List<OnyxPatrolScan>> _readPatrolScansForSite({
  required String siteId,
  int limit = 500,
}) async {
  if (siteId.trim().isEmpty) {
    return const <OnyxPatrolScan>[];
  }
  try {
    final rows = await Supabase.instance.client
        .from('patrol_checkpoint_scans')
        .select(
          'id,site_id,client_id,guard_id,checkpoint_id,checkpoint_name,scanned_at,lat,lon,method,valid,notes',
        )
        .eq('site_id', siteId.trim())
        .order('scanned_at', ascending: false)
        .limit(limit);
    return rows
        .map(
          (row) =>
              OnyxPatrolScan.fromRow(Map<String, dynamic>.from(row as Map)),
        )
        .toList(growable: false);
  } catch (_) {
    return const <OnyxPatrolScan>[];
  }
}

Future<void> _upsertPatrolComplianceSnapshot(
  OnyxPatrolComplianceSnapshot snapshot,
) async {
  try {
    await Supabase.instance.client
        .from('patrol_compliance')
        .upsert(<String, Object?>{
          'site_id': snapshot.siteId,
          'guard_id': snapshot.guardId,
          'compliance_date': snapshot.complianceDateValue,
          'expected_patrols': snapshot.expectedPatrols,
          'completed_patrols': snapshot.completedPatrols,
          'missed_checkpoints': snapshot.missedCheckpoints,
          'compliance_percent': snapshot.compliancePercent,
        }, onConflict: 'site_id,guard_id,compliance_date');
  } catch (_) {
    // Patrol compliance persistence is best-effort; alerts still continue.
  }
}

bool? _siteAwarenessSummaryBool(Object? value) {
  if (value is bool) {
    return value;
  }
  if (value is num) {
    if (value == 1) {
      return true;
    }
    if (value == 0) {
      return false;
    }
  }
  if (value is String) {
    final normalized = value.trim().toLowerCase();
    if (normalized == 'true' || normalized == '1' || normalized == 'yes') {
      return true;
    }
    if (normalized == 'false' || normalized == '0' || normalized == 'no') {
      return false;
    }
  }
  return null;
}

double? _siteAwarenessSummaryDouble(Object? value) {
  if (value is num) {
    return value.toDouble();
  }
  if (value is String) {
    return double.tryParse(value.trim());
  }
  return null;
}

String _siteAwarenessHumanizedLabel(Object? value) {
  final raw = value?.toString().trim() ?? '';
  if (raw.isEmpty) {
    return 'unknown';
  }
  final spaced = raw
      .replaceAllMapped(
        RegExp(r'([a-z0-9])([A-Z])'),
        (match) => '${match.group(1)} ${match.group(2)}',
      )
      .replaceAll(RegExp(r'[_\-]+'), ' ')
      .replaceAll(RegExp(r'\s+'), ' ')
      .trim()
      .toLowerCase();
  return spaced.isEmpty ? 'unknown' : spaced;
}

/// Formats a raw `site_awareness_snapshots` row into a compact text block
/// suitable for injection into the Telegram AI system prompt.
String _formatSiteAwarenessSnapshot(Map<String, dynamic> row) {
  final snapshotAt =
      _siteAwarenessSummaryDate(row['snapshot_at'])?.toIso8601String() ??
      (row['snapshot_at'] as String? ?? '');
  final perimeterClear = row['perimeter_clear'];
  final knownFaults = row['known_faults'];
  final activeAlerts = row['active_alerts'];
  final humans = _siteAwarenessDetectionCount(row, 'human_count', 'humanCount');
  final vehicles = _siteAwarenessDetectionCount(
    row,
    'vehicle_count',
    'vehicleCount',
  );
  final animals = _siteAwarenessDetectionCount(
    row,
    'animal_count',
    'animalCount',
  );
  final motion = _siteAwarenessDetectionCount(
    row,
    'motion_count',
    'motionCount',
  );
  final knownFaultLabels = knownFaults is List
      ? knownFaults
            .map((value) => value.toString().trim())
            .where((value) => value.isNotEmpty)
            .toList(growable: false)
      : const <String>[];
  final alertCount = activeAlerts is List ? activeAlerts.length : 0;
  final humanZones = _siteAwarenessHumanZones(row);

  final lines = <String>[];
  if (snapshotAt.isNotEmpty) {
    lines.add('- Snapshot time (UTC): $snapshotAt');
  }
  lines.add(
    '- Perimeter status: ${perimeterClear == true ? 'clear' : 'breach detected'}',
  );
  lines.add('- People detected in latest snapshot: $humans');
  lines.add('- Vehicles detected in latest snapshot: $vehicles');
  lines.add('- Animals detected in latest snapshot: $animals');
  lines.add('- Motion indicators in latest snapshot: $motion');
  if (humanZones.isNotEmpty) {
    lines.add(
      '- Human movement zones in latest snapshot: ${humanZones.map((zone) => '${zone.zoneName} (${zone.zoneTypeLabel})').join(', ')}',
    );
  }
  lines.add('- Active alerts in latest snapshot: $alertCount');
  lines.add(
    '- Known fault channels: ${knownFaultLabels.isEmpty ? 'none' : knownFaultLabels.map((value) => 'Channel $value').join(', ')}',
  );

  final channels = row['channels'];
  if (channels is Map) {
    final channelLines = <String>['- Channel status:'];
    final sortedKeys = channels.keys.toList(growable: false)
      ..sort((a, b) => a.toString().compareTo(b.toString()));
    for (final key in sortedKeys) {
      final keyLabel = key.toString().trim();
      if (!_siteAwarenessValidChannelLabel(keyLabel)) {
        continue;
      }
      final ch = channels[key];
      if (ch is Map) {
        final status = _siteAwarenessHumanizedLabel(ch['status']);
        final lastEvent = _siteAwarenessHumanizedLabel(
          ch['last_event_type'] ?? ch['lastEventType'],
        );
        final isFault = ch['is_fault'] ?? ch['isFault'] ?? false;
        final lastEventAt =
            _siteAwarenessSummaryDate(
              ch['last_event_at'] ?? ch['lastEventAt'],
            )?.toIso8601String() ??
            _siteAwarenessSummaryString(
              ch['last_event_at'] ?? ch['lastEventAt'],
            );
        final details = <String>[status];
        if (lastEvent != 'unknown') {
          details.add('last event $lastEvent');
        }
        if (lastEventAt != null && lastEventAt.isNotEmpty) {
          details.add('last event time $lastEventAt');
        }
        if (isFault == true) {
          details.add('fault');
        }
        final faultReason = _siteAwarenessSummaryString(
          ch['fault_reason'] ?? ch['faultReason'],
        );
        if (faultReason != null) {
          details.add('fault reason $faultReason');
        }
        channelLines.add('  Channel $keyLabel: ${details.join('; ')}');
      }
    }
    if (channelLines.length > 1) {
      lines.addAll(channelLines);
    }
  }

  return lines.join('\n');
}
